/* AUTO-GENERATED — Wisconsin Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["WI"] = {"code":"WI","name":"Wisconsin","agency":"Wisconsin DMV","agencyShort":"DMV","handbook":"https://wisconsindot.gov/Pages/dmv/com-drv-vehs/cdl-how-aply/cdl-manual.aspx","links":{},"en":[{"q":"Without a special permit, what is the maximum total width of a vehicle and its load on a Wisconsin highway?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Wis. Stat. 348.05(1) prohibits operating a vehicle with a total width over 8 feet 6 inches (102 inches) without a permit. This matches the federal standard adopted by Wisconsin.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum legal height of a vehicle (including load) on a Wisconsin highway?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","14 feet 6 inches"],"answer":1,"explanation":"Wis. Stat. 348.06(1) sets the maximum overall height at 13 feet 6 inches (13 1/2 feet) without a permit. Drivers remain responsible for actual overhead clearance regardless of this limit.","handbook":"","hbref":""},{"q":"What is the maximum gross weight imposed on a Wisconsin highway by any single axle without a permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":1,"explanation":"Under Wis. Stat. 348.15(3)(b), the gross weight on any single axle may not exceed 20,000 pounds. This is the same as the federal single-axle limit.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum gross weight allowed on a tandem axle group on a Wisconsin Class \"A\" highway?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Wis. Stat. 348.15(3)(d) allows a tandem axle group (two consecutive sets) to carry up to 34,000 pounds, consistent with the federal tandem-axle limit.","handbook":"","hbref":""},{"q":"On a Wisconsin Class \"A\" highway, what is the maximum legal gross vehicle weight for a properly spaced five-axle combination operating without a permit?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"answer":2,"explanation":"The axle-group weight table in Wis. Stat. 348.15(3)(g), which applies the federal bridge formula, caps legal gross weight at 80,000 pounds. WisDOT publishes 80,000 lb as the legal limit.","handbook":"","hbref":""},{"q":"What is the maximum gross weight Wisconsin allows on any one wheel, or wheels, supporting one end of an axle, without a permit?","options":["9,000 pounds","10,000 pounds","11,000 pounds","13,000 pounds"],"answer":2,"explanation":"Wis. Stat. 348.15(3)(a) limits the gross weight on any one wheel or wheels supporting one end of an axle to 11,000 pounds.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum overall length of a single vehicle on a Wisconsin highway?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":1,"explanation":"Wis. Stat. 348.07(1) limits a single vehicle to an overall length of 45 feet without a permit (implements of husbandry have a separate higher allowance).","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum overall length of a combination of two vehicles and load on a Wisconsin highway (where an overall length limit applies)?","options":["65 feet","70 feet","75 feet","80 feet"],"answer":1,"explanation":"Wis. Stat. 348.07(1) sets the general overall-length limit for a combination of two vehicles at 70 feet, though certain tractor-semitrailer combinations on designated highways have no overall length limit.","handbook":"","hbref":""},{"q":"On a Wisconsin highway designated under s. 348.07(4), what is the maximum length of a single semitrailer operated in a two-vehicle combination (with kingpin-to-axle distance within limits)?","options":["48 feet","50 feet","53 feet","57 feet"],"answer":2,"explanation":"Wis. Stat. 348.07(2)(gv) allows a 53-foot semitrailer (kingpin-to-axle not exceeding 43 feet) in a two-vehicle combination on designated highways, with no overall combination length limit.","handbook":"","hbref":""},{"q":"On Wisconsin highways NOT designated under s. 348.07(4), what is the maximum length of a semitrailer or trailer operated as part of a two-vehicle combination?","options":["45 feet","48 feet","53 feet","57 feet"],"answer":1,"explanation":"Wis. Stat. 348.07(2)(g) limits a semitrailer or trailer to 48 feet on highways not designated under s. 348.07(4); the 53-foot allowance applies only on designated highways.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on the steering axle of a truck tractor in Wisconsin when the manufacturer's rating does not authorize more?","options":["11,000 pounds","12,000 pounds","13,000 pounds","15,000 pounds"],"answer":2,"explanation":"Wis. Stat. 348.15(3)(b) limits a truck tractor's steering axle to 13,000 pounds, unless the manufacturer's rated capacity (tires, axle, etc.) is higher, up to 20,000 pounds.","handbook":"","hbref":""},{"q":"Wisconsin's weight limits for groups of two or more consecutive axles are calculated using which method?","options":["A flat 80,000-pound cap regardless of spacing","The federal bridge formula / weight table in s. 348.15(3)(g)","The manufacturer's GVWR rating only","A fixed 34,000 pounds per axle group"],"answer":1,"explanation":"Wis. Stat. 348.15(3)(g) sets maximum gross weights for consecutive axle groups according to a table that applies the federal bridge formula, based on axle spacing and number of axles.","handbook":"","hbref":""},{"q":"In Wisconsin, when is a Department of Transportation oversize/overweight (OSOW) permit generally required?","options":["Only for loads over 100,000 pounds","When a vehicle or load exceeds the statutory size or weight limits","Only for vehicles wider than 10 feet","Only when traveling on the Interstate system"],"answer":1,"explanation":"Per Wis. Stat. ch. 348 and WisDOT permit rules, a vehicle or load that exceeds the legal size or weight limits (width, height, length, or weight) must obtain an OSOW permit before operating.","handbook":"","hbref":""},{"q":"A non-divisible load that exceeds Wisconsin's legal dimensions for one trip is typically authorized by which permit type?","options":["A single-trip OSOW permit","A vehicle registration sticker","A CDL endorsement","An IRP apportioned plate"],"answer":0,"explanation":"WisDOT issues single-trip OSOW permits (form MV2600) for non-divisible oversize/overweight loads on a specified route; multiple-trip and annual permits cover qualifying repeated movements.","handbook":"","hbref":""},{"q":"Under a Wisconsin multiple-trip OSOW weight permit, a vehicle combination must have at least how many axles to qualify for the higher gross-weight allowance?","options":["Four axles","Five axles","Six axles","Eight axles"],"answer":2,"explanation":"WisDOT multiple-trip weight permits require a combination of six or more axles, with each counted axle generally carrying at least 8 percent of the total gross weight.","handbook":"","hbref":""},{"q":"Under Wisconsin OSOW permits for vehicles hauling raw forest products at higher weights, what is the maximum permitted gross weight?","options":["80,000 pounds","90,000 pounds","98,000 pounds","120,000 pounds"],"answer":2,"explanation":"WisDOT raw forest products (RS) permits allow a maximum gross weight of 98,000 pounds with a six-or-more-axle combination, with no single axle exceeding 18,000 pounds.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum width allowed for most agricultural commercial motor vehicles on Wisconsin highways under the agricultural width allowance?","options":["8 feet 6 inches","9 feet 6 inches","10 feet","12 feet"],"answer":2,"explanation":"Wis. Stat. 348.05(2)(am) allows certain agricultural commercial motor vehicles a width up to 10 feet without a permit (with higher allowances for specific equipment such as sprayers).","handbook":"","hbref":""},{"q":"Wisconsin's 80,000-pound legal gross weight limit applies to Class \"A\" highways. How is the limit treated on the Interstate system in the state?","options":["Interstates have no weight limit at all","Interstates use the same axle and bridge-formula limits, with an 80,000-pound legal maximum","Interstates allow 120,000 pounds without a permit","Interstates only allow 73,280 pounds"],"answer":1,"explanation":"Wisconsin applies federal axle and bridge-formula limits to the Interstate system, yielding the same 80,000-pound legal maximum (Wis. Stat. 348.15; 23 U.S.C. 127), so overweight loads still need a permit.","handbook":"","hbref":""},{"q":"Under a Wisconsin OSOW permit for transporting fluid milk products, the gross weight may exceed the normal maximum by not more than how much?","options":["10,000 pounds","15,000 pounds","18,000 pounds","25,000 pounds"],"answer":2,"explanation":"WisDOT fluid milk products (FMP) permits allow combinations to exceed the maximum gross weight by not more than 18,000 pounds (up to 98,000 lb) on a six-or-more-axle combination.","handbook":"","hbref":""},{"q":"A tandem axle group in Wisconsin may be loaded to 34,000 pounds only if the spacing between the first and last axles of two consecutive tandem sets meets what minimum distance?","options":["28 feet or more","30 feet or more","36 feet or more","40 feet or more"],"answer":2,"explanation":"Wis. Stat. 348.15(3)(d) permits each of two consecutive tandem axle sets to carry 34,000 pounds when the distance between the first and last axles is 36 feet or more.","handbook":"","hbref":""},{"q":"In Wisconsin, which CDL class is required to operate a combination vehicle with a Gross Combination Weight Rating over 26,000 pounds that includes a towed unit with a GVWR of over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Wisconsin defines a Class A CDL as a combination vehicle with a GCWR (or actual/registered weight) over 26,000 pounds, inclusive of a towed unit with a GVWR over 10,000 pounds. Source: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'","handbook":"","hbref":""},{"q":"Under Wisconsin rules, a single heavy straight truck with a GVWR of over 26,000 pounds and no trailer (or a towed unit of 10,000 pounds or less) requires which CDL class?","options":["Class A","Class B","Class C","No CDL is required"],"answer":1,"explanation":"Wisconsin defines a Class B CDL as a heavy straight vehicle with a GVWR (or actual/registered weight) of over 26,000 pounds, including such a vehicle towing a unit of 10,000 pounds or less. Source: Wisconsin Commercial Driver's Manual (WisDOT).","handbook":"","hbref":""},{"q":"A small vehicle with a GVWR of 26,000 pounds or less is designed to carry 16 or more persons including the driver. Which Wisconsin CDL class does it require?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"Wisconsin defines a Class C CDL as a vehicle of 26,000 pounds or less that is designed to carry 16 or more persons (including the driver), or of any size used to transport hazardous materials as defined in 49 CFR 383.5. Source: Wisconsin Commercial Driver's Manual (WisDOT).","handbook":"","hbref":""},{"q":"When determining the class of a commercial motor vehicle for Wisconsin CDL purposes, which value must be used?","options":["Always the manufacturer's GVWR only","The lowest of GVWR, actual gross weight, or registered weight","The greater of GVWR, actual gross weight, or registered weight","The vehicle's curb weight when empty"],"answer":2,"explanation":"Wisconsin instructs drivers to use the greater of the Gross Vehicle Weight Rating, the actual gross weight, or the registered weight to determine the CMV class. Source: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'","handbook":"","hbref":""},{"q":"Which endorsement is required on a Wisconsin CDL to drive a commercial vehicle that transports hazardous materials in amounts requiring placarding?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"The 'H' (HazMat) endorsement is required to transport hazardous materials as defined under 49 CFR 383.5. Source: Wisconsin Commercial Driver's Manual (WisDOT), endorsements section.","handbook":"","hbref":""},{"q":"Which Wisconsin CDL endorsement allows a driver to operate a commercial vehicle equipped with a cargo tank used to haul liquids or gases in bulk?","options":["P endorsement","T endorsement","N endorsement","S endorsement"],"answer":2,"explanation":"The 'N' (Tank) endorsement is required for commercial vehicles equipped with a cargo tank to transport liquid or gaseous materials in bulk. Source: Wisconsin Commercial Driver's Manual (WisDOT), endorsements list.","handbook":"","hbref":""},{"q":"Under Wisconsin's tank vehicle rule, the tank endorsement test is required for a vehicle carrying a liquid or gas in an individual container with a rated capacity of more than 119 gallons and an aggregate rated capacity of at least how much?","options":["500 gallons or more","1,000 gallons or more","2,500 gallons or more","3,000 gallons or more"],"answer":1,"explanation":"Wisconsin requires the Tank Vehicle test for vehicles carrying liquids or gases in a container with a rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: Wisconsin Commercial Driver's Manual (WisDOT), Section 8 / Tank Vehicle test.","handbook":"","hbref":""},{"q":"Which endorsement does a Wisconsin CDL holder need to pull more than one trailer (doubles or triples)?","options":["T endorsement","N endorsement","H endorsement","P endorsement"],"answer":0,"explanation":"The 'T' endorsement (Doubles/Triples) authorizes a driver to operate combination vehicles pulling more than one trailer and requires passing the Doubles and Triples knowledge test. Source: Wisconsin Commercial Driver's Manual (WisDOT).","handbook":"","hbref":""},{"q":"A Wisconsin commercial vehicle is designed to transport 16 or more passengers including the driver. Which endorsement is required in addition to the proper CDL class?","options":["S endorsement","P endorsement","N endorsement","T endorsement"],"answer":1,"explanation":"The 'P' (Passenger) endorsement is required to operate a vehicle designed to transport or actually transporting 16 or more passengers, including the driver. Source: Wisconsin Commercial Driver's Manual (WisDOT), endorsements list.","handbook":"","hbref":""},{"q":"Which statement is TRUE about the Wisconsin school bus 'S' endorsement?","options":["It requires only a one-time knowledge test that never expires","It requires a knowledge test and driving skills test both when first issued and upon every renewal","It is automatically granted to anyone holding a 'P' endorsement","It is only available on a Class A CDL"],"answer":1,"explanation":"Wisconsin requires the school bus 'S' endorsement applicant to pass knowledge and driving skills testing when originally issued, and to pass testing (knowledge, road signs, vision, abbreviated skills) again upon every renewal. Source: Wisconsin Commercial Driver's Manual (WisDOT), school bus endorsement section.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Wisconsin CDL valid for intrastate (within-Wisconsin) commercial driving?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"A driver must be at least 18 years old to obtain a Wisconsin CDL for intrastate commerce. Source: Wisconsin Commercial Driver's Manual (WisDOT) / WisDOT CDL requirements.","handbook":"","hbref":""},{"q":"What is the minimum age required to drive a commercial motor vehicle in interstate commerce (across state lines) under Wisconsin and federal rules?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"A driver must be at least 21 years old to operate a CMV in interstate commerce, to haul hazardous materials, and to transport passengers across state lines. Source: Wisconsin Commercial Driver's Manual (WisDOT) / WisDOT CDL requirements.","handbook":"","hbref":""},{"q":"Under Wisconsin's Commercial Learner Permit (CLP) rules, how long must you hold the CLP before you are allowed to take the CDL skills (road) test?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"Wisconsin (following the federal standard) requires you to hold a CLP for at least 14 days before taking the skills test. Source: Wisconsin Commercial Driver's Manual (WisDOT), Commercial Learner Permit section.","handbook":"","hbref":""},{"q":"For how many days is a Wisconsin Commercial Learner Permit (CLP) valid before it must be renewed?","options":["90 days","180 days","1 year","2 years"],"answer":1,"explanation":"A Wisconsin CLP is valid for 180 days and may be renewed. Source: Wisconsin Commercial Driver's Manual (WisDOT), Commercial Learner Permit section / WisDOT CDL requirements page.","handbook":"","hbref":""},{"q":"While driving with a Wisconsin Commercial Learner Permit (CLP), what is required of the supervising driver?","options":["No supervising driver is required if the CLP holder is 21","A valid CDL holder, at or above the permit's class and endorsement level, must be seated next to the CLP holder","Any licensed driver age 16 or older may ride in the back seat","A WisDOT examiner must be present at all times"],"answer":1,"explanation":"A CLP holder must be accompanied by a person who holds a valid CDL at or above the permit's class/endorsement level, seated next to the CLP holder in the front. Source: Wisconsin Commercial Driver's Manual (WisDOT), CLP section.","handbook":"","hbref":""},{"q":"When applying for or renewing a Wisconsin HazMat 'H' endorsement, which additional federal requirement must the applicant satisfy beyond passing the HazMat knowledge test?","options":["A second road skills test in a placarded vehicle","Fingerprinting for an FBI criminal background/threat assessment check","A notarized employer sponsorship letter","A drug and alcohol clearinghouse subscription fee"],"answer":1,"explanation":"Wisconsin requires 'H' endorsement applicants to provide fingerprints for an FBI criminal background records check (TSA security threat assessment) and present proof of U.S. citizenship or lawful status, at original issuance and every renewal. Source: Wisconsin Commercial Driver's Manual (WisDOT), HazMat 'H' endorsement section.","handbook":"","hbref":""},{"q":"For the Wisconsin HazMat 'H' endorsement, a conviction for certain disqualifying crimes will bar issuance if the conviction occurred within how many years prior to the application date?","options":["3 years","5 years","7 years","10 years"],"answer":2,"explanation":"An applicant will not be permitted to obtain, renew, or transfer an 'H' endorsement if convicted (or found not guilty by reason of insanity) of certain disqualifying crimes during the 7 years prior to the application date. Source: Wisconsin Commercial Driver's Manual (WisDOT), HazMat disqualifications.","handbook":"","hbref":""},{"q":"Which document or proof does Wisconsin specifically require a HazMat 'H' endorsement applicant to present that is NOT required for most other CDL endorsements?","options":["Proof of U.S. citizenship or lawful status in the U.S.","A high school diploma","A commercial vehicle lease agreement","A motor carrier's USDOT number"],"answer":0,"explanation":"Wisconsin requires HazMat 'H' applicants to present proof of U.S. citizenship or legal status in the U.S. at knowledge testing, original issuance, and all renewals, in addition to the FBI background check. Source: Wisconsin Commercial Driver's Manual (WisDOT), HazMat 'H' endorsement section.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) in Wisconsin must be completed through a provider listed where, and is required for first-time CDL applicants and certain endorsements?","options":["The Wisconsin Technical College System registry","The FMCSA Training Provider Registry (TPR)","The National Safety Council database","Any DMV-approved third-party tester list"],"answer":1,"explanation":"ELDT must be obtained from a training provider listed on the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov). It is required for a first CDL, a class upgrade (B to A), and the H, P, and S endorsements; drivers whose CDL was issued before February 7, 2022 are exempt. Source: WisDOT CDL requirements page / Wisconsin Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"On Wisconsin's CDL medical self-certification, which of the following is one of the four valid certification categories of operation?","options":["Interstate Non-Excepted (NI)","Federal Hazmat Certified (FH)","Interstate Suspended (IS)","Commercial Exempt Farm (CF)"],"answer":0,"explanation":"Wisconsin's four CDL self-certification categories are Interstate Non-Excepted (NI), Interstate Excepted (EI), Intrastate Non-Excepted (NA), and Intrastate Excepted (EA); NI drivers must meet 49 CFR Part 391 medical requirements and hold a valid Fed Med card. Source: WisDOT MV3230 Commercial Driver Certification: Tier of Operation / Fed Med card page.","handbook":"","hbref":""},{"q":"In Wisconsin, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.04","0.08","0.02","0.00"],"answer":0,"explanation":"Wisconsin prohibits operating a CMV with a BAC of 0.04 or more (Wis. Stat. § 346.63(5); Wisconsin CDL Manual). Reaching 0.04 in a CMV is a major disqualifying offense, unlike the 0.08 limit that applies to ordinary (non-commercial) vehicles.","handbook":"","hbref":""},{"q":"How long is a CDL disqualified in Wisconsin for a first major offense, such as operating a CMV with a BAC of 0.04 or more?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"Per the Wisconsin General CDL Disqualifications table (WisDOT) and Wis. Stat. § 343.315, a first conviction for a major offense disqualifies the CDL for 1 year. The 3-year period applies only when the driver was transporting placarded hazardous materials.","handbook":"","hbref":""},{"q":"Under Wisconsin rules, a first major offense (such as OWI in a CMV) carries a 3-year CDL disqualification instead of 1 year under which condition?","options":["The driver was transporting placarded hazardous materials","The driver was over age 65","The crash caused property damage","The driver had two passengers aboard"],"answer":0,"explanation":"The WisDOT CDL Disqualifications table and Wis. Stat. § 343.315 raise a first major-offense disqualification from 1 year to 3 years when the violation occurred while the CMV was transporting placarded hazardous materials.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Wisconsin for a SECOND major offense (for example, a second OWI in a CMV)?","options":["Lifetime","3 years","10 years","5 years"],"answer":0,"explanation":"A second conviction for any major disqualifying offense results in a lifetime CDL disqualification under the WisDOT CDL Disqualifications table and Wis. Stat. § 343.315 (mirroring 49 CFR 383.51).","handbook":"","hbref":""},{"q":"Under Wisconsin's Implied Consent law, what happens if a CMV driver refuses a law enforcement officer's request to submit to chemical testing for alcohol or drugs?","options":["The CDL is disqualified for 1 year (lifetime on a second occurrence)","A warning is issued with no disqualification","The CDL is disqualified for 60 days","The CDL is disqualified for 6 months"],"answer":0,"explanation":"Refusal is treated as a major offense: 1-year CDL disqualification for a first occurrence and a lifetime disqualification for a second (WisDOT CDL Disqualifications table; Wis. Stat. §§ 343.305, 343.315).","handbook":"","hbref":""},{"q":"Under Wisconsin's Implied Consent law, refusing a requested chemical test revokes a driver's operating privilege for a minimum of how long?","options":["1 year","90 days","30 days","6 months"],"answer":0,"explanation":"The Wisconsin CDL Manual states that if you refuse a test requested by an officer under the Implied Consent law (Wis. Stat. § 343.305), your operating privilege will be revoked for a minimum of one year, plus other penalties.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger a 60-day CDL disqualification in Wisconsin?","options":["2","3","4","5"],"answer":0,"explanation":"Two serious traffic violations in separate incidents within 3 years result in a 60-day CDL disqualification (WisDOT CDL Disqualifications table; Wis. Stat. § 343.315; 49 CFR 383.51).","handbook":"","hbref":""},{"q":"In Wisconsin, three serious traffic violations within a 3-year period result in a CDL disqualification of how long?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Three serious traffic violations within 3 years disqualify the CDL for 120 days (WisDOT CDL Disqualifications table; Wis. Stat. § 343.315). Two within 3 years is 60 days.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation under Wisconsin CDL rules?","options":["Speeding 15 mph or more over the limit","A parking violation","Operating with a BAC of 0.04 or more","Refusing a chemical test"],"answer":0,"explanation":"Speeding 15 mph or more over the limit is a serious traffic violation (WisDOT CDL Disqualifications table). A 0.04 BAC and a test refusal are MAJOR offenses, not serious violations, and parking tickets do not count.","handbook":"","hbref":""},{"q":"Which of the following is NOT on Wisconsin's list of serious traffic violations for CDL disqualification purposes?","options":["Operating a CMV with a BAC of 0.04 or more","Following too closely","Reckless driving","Improper or erratic lane change"],"answer":0,"explanation":"Following too closely, reckless driving, and improper/erratic lane changes are serious traffic violations (WisDOT table). Operating with a BAC of 0.04 or more is a MAJOR offense (1 year / lifetime), not a serious violation.","handbook":"","hbref":""},{"q":"Since July 1, 2016, in Wisconsin, how many convictions for using a hand-held mobile telephone while operating a CMV are required before the CDL is disqualified?","options":["2 or more","1","4 or more","3 or more"],"answer":0,"explanation":"The Wisconsin CDL Manual states the CDL is disqualified after two or more convictions for hand-held mobile phone use while operating a CMV: 60 days for the second offense within 3 years and 120 days for three or more within 3 years.","handbook":"","hbref":""},{"q":"Under the Wisconsin CDL Manual, what is the maximum civil penalty that may be imposed on a CMV driver for texting while driving?","options":["$2,750","$2,500","$11,000","$5,000"],"answer":0,"explanation":"The Wisconsin CDL Manual states a driver who texts while operating a CMV is subject to civil penalties up to $2,750 per violation; motor carriers that allow or require it face penalties up to $11,000.","handbook":"","hbref":""},{"q":"Under the Wisconsin CDL Manual, what is the maximum civil penalty a motor carrier may face for allowing or requiring its drivers to use a hand-held phone or text while driving a CMV?","options":["$11,000","$2,750","$10,000","$5,500"],"answer":0,"explanation":"The Wisconsin CDL Manual states employers (motor carriers) may be subject to civil penalties up to $11,000 for allowing or requiring hand-held phone use or texting by CMV drivers; the driver's own penalty is up to $2,750.","handbook":"","hbref":""},{"q":"Two convictions for texting while operating a CMV within a 3-year period result in what CDL disqualification in Wisconsin?","options":["60 days","120 days","30 days","1 year"],"answer":0,"explanation":"The Wisconsin CDL Manual states the CDL is disqualified for 60 days on the second texting offense within 3 years, and 120 days for three or more offenses within 3 years.","handbook":"","hbref":""},{"q":"What is the CDL disqualification in Wisconsin for a SECOND out-of-service order violation within 10 years (non-hazmat, non-passenger)?","options":["2 years","90 days","1 year","5 years"],"answer":0,"explanation":"Per the WisDOT CDL Disqualifications table, a second out-of-service order violation within 10 years disqualifies the CDL for 2 years (3 years if hazmat-placarded or a passenger vehicle).","handbook":"","hbref":""},{"q":"In Wisconsin, what is the CDL disqualification for a FIRST conviction of a railroad-highway grade crossing violation (such as failing to stop when the tracks are not clear)?","options":["60 days","30 days","120 days","90 days"],"answer":0,"explanation":"The WisDOT CDL Disqualifications table sets a first railroad-highway grade crossing violation at a 60-day disqualification; a second within 3 years is 120 days and a third within 3 years is 1 year.","handbook":"","hbref":""},{"q":"What CDL disqualification applies in Wisconsin to a THIRD railroad-highway grade crossing violation within a 3-year period?","options":["1 year","120 days","60 days","Lifetime"],"answer":0,"explanation":"Per the WisDOT CDL Disqualifications table, railroad-highway grade crossing violations carry 60 days (first), 120 days (second within 3 years), and 1 year (third within 3 years).","handbook":"","hbref":""},{"q":"In Wisconsin, using a commercial motor vehicle in the commission of a felony involving manufacturing, distributing, or dispensing a controlled substance results in what CDL disqualification?","options":["Lifetime, with no reinstatement","1 year","3 years","10 years"],"answer":0,"explanation":"Per the WisDOT CDL Disqualifications table and Wis. Stat. § 343.315, a felony involving a controlled substance committed using a CMV results in an unalterable lifetime disqualification (no reinstatement), even for a first offense.","handbook":"","hbref":""},{"q":"Under Wisconsin's Move Over law, when you approach a tow truck, squad car, or highway maintenance vehicle stopped on the roadside with flashing warning lights and there is more than one lane in your direction, what must you do?","options":["Move into a lane not next to the stopped vehicle if it is safe to do so","Come to a complete stop until the other vehicle's lights are turned off","Continue at the posted speed because Move Over only covers police cars","Honk your horn and maintain your speed past the stopped vehicle"],"answer":0,"explanation":"Wisconsin's Move Over law (Wis. Stat. s. 346.072) requires drivers approaching emergency, tow, utility, or highway maintenance vehicles with flashing lights to vacate the lane nearest the vehicle by moving over, if a lane change can be made safely. The Wisconsin CDL Manual (Section 2.8) and WisDOT state this applies to law enforcement, EMS, fire, tow, and roadside workers, not just police.","handbook":"","hbref":""},{"q":"Under Wisconsin's Move Over law, what must you do if you cannot safely change lanes away from a stopped emergency or roadside-service vehicle displaying flashing lights?","options":["Slow down and proceed with caution until you have safely passed the vehicle","Stop completely on the shoulder and wait for the vehicle to leave","Maintain the posted speed limit since moving over is impossible","Pull onto the opposite side of the road to give maximum clearance"],"answer":0,"explanation":"Wis. Stat. s. 346.072 and the Wisconsin CDL Manual (Section 2.8) state that if a lane change is unsafe (or only one lane exists in your direction), you must slow down and proceed with caution until you have safely passed the stopped vehicle. There is no requirement to stop or use the opposite lane.","handbook":"","hbref":""},{"q":"In Wisconsin, a vehicle approaching a stopped school bus that is displaying flashing red warning lights must stop at what minimum distance from the bus?","options":["Not less than 20 feet from the bus","Not less than 10 feet from the bus","Not less than 50 feet from the bus","Not less than 100 feet from the bus"],"answer":0,"explanation":"Wisconsin Statute 346.48(1) requires the operator of a vehicle approaching from the front or rear of a school bus displaying flashing red warning lights to stop not less than 20 feet from the bus and remain stopped until the bus moves or the red lights are turned off.","handbook":"","hbref":""},{"q":"Under Wisconsin law, who is exempt from the requirement to stop for a school bus that is displaying flashing red warning lights?","options":["Drivers proceeding in the opposite direction on a divided highway","Drivers proceeding in the same direction within 100 feet of the bus","Drivers on any highway with two or more lanes in their direction","No one is exempt; all drivers must stop on every type of road"],"answer":0,"explanation":"Wisconsin Statute 346.48(1) provides one exception: the stopping requirement does not apply to operators of vehicles proceeding in the OPPOSITE direction on a DIVIDED highway. On undivided roads, opposing traffic must still stop. Same-direction traffic must always stop.","handbook":"","hbref":""},{"q":"A school bus driver in Wisconsin approaches a railroad-highway grade crossing required to be stopped for. The front of the bus must come to a full stop within what range of the nearest rail?","options":["Not less than 15 feet nor more than 50 feet","Not less than 5 feet nor more than 15 feet","Not less than 25 feet nor more than 75 feet","Not less than 50 feet nor more than 100 feet"],"answer":0,"explanation":"The Wisconsin CDL Manual (Sections 2.15 and 4.3.5) requires a bus to stop between 15 and 50 feet before a railroad crossing - no closer than 15 feet and no farther than 50 feet from the nearest rail - then look and listen in both directions before proceeding.","handbook":"","hbref":""},{"q":"According to the Wisconsin CDL Manual, a placarded hazardous materials vehicle must stop 15 to 50 feet before a railroad crossing. Besides placarded loads, which of these ALSO requires a stop even when empty?","options":["A cargo tank used for hazardous materials, whether loaded or empty","Any straight truck over 26,000 pounds carrying dry freight","A flatbed hauling steel coils that are properly secured","A refrigerated van carrying perishable food products"],"answer":0,"explanation":"Wisconsin CDL Manual Section 9.6.12 states a vehicle must stop 15 to 50 feet before the nearest rail if it is placarded, carries any amount of chlorine, OR has cargo tanks used for hazardous materials whether loaded or empty. Ordinary dry-freight or reefer loads do not require a stop.","handbook":"","hbref":""},{"q":"If you must stop your commercial vehicle on a Wisconsin two-lane road or undivided highway, within how many minutes must your emergency warning devices be placed?","options":["Within 10 minutes","Within 2 minutes","Within 15 minutes","Within 30 minutes"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 2.7) states that if you must stop on a road or shoulder, you must put out your emergency warning devices within 10 minutes of stopping.","handbook":"","hbref":""},{"q":"When stopped on a Wisconsin two-lane road carrying traffic in both directions, where does the CDL Manual say to place your three reflective triangles?","options":["Within 10 feet of the vehicle, and 100 feet behind and 100 feet ahead","At 10 feet, 100 feet, and 200 feet behind the vehicle only","At 50 feet, 100 feet, and 500 feet toward approaching traffic","All three within 25 feet of the rear bumper of the vehicle"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 2.7) directs that on a two-lane/undivided road you place one triangle within 10 feet of the vehicle's front or rear corner, one about 100 feet behind, and one about 100 feet ahead, on the shoulder or in the lane where you are stopped.","handbook":"","hbref":""},{"q":"Per the Wisconsin CDL Manual, where should the three warning triangles be placed when you are stopped on a one-way or divided highway?","options":["At 10 feet, 100 feet, and 200 feet toward the approaching traffic","At 10 feet, 100 feet, and 100 feet on both sides of the vehicle","At 25 feet, 100 feet, and 300 feet toward approaching traffic","At 50 feet, 150 feet, and 250 feet behind the vehicle"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 2.7) states that on a one-way or divided highway you place warning devices at 10 feet, 100 feet, and 200 feet toward the approaching traffic (behind the vehicle).","handbook":"","hbref":""},{"q":"The Wisconsin CDL Manual says that if you stop near a hill, curve, or obstruction that keeps other drivers from seeing your vehicle within a certain distance, you should move the rear-most triangle farther back. What is that sight-distance figure?","options":["500 feet","200 feet","300 feet","1,000 feet"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 2.7) says that if a hill, curve, or other obstruction prevents drivers from seeing your vehicle within 500 feet, move the rear-most warning triangle back down the road to give adequate advance warning.","handbook":"","hbref":""},{"q":"What is the maximum speed limit for a commercial truck on a rural Wisconsin freeway that is part of the interstate system?","options":["70 miles per hour, the same as for cars","55 miles per hour for all trucks over 26,000 pounds","65 miles per hour, lower than the 70 mph limit for cars","60 miles per hour for any vehicle pulling a trailer"],"answer":0,"explanation":"Under Wis. Stat. s. 346.57(4), the limit on Wisconsin freeways including interstate highways is 70 mph. Wisconsin sets no separate, lower speed limit for trucks - unlike some neighboring states - so trucks may run at the same posted 70 mph where signed, subject to the basic safe-speed rule.","handbook":"","hbref":""},{"q":"Does Wisconsin law restrict commercial trucks to specific lanes (such as banning them from the left lane) on interstate highways generally?","options":["No statewide truck-only lane ban exists; the general 'keep right except to pass' rule applies","Yes, trucks are banned from the leftmost lane on all Wisconsin interstates","Yes, trucks must stay in the right lane whenever there are three or more lanes","Yes, trucks over 10,000 pounds may use only the right two lanes statewide"],"answer":0,"explanation":"Wisconsin has no statewide statute restricting trucks to particular lanes. The general rule (Wis. Stat. s. 346.05) requires driving on the right and using the left lane mainly for passing. Specific local lane restrictions can be posted, but there is no blanket interstate truck-lane ban as found in some states.","handbook":"","hbref":""},{"q":"The Wisconsin CDL Manual lists a state-specific note about school buses and railroad tracks. Which statement reflects that Wisconsin note?","options":["In Wisconsin, school buses must stop at tracks used for industrial switching","In Wisconsin, school buses may roll through any crossing under 10 mph","In Wisconsin, school buses never stop at crossings inside city limits","In Wisconsin, school buses stop only at crossings with active gates"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 4.3.5) carries a 'Wisconsin Note' stating that in Wisconsin, school buses must stop at tracks used for industrial switching - a state-specific requirement beyond the general crossing rules.","handbook":"","hbref":""},{"q":"According to the Wisconsin CDL Manual, at which type of crossing does a bus driver NOT need to make a full stop (but must still slow and check for traffic)?","options":["A crossing marked as 'exempt' or 'abandoned'","A crossing with a crossbuck sign and no gates","A multiple-track crossing in a rural area","A crossing where the warning bells are silent"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 4.3.5) lists where a bus need not stop but must slow and check: streetcar crossings, where an officer or flagman directs traffic, when a traffic signal shows green, and at crossings marked 'exempt' or 'abandoned.' A plain crossbuck without those conditions still requires a stop for a bus.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle width in Wisconsin before an oversize permit is required for travel on highways?","options":["8 feet 6 inches (8.5 feet)","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Wisconsin's legal maximum width is 8 feet 6 inches (8.5 feet); loads wider than this require an oversize permit through WisDOT's permit system. The standard legal limits are 8.5 ft wide, 13.5 ft high, 53 ft long for a semitrailer, and 80,000 lbs gross weight.","handbook":"","hbref":""},{"q":"Wisconsin operates seasonal weight-restriction programs that are distinctive to its climate. What does the winter 'frozen road declaration' allow?","options":["Heavier loads on designated roads while the pavement is frozen and stronger","A complete ban on all commercial trucks until the spring thaw ends","Higher speed limits for trucks because of reduced summer traffic","A waiver of all permit fees for loads traveling at night only"],"answer":0,"explanation":"WisDOT's seasonal weight-restriction programs take advantage of Wisconsin's climate: the winter frozen road declaration (roughly mid-December to early March) allows heavier loads while the frozen pavement is structurally stronger, per WisDOT's Seasonal Weight Restrictions program.","handbook":"","hbref":""},{"q":"During Wisconsin's spring thaw, the Class II highway and seasonal posted-road programs do what to truck weights?","options":["Reduce allowable axle weights to protect pavement weakened by thawing","Increase allowable weights because melting snow clears the roads","Have no effect on weight; they only change posted speed limits","Apply only to passenger cars and recreational vehicles, not trucks"],"answer":0,"explanation":"WisDOT's spring-thaw programs (Class II roads and seasonal posted roads, roughly March into May) reduce allowable axle and gross weights and suspend many divisible-load permits because thawing pavement is structurally weak. The goal is to prolong highway life, per WisDOT's Seasonal Weight Restrictions program.","handbook":"","hbref":""},{"q":"In Wisconsin, when an oversize load is wide enough to require a single front escort, what type of vehicle may serve as the escort?","options":["An automobile or single-unit truck not over 16,000 pounds with the required warning lamps","Any motorcycle equipped with a flag and amber light","A second loaded semitrailer traveling directly ahead of the load","Only a marked law-enforcement squad car in every case"],"answer":0,"explanation":"Under Wisconsin oversize-permit rules (WisDOT/Trans code), an escort (pilot) vehicle must be an automobile or single-unit truck of not more than 16,000 pounds, with an unobstructed view, low-beam headlamps on, and warning lamps lighted while escorting the permitted load.","handbook":"","hbref":""},{"q":"On a Wisconsin two-lane road, what additional pavement marking typically accompanies a railroad crossing to control passing?","options":["A no-passing zone marking (and a no-passing sign) approaching the tracks","A dashed yellow center line encouraging passing before the tracks","A solid white lane line allowing trucks to share the crossing","A bike-lane stripe directing trucks to the far right of the crossing"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 2.15) notes that on two-lane roads, railroad pavement markings include an 'X' with the letters 'RR' and a no-passing marking, and there is also a no-passing-zone sign approaching the crossing. A white stop line, if present, is where the front of the bus must remain while stopped.","handbook":"","hbref":""},{"q":"A Wisconsin CDL driver stops on the shoulder of a busy divided freeway after a breakdown. After placing the three triangles toward approaching traffic at 10, 100, and 200 feet, what does the Wisconsin CDL Manual advise about holding the triangles?","options":["Hold each triangle between yourself and oncoming traffic so other drivers can see you","Hold the triangles overhead and walk down the center of the travel lane","Throw the triangles from the cab to avoid leaving the vehicle entirely","Place all three on the left side facing away from the traffic flow"],"answer":0,"explanation":"The Wisconsin CDL Manual (Section 2.7) advises that when putting out triangles you hold them between yourself and oncoming traffic for your own safety, so approaching drivers can see you while you set the devices.","handbook":"","hbref":""},{"q":"Which state agency issues Commercial Driver Licenses (CDLs) in Wisconsin?","options":["The Wisconsin Division of Motor Vehicles (DMV), part of WisDOT","The Wisconsin State Patrol","The Wisconsin Department of Public Safety","The Federal Motor Carrier Safety Administration"],"answer":0,"explanation":"Wisconsin CDLs are issued by the Wisconsin Division of Motor Vehicles (DMV), a division of the Wisconsin Department of Transportation. The State Patrol enforces motor carrier laws but does not issue licenses, and FMCSA is a federal agency that sets standards rather than issuing state CDLs. Source: Wisconsin Commercial Driver's Manual; wisconsindot.gov CDL Requirements page.","handbook":"","hbref":""},{"q":"What is the minimum number of correct answers needed to pass the Wisconsin CDL General Knowledge test, which contains 50 questions?","options":["40 correct (80%)","30 correct (60%)","35 correct (70%)","45 correct (90%)"],"answer":0,"explanation":"The Wisconsin General Knowledge test has 50 questions and you must answer at least 40 correctly, a passing score of 80%. The 80% standard applies to CDL knowledge tests in Wisconsin. Source: Wisconsin Commercial Driver's Manual; wisconsindot.gov CDL Requirements.","handbook":"","hbref":""},{"q":"How long is a Wisconsin Commercial Learner Permit (CLP) valid?","options":["180 days","90 days","1 year","60 days"],"answer":0,"explanation":"A Wisconsin CLP is valid for 180 days and lists the vehicle types and endorsements for which the holder has qualified. Source: Wisconsin Commercial Driver's Manual, Commercial Learner Permit (CLP) section.","handbook":"","hbref":""},{"q":"How long must a Wisconsin CLP holder wait after the permit is issued before being allowed to take the CDL skills test?","options":["14 days","10 days","30 days","7 days"],"answer":0,"explanation":"Under federal rules adopted by Wisconsin, you must hold the CLP for at least 14 days before you are allowed to take a skills test. Source: Wisconsin Commercial Driver's Manual, Skills testing section; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Wisconsin CDL skills test has three parts that must be taken in a set order. What is the correct order?","options":["Vehicle inspection, basic vehicle control, on-road driving","On-road driving, vehicle inspection, basic vehicle control","Basic vehicle control, on-road driving, vehicle inspection","Vehicle inspection, on-road driving, basic vehicle control"],"answer":0,"explanation":"Wisconsin's three-part skills test must be taken in order: vehicle inspection, then basic vehicle control, then on-road driving. Source: Wisconsin Commercial Driver's Manual, Skills tests section.","handbook":"","hbref":""},{"q":"Before a new applicant in Wisconsin is eligible to take CDL testing, what training must be completed?","options":["Entry Level Driver Training (ELDT) from an FMCSA-registered provider","A defensive driving course approved by the county","A two-year apprenticeship under a licensed carrier","An OSHA workplace safety certification"],"answer":0,"explanation":"New CDL applicants (and those upgrading class or adding certain endorsements) must complete Entry Level Driver Training from a provider listed on the FMCSA Training Provider Registry before testing. Source: Wisconsin Commercial Driver's Manual; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"Which document do Wisconsin CDL applicants use to self-certify their tier (type) of commercial operation?","options":["Form MV3230, Commercial Driver Certification: Tier of Operation","Form MV3001, the general driver license application","Form MV3740, the school bus self-certification","FMCSA Medical Examination Report (MCSA-5875)"],"answer":0,"explanation":"Wisconsin drivers self-certify their tier of operation on Form MV3230. MV3001 is the general license application, MV3740 is a school bus self-certification, and the MCSA-5875 is the medical exam report completed by an examiner. Source: wisconsindot.gov Fed Med card page; Form MV3230.","handbook":"","hbref":""},{"q":"How many self-certification categories (tiers of operation) must a Wisconsin CDL holder choose from?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification tiers: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. Source: wisconsindot.gov Fed Med card page; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which Wisconsin self-certification tier REQUIRES the driver to maintain a valid Federal medical examiner's certificate (Fed Med card)?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Any driver who never crosses state lines"],"answer":0,"explanation":"Non-Excepted Interstate (NI) drivers must hold a valid Fed Med card. Excepted Interstate and Excepted Intrastate tiers do not require one. Source: wisconsindot.gov Fed Med card page; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"As of the 2025 process change, how does a Wisconsin driver's Federal medical examiner's certificate information normally reach the WI DMV after a DOT physical?","options":["FMCSA electronically transmits it to the WI DMV within about 48 hours of the exam","The driver must always fax a paper copy to the DMV within 10 days","The trucking employer mails it to the DMV on the driver's behalf","It is printed on the CDL and never reported to the state"],"answer":0,"explanation":"Effective April 13, 2025, FMCSA automatically provides the driver's Fed Med card information to the WI DMV, generally within 48 hours of the DOT physical. Exams completed before that date had to be submitted by the driver. Source: wisconsindot.gov Fed Med card page.","handbook":"","hbref":""},{"q":"How often must a Wisconsin CDL be renewed?","options":["Every 8 years","Every 4 years","Every 6 years","Every 2 years"],"answer":0,"explanation":"A Wisconsin CDL must be renewed every 8 years. Source: Wisconsin Commercial Driver's Manual; wisconsindot.gov renewal information.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Wisconsin CDL for intrastate (within-Wisconsin) commercial driving?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"You must be at least 18 to obtain a Wisconsin CDL/CLP for intrastate operation. Interstate commerce generally requires being at least 21. Source: Wisconsin Commercial Driver's Manual, Commercial Learner Permit (CLP) section.","handbook":"","hbref":""},{"q":"Under what condition may a CLP holder in Wisconsin operate a commercial vehicle in interstate commerce?","options":["Only if at least 21 years old and holding a valid federal medical certificate","At any age, since a CLP grants full interstate authority","Only after holding the CLP for 180 days","Only with a school bus endorsement"],"answer":0,"explanation":"A CLP holder may not operate in interstate commerce unless at least 21 years old and holding a valid Fed Med card. Source: Wisconsin Commercial Driver's Manual, CLP section.","handbook":"","hbref":""},{"q":"On the skills test, how many of the three segments must a Wisconsin applicant pass on the same CLP?","options":["All three segments must be passed on the same CLP","Only the on-road segment must be on the same CLP","Any two of the three may carry over to a new CLP","Segments may be spread across up to three different CLPs"],"answer":0,"explanation":"Wisconsin requires that all three segments of the skills test be passed on the same CLP. Source: Wisconsin Commercial Driver's Manual, Skills testing section.","handbook":"","hbref":""},{"q":"Which test must EVERY Wisconsin CDL applicant pass regardless of the class or endorsements sought?","options":["The General Knowledge test","The Air Brakes test","The Combination Vehicles test","The Hazardous Materials test"],"answer":0,"explanation":"The General Knowledge test is taken by all CDL applicants; other knowledge tests (air brakes, combination, hazmat, etc.) are required only for specific classes or endorsements. Source: Wisconsin Commercial Driver's Manual, Knowledge tests section.","handbook":"","hbref":""},{"q":"In addition to the General Knowledge test, which TWO documents/proofs are required when applying for a Wisconsin CLP/CDL?","options":["A valid Wisconsin driver license and proof of citizenship or lawful status","A passport and a notarized employer letter","A Social Security card and a vehicle title","A high school diploma and two character references"],"answer":0,"explanation":"Wisconsin applicants must hold a valid Wisconsin driver license and provide proof of U.S. citizenship or legal presence, along with the application (MV3001) and tier self-certification (MV3230). Source: wisconsindot.gov CDL Requirements; Wisconsin Commercial Driver's Manual.","handbook":"","hbref":""},{"q":"A CDL holder who lets their Fed Med card lapse and has no valid medical certificate on file in Wisconsin is restricted to what type of operation?","options":["Intrastate operation only (within Wisconsin)","Interstate operation only","Operation of empty vehicles only","No operation of any commercial vehicle is permitted"],"answer":0,"explanation":"A driver without a valid federal medical card is restricted to intrastate (within-state) operation, or intrastate excepted operation, and loses interstate authority. Source: Wisconsin Commercial Driver's Manual, CLP/medical section.","handbook":"","hbref":""},{"q":"Who, besides Wisconsin DMV examiners, is authorized to administer Wisconsin CDL skills tests?","options":["DMV-authorized third party examiners","Any licensed CDL driver chosen by the applicant","FMCSA field inspectors","County sheriff's deputies"],"answer":0,"explanation":"Wisconsin DMV authorizes approved third party examiners to administer CDL skills tests; applicants contact an authorized third party examiner to schedule. Source: Wisconsin Commercial Driver's Manual, skills testing section.","handbook":"","hbref":""},{"q":"On the vehicle inspection segment of the Wisconsin skills test, what is the applicant required to do?","options":["Inspect the vehicle and explain to the examiner what is being checked and why","Watch the examiner inspect the vehicle and sign a checklist","Submit a mechanic's written inspection report from the prior week","Drive the vehicle on the road while describing the dashboard gauges"],"answer":0,"explanation":"In the vehicle inspection test, the applicant performs the inspection and explains to the examiner what would be inspected and why, demonstrating knowledge that the vehicle is safe to drive. Source: Wisconsin Commercial Driver's Manual, Section 2.1 and Section 11M.","handbook":"","hbref":""},{"q":"What is the relationship between the medical examiner who issues a Fed Med card and the FMCSA National Registry?","options":["The exam must be performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed physician may issue the card without registration","Only Wisconsin DMV staff physicians may perform the exam","The card is issued by FMCSA directly after a mailed questionnaire"],"answer":0,"explanation":"The DOT physical must be performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners, who completes the FMCSA Medical Examination Report and issues the Medical Examiner's Certificate. Source: wisconsindot.gov Fed Med card page; 49 CFR 390.103.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая ширина транспортного средства вместе с грузом на автодороге штата Висконсин без специального разрешения?","options":["8 футов 0 дюймов","8 футов 6 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Wis. Stat. 348.05(1) запрещает движение транспортного средства с общей шириной более 8 футов 6 дюймов (102 inches) без разрешения. Это соответствует федеральному стандарту, принятому Висконсином."},"1":{"q":"Какова максимальная допустимая высота транспортного средства (включая груз) на автодороге штата Висконсин без разрешения?","options":["13 футов 0 дюймов","13 футов 6 дюймов","14 футов 0 дюймов","14 футов 6 дюймов"],"explanation":"Wis. Stat. 348.06(1) устанавливает максимальную общую высоту в 13 футов 6 дюймов (13 1/2 футов) без разрешения. Водители по-прежнему несут ответственность за фактический габарит по высоте независимо от этого предела."},"2":{"q":"Какова максимальная полная масса, приходящаяся на любую одиночную ось, на автодороге штата Висконсин без разрешения?","options":["18,000 фунтов","20,000 фунтов","22,400 фунтов","24,000 фунтов"],"explanation":"Согласно Wis. Stat. 348.15(3)(b), полная масса на любой одиночной оси не может превышать 20,000 фунтов. Это совпадает с федеральным пределом для одиночной оси."},"3":{"q":"Какова максимальная полная масса, допустимая на сдвоенную осевую группу, на автодороге класса \"A\" штата Висконсин без разрешения?","options":["32,000 фунтов","34,000 фунтов","36,000 фунтов","40,000 фунтов"],"explanation":"Wis. Stat. 348.15(3)(d) позволяет сдвоенной осевой группе (два последовательных комплекта) нести до 34,000 фунтов, что соответствует федеральному пределу для сдвоенной оси."},"4":{"q":"На автодороге класса \"A\" штата Висконсин какова максимальная допустимая полная масса транспортного средства для правильно распределённой по осям пятиосной автопоездной комбинации, работающей без разрешения?","options":["73,280 фунтов","76,000 фунтов","80,000 фунтов","84,000 фунтов"],"explanation":"Таблица масс осевых групп в Wis. Stat. 348.15(3)(g), применяющая федеральную мостовую формулу, ограничивает допустимую полную массу значением 80,000 фунтов. WisDOT публикует 80,000 lb как законный предел."},"5":{"q":"Какую максимальную полную массу штат Висконсин допускает на любое одно колесо или колёса, поддерживающие один конец оси, без разрешения?","options":["9,000 фунтов","10,000 фунтов","11,000 фунтов","13,000 фунтов"],"explanation":"Wis. Stat. 348.15(3)(a) ограничивает полную массу на любое одно колесо или колёса, поддерживающие один конец оси, значением 11,000 фунтов."},"6":{"q":"Какова максимальная общая длина одиночного транспортного средства на автодороге штата Висконсин без разрешения?","options":["40 футов","45 футов","48 футов","53 фута"],"explanation":"Wis. Stat. 348.07(1) ограничивает общую длину одиночного транспортного средства 45 футами без разрешения (для сельскохозяйственной техники предусмотрен отдельный, более высокий допуск)."},"7":{"q":"Какова максимальная общая длина автопоезда из двух транспортных средств вместе с грузом на автодороге штата Висконсин без разрешения (там, где применяется ограничение общей длины)?","options":["65 футов","70 футов","75 футов","80 футов"],"explanation":"Wis. Stat. 348.07(1) устанавливает общий предел длины для автопоезда из двух транспортных средств в 70 футов, хотя для некоторых седельных тягачей с полуприцепом на определённых автодорогах ограничения общей длины нет."},"8":{"q":"На автодороге штата Висконсин, обозначенной согласно s. 348.07(4), какова максимальная длина одиночного полуприцепа, эксплуатируемого в составе автопоезда из двух транспортных средств (при расстоянии от шкворня до оси в пределах нормы)?","options":["48 футов","50 футов","53 фута","57 футов"],"explanation":"Wis. Stat. 348.07(2)(gv) допускает 53-футовый полуприцеп (расстояние от шкворня до оси не более 43 футов) в составе автопоезда из двух транспортных средств на обозначенных автодорогах, без ограничения общей длины комбинации."},"9":{"q":"На автодорогах штата Висконсин, НЕ обозначенных согласно s. 348.07(4), какова максимальная длина полуприцепа или прицепа, эксплуатируемого в составе автопоезда из двух транспортных средств?","options":["45 футов","48 футов","53 фута","57 футов"],"explanation":"Wis. Stat. 348.07(2)(g) ограничивает полуприцеп или прицеп длиной 48 футов на автодорогах, не обозначенных согласно s. 348.07(4); допуск в 53 фута применяется только на обозначенных автодорогах."},"10":{"q":"Какова максимальная допустимая масса на управляемой оси седельного тягача в штате Висконсин, когда заводская паспортная характеристика не разрешает большего?","options":["11,000 фунтов","12,000 фунтов","13,000 фунтов","15,000 фунтов"],"explanation":"Wis. Stat. 348.15(3)(b) ограничивает управляемую ось седельного тягача 13,000 фунтами, если заводская паспортная грузоподъёмность (шины, ось и т. д.) не выше, вплоть до 20,000 фунтов."},"11":{"q":"Каким методом рассчитываются весовые ограничения штата Висконсин для групп из двух или более последовательных осей?","options":["Единый предел в 80,000 фунтов независимо от расстояния между осями","Федеральная мостовая формула / весовая таблица в s. 348.15(3)(g)","Только заводская характеристика GVWR","Фиксированные 34,000 фунтов на осевую группу"],"explanation":"Wis. Stat. 348.15(3)(g) устанавливает максимальные полные массы для последовательных осевых групп согласно таблице, применяющей федеральную мостовую формулу, на основе расстояния между осями и числа осей."},"12":{"q":"В штате Висконсин, когда обычно требуется разрешение Министерства транспорта на сверхгабаритный/сверхтяжёлый груз (OSOW)?","options":["Только для грузов свыше 100,000 фунтов","Когда транспортное средство или груз превышает установленные законом пределы по габаритам или массе","Только для транспортных средств шире 10 футов","Только при движении по системе межштатных автомагистралей"],"explanation":"Согласно Wis. Stat. ch. 348 и правилам выдачи разрешений WisDOT, транспортное средство или груз, превышающие законные пределы по габаритам или массе (ширина, высота, длина или масса), должны получить разрешение OSOW до начала эксплуатации."},"13":{"q":"Неделимый груз, превышающий законные габариты штата Висконсин для одной поездки, обычно разрешается каким типом разрешения?","options":["Разовое разрешение OSOW на одну поездку","Регистрационная наклейка транспортного средства","Подтверждение CDL","Распределённый номерной знак IRP"],"explanation":"WisDOT выдаёт разовые разрешения OSOW на одну поездку (форма MV2600) для неделимых сверхгабаритных/сверхтяжёлых грузов по указанному маршруту; разрешения на несколько поездок и годовые разрешения охватывают соответствующие повторяющиеся перевозки."},"14":{"q":"По разрешению OSOW штата Висконсин на несколько поездок по массе, сколько осей минимум должна иметь автопоездная комбинация, чтобы претендовать на повышенный допуск полной массы?","options":["Четыре оси","Пять осей","Шесть осей","Восемь осей"],"explanation":"Разрешения WisDOT на несколько поездок по массе требуют комбинации из шести или более осей, причём каждая учитываемая ось, как правило, несёт не менее 8 процентов общей полной массы."},"15":{"q":"По разрешениям OSOW штата Висконсин для транспортных средств, перевозящих необработанную лесопродукцию при повышенной массе, какова максимальная разрешённая полная масса?","options":["80,000 фунтов","90,000 фунтов","98,000 фунтов","120,000 фунтов"],"explanation":"Разрешения WisDOT на необработанную лесопродукцию (RS) допускают максимальную полную массу 98,000 фунтов при комбинации из шести или более осей, причём ни одна одиночная ось не превышает 18,000 фунтов."},"16":{"q":"Какова максимальная допустимая ширина для большинства сельскохозяйственных коммерческих транспортных средств на автодорогах штата Висконсин без разрешения, в рамках сельскохозяйственного допуска по ширине?","options":["8 футов 6 дюймов","9 футов 6 дюймов","10 футов","12 футов"],"explanation":"Wis. Stat. 348.05(2)(am) допускает для некоторых сельскохозяйственных коммерческих транспортных средств ширину до 10 футов без разрешения (с более высокими допусками для отдельного оборудования, такого как опрыскиватели)."},"17":{"q":"Законный предел полной массы в 80,000 фунтов штата Висконсин применяется к автодорогам класса \"A\". Как этот предел трактуется в системе межштатных автомагистралей штата?","options":["На межштатных автомагистралях вообще нет ограничения массы","На межштатных автомагистралях применяются те же осевые пределы и мостовая формула, с законным максимумом 80,000 фунтов","Межштатные автомагистрали допускают 120,000 фунтов без разрешения","Межштатные автомагистрали допускают только 73,280 фунтов"],"explanation":"Висконсин применяет федеральные осевые пределы и мостовую формулу к системе межштатных автомагистралей, что даёт тот же законный максимум в 80,000 фунтов (Wis. Stat. 348.15; 23 U.S.C. 127), поэтому сверхтяжёлые грузы всё равно требуют разрешения."},"18":{"q":"По разрешению OSOW штата Висконсин на перевозку жидких молочных продуктов полная масса может превышать обычный максимум не более чем на сколько?","options":["10,000 фунтов","15,000 фунтов","18,000 фунтов","25,000 фунтов"],"explanation":"Разрешения WisDOT на жидкие молочные продукты (FMP) позволяют комбинациям превышать максимальную полную массу не более чем на 18,000 фунтов (до 98,000 lb) при комбинации из шести или более осей."},"19":{"q":"Сдвоенная осевая группа в штате Висконсин может быть загружена до 34,000 фунтов только если расстояние между первой и последней осями двух последовательных сдвоенных комплектов соответствует какому минимальному значению?","options":["28 футов или более","30 футов или более","36 футов или более","40 футов или более"],"explanation":"Wis. Stat. 348.15(3)(d) разрешает каждому из двух последовательных сдвоенных осевых комплектов нести 34,000 фунтов, когда расстояние между первой и последней осями составляет 36 футов или более."},"20":{"q":"В штате Висконсин какой класс CDL требуется для управления автопоездной комбинацией с полной массой автопоезда (GCWR) свыше 26,000 фунтов, включающей буксируемую единицу с GVWR свыше 10,000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Висконсин определяет CDL класса A как автопоездную комбинацию с GCWR (либо фактической/зарегистрированной массой) свыше 26,000 фунтов, включая буксируемую единицу с GVWR свыше 10,000 фунтов. Источник: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'"},"21":{"q":"По правилам штата Висконсин, одиночный тяжёлый грузовик с цельной рамой с GVWR свыше 26,000 фунтов и без прицепа (либо с буксируемой единицей в 10,000 фунтов или менее) требует какого класса CDL?","options":["Класс A","Класс B","Класс C","CDL не требуется"],"explanation":"Висконсин определяет CDL класса B как тяжёлое цельнорамное транспортное средство с GVWR (либо фактической/зарегистрированной массой) свыше 26,000 фунтов, включая такое транспортное средство, буксирующее единицу в 10,000 фунтов или менее. Источник: Wisconsin Commercial Driver's Manual (WisDOT)."},"22":{"q":"Малое транспортное средство с GVWR 26,000 фунтов или менее предназначено для перевозки 16 или более человек, включая водителя. Какого класса CDL штата Висконсин оно требует?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"Висконсин определяет CDL класса C как транспортное средство массой 26,000 фунтов или менее, предназначенное для перевозки 16 или более человек (включая водителя), либо любого размера, используемое для перевозки опасных материалов, как определено в 49 CFR 383.5. Источник: Wisconsin Commercial Driver's Manual (WisDOT)."},"23":{"q":"При определении класса коммерческого транспортного средства для целей CDL штата Висконсин какое значение должно использоваться?","options":["Всегда только заводское GVWR","Наименьшее из GVWR, фактической полной массы или зарегистрированной массы","Наибольшее из GVWR, фактической полной массы или зарегистрированной массы","Снаряжённая масса транспортного средства порожнём"],"explanation":"Висконсин предписывает водителям использовать наибольшее из значений: паспортной полной массы (GVWR), фактической полной массы или зарегистрированной массы для определения класса CMV. Источник: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'"},"24":{"q":"Какое подтверждение требуется на CDL штата Висконсин для управления коммерческим транспортным средством, перевозящим опасные материалы в количествах, требующих установки знаков-плакатов?","options":["Подтверждение N","Подтверждение H","Подтверждение T","Подтверждение X"],"explanation":"Подтверждение 'H' (HazMat) требуется для перевозки опасных материалов, как определено в 49 CFR 383.5. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел о подтверждениях."},"25":{"q":"Какое подтверждение CDL штата Висконсин позволяет водителю управлять коммерческим транспортным средством, оборудованным грузовой цистерной, используемой для перевозки жидкостей или газов наливом?","options":["Подтверждение P","Подтверждение T","Подтверждение N","Подтверждение S"],"explanation":"Подтверждение 'N' (Цистерна) требуется для коммерческих транспортных средств, оборудованных грузовой цистерной для перевозки жидких или газообразных материалов наливом. Источник: Wisconsin Commercial Driver's Manual (WisDOT), перечень подтверждений."},"26":{"q":"По правилу штата Висконсин о цистернах, тест на подтверждение для цистерны требуется для транспортного средства, перевозящего жидкость или газ в отдельной ёмкости с паспортной вместимостью более 119 галлонов и суммарной паспортной вместимостью не менее скольки?","options":["500 галлонов или более","1,000 галлонов или более","2,500 галлонов или более","3,000 галлонов или более"],"explanation":"Висконсин требует тест на цистерну для транспортных средств, перевозящих жидкости или газы в ёмкости с паспортной вместимостью более 119 галлонов и суммарной паспортной вместимостью 1,000 галлонов или более. Источник: Wisconsin Commercial Driver's Manual (WisDOT), Section 8 / тест на цистерну."},"27":{"q":"Какое подтверждение нужно владельцу CDL штата Висконсин, чтобы буксировать более одного прицепа (двойные или тройные)?","options":["Подтверждение T","Подтверждение N","Подтверждение H","Подтверждение P"],"explanation":"Подтверждение 'T' (Двойные/Тройные) разрешает водителю управлять автопоездными комбинациями, буксирующими более одного прицепа, и требует сдачи теоретического теста по двойным и тройным прицепам. Источник: Wisconsin Commercial Driver's Manual (WisDOT)."},"28":{"q":"Коммерческое транспортное средство штата Висконсин предназначено для перевозки 16 или более пассажиров, включая водителя. Какое подтверждение требуется в дополнение к надлежащему классу CDL?","options":["Подтверждение S","Подтверждение P","Подтверждение N","Подтверждение T"],"explanation":"Подтверждение 'P' (Пассажирское) требуется для управления транспортным средством, предназначенным для перевозки или фактически перевозящим 16 или более пассажиров, включая водителя. Источник: Wisconsin Commercial Driver's Manual (WisDOT), перечень подтверждений."},"29":{"q":"Какое утверждение о подтверждении 'S' для школьного автобуса штата Висконсин является ВЕРНЫМ?","options":["Оно требует лишь однократного теоретического теста, который никогда не истекает","Оно требует теоретического теста и практического экзамена по вождению как при первичной выдаче, так и при каждом продлении","Оно автоматически предоставляется любому, у кого есть подтверждение 'P'","Оно доступно только на CDL класса A"],"explanation":"Висконсин требует от соискателя подтверждения 'S' для школьного автобуса сдать теоретический тест и практический экзамен по вождению при первичной выдаче, а также пройти тестирование (теория, дорожные знаки, зрение, сокращённый практический навык) повторно при каждом продлении. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел о подтверждении для школьного автобуса."},"30":{"q":"Каков минимальный возраст для получения CDL штата Висконсин, действительного для внутриштатного (в пределах Висконсина) коммерческого вождения?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Водитель должен быть не моложе 18 лет, чтобы получить CDL штата Висконсин для внутриштатной коммерческой деятельности. Источник: Wisconsin Commercial Driver's Manual (WisDOT) / требования WisDOT к CDL."},"31":{"q":"Каков минимальный возраст, требуемый для управления коммерческим транспортным средством в межштатной коммерческой деятельности (через границы штатов) по правилам штата Висконсин и федеральным правилам?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Водитель должен быть не моложе 21 года, чтобы управлять CMV в межштатной коммерческой деятельности, перевозить опасные материалы и перевозить пассажиров через границы штатов. Источник: Wisconsin Commercial Driver's Manual (WisDOT) / требования WisDOT к CDL."},"32":{"q":"По правилам штата Висконсин об ученическом коммерческом удостоверении (CLP), как долго вы должны иметь CLP, прежде чем вам будет разрешено сдавать практический экзамен (дорожный) на CDL?","options":["7 days","14 days","30 days","60 days"],"explanation":"Висконсин (следуя федеральному стандарту) требует, чтобы вы имели CLP не менее 14 days, прежде чем сдавать практический экзамен. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел об ученическом коммерческом удостоверении."},"33":{"q":"В течение скольких дней действительно ученическое коммерческое удостоверение (CLP) штата Висконсин, прежде чем его нужно продлить?","options":["90 days","180 days","1 год","2 года"],"explanation":"CLP штата Висконсин действительно в течение 180 days и может быть продлено. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел об ученическом коммерческом удостоверении / страница требований WisDOT к CDL."},"34":{"q":"При вождении с ученическим коммерческим удостоверением (CLP) штата Висконсин что требуется от сопровождающего водителя?","options":["Сопровождающий водитель не требуется, если владельцу CLP 21 год","Действующий владелец CDL, с классом и уровнем подтверждений не ниже, чем у удостоверения, должен сидеть рядом с владельцем CLP","Любой лицензированный водитель в возрасте 16 лет или старше может ехать на заднем сиденье","Экзаменатор WisDOT должен присутствовать постоянно"],"explanation":"Владельца CLP должен сопровождать человек, имеющий действующий CDL с классом/уровнем подтверждений не ниже, чем у удостоверения, сидящий рядом с владельцем CLP спереди. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел о CLP."},"35":{"q":"При подаче заявления на подтверждение HazMat 'H' штата Висконсин или его продлении, какое дополнительное федеральное требование должен выполнить соискатель помимо сдачи теоретического теста по HazMat?","options":["Второй практический экзамен по вождению на транспортном средстве со знаками-плакатами","Дактилоскопирование для проверки криминального прошлого / оценки угрозы ФБР","Нотариально заверенное письмо-поручительство от работодателя","Плата за подписку на реестр учёта наркотиков и алкоголя"],"explanation":"Висконсин требует от соискателей подтверждения 'H' предоставить отпечатки пальцев для проверки криминального прошлого в ФБР (оценка угрозы безопасности TSA) и предъявить доказательство гражданства США или законного статуса, при первичной выдаче и при каждом продлении. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел о подтверждении HazMat 'H'."},"36":{"q":"Для подтверждения HazMat 'H' штата Висконсин судимость за определённые дисквалифицирующие преступления препятствует выдаче, если осуждение произошло в течение скольких лет до даты подачи заявления?","options":["3 года","5 лет","7 лет","10 лет"],"explanation":"Соискателю не будет разрешено получить, продлить или перенести подтверждение 'H', если он был осуждён (или признан невиновным по причине невменяемости) за определённые дисквалифицирующие преступления в течение 7 лет до даты подачи заявления. Источник: Wisconsin Commercial Driver's Manual (WisDOT), дисквалификации по HazMat."},"37":{"q":"Какой документ или доказательство штат Висконсин специально требует предъявить соискателю подтверждения HazMat 'H', который НЕ требуется для большинства других подтверждений CDL?","options":["Доказательство гражданства США или законного статуса в США","Аттестат об окончании средней школы","Договор аренды коммерческого транспортного средства","Номер USDOT автоперевозчика"],"explanation":"Висконсин требует от соискателей HazMat 'H' предъявить доказательство гражданства США или законного статуса в США при теоретическом тестировании, первичной выдаче и всех продлениях, в дополнение к проверке прошлого в ФБР. Источник: Wisconsin Commercial Driver's Manual (WisDOT), раздел о подтверждении HazMat 'H'."},"38":{"q":"Начальная подготовка водителя (ELDT) в штате Висконсин должна быть пройдена через поставщика, указанного где, и требуется для впервые подающих заявление на CDL и определённых подтверждений?","options":["Реестр системы технических колледжей штата Висконсин","Реестр поставщиков обучения FMCSA (TPR)","База данных Национального совета по безопасности","Любой список сторонних экзаменаторов, одобренных DMV"],"explanation":"ELDT должна быть получена у поставщика обучения, указанного в Реестре поставщиков обучения FMCSA (tpr.fmcsa.dot.gov). Она требуется для первого CDL, повышения класса (с B до A), а также подтверждений H, P и S; водители, чей CDL был выдан до February 7, 2022, освобождены. Источник: страница требований WisDOT к CDL / Wisconsin Commercial Driver's Manual."},"39":{"q":"В медицинской самосертификации CDL штата Висконсин какая из следующих является одной из четырёх действительных категорий сертификации деятельности?","options":["Межштатная без исключений (NI)","Федеральная сертификация по Hazmat (FH)","Межштатная приостановленная (IS)","Коммерческая фермерская с исключением (CF)"],"explanation":"Четыре категории самосертификации CDL штата Висконсин: Межштатная без исключений (NI), Межштатная с исключением (EI), Внутриштатная без исключений (NA) и Внутриштатная с исключением (EA); водители NI должны соответствовать медицинским требованиям 49 CFR Part 391 и иметь действующую карту Fed Med. Источник: WisDOT MV3230 Commercial Driver Certification: Tier of Operation / страница карты Fed Med."},"40":{"q":"В штате Висконсин какова максимальная концентрация алкоголя в крови (BAC), при которой человек может на законных основаниях управлять коммерческим транспортным средством (CMV)?","options":["0.04","0.08","0.02","0.00"],"explanation":"Висконсин запрещает управление CMV при BAC 0.04 или выше (Wis. Stat. § 346.63(5); Wisconsin CDL Manual). Достижение 0.04 в CMV является серьёзным дисквалифицирующим нарушением, в отличие от предела 0.08, применяемого к обычным (некоммерческим) транспортным средствам."},"41":{"q":"На сколько дисквалифицируется CDL в штате Висконсин за первое серьёзное нарушение, такое как управление CMV при BAC 0.04 или выше?","options":["1 год","60 days","6 месяцев","3 года"],"explanation":"Согласно таблице общих дисквалификаций CDL штата Висконсин (WisDOT) и Wis. Stat. § 343.315, первое осуждение за серьёзное нарушение дисквалифицирует CDL на 1 год. Период в 3 года применяется только когда водитель перевозил опасные материалы со знаками-плакатами."},"42":{"q":"По правилам штата Висконсин первое серьёзное нарушение (такое как OWI в CMV) влечёт дисквалификацию CDL на 3 года вместо 1 года при каком условии?","options":["Водитель перевозил опасные материалы со знаками-плакатами","Водителю было более 65 лет","Авария причинила имущественный ущерб","У водителя на борту было двое пассажиров"],"explanation":"Таблица дисквалификаций CDL WisDOT и Wis. Stat. § 343.315 повышают дисквалификацию за первое серьёзное нарушение с 1 года до 3 лет, когда нарушение произошло, пока CMV перевозил опасные материалы со знаками-плакатами."},"43":{"q":"Каков период дисквалификации CDL в штате Висконсин за ВТОРОЕ серьёзное нарушение (например, второе OWI в CMV)?","options":["Пожизненно","3 года","10 лет","5 лет"],"explanation":"Второе осуждение за любое серьёзное дисквалифицирующее нарушение влечёт пожизненную дисквалификацию CDL согласно таблице дисквалификаций CDL WisDOT и Wis. Stat. § 343.315 (отражающей 49 CFR 383.51)."},"44":{"q":"По закону штата Висконсин о подразумеваемом согласии, что происходит, если водитель CMV отказывается выполнить требование сотрудника правоохранительных органов пройти химический тест на алкоголь или наркотики?","options":["CDL дисквалифицируется на 1 год (пожизненно при повторном случае)","Выносится предупреждение без дисквалификации","CDL дисквалифицируется на 60 days","CDL дисквалифицируется на 6 месяцев"],"explanation":"Отказ рассматривается как серьёзное нарушение: дисквалификация CDL на 1 год за первый случай и пожизненная дисквалификация за второй (таблица дисквалификаций CDL WisDOT; Wis. Stat. §§ 343.305, 343.315)."},"45":{"q":"По закону штата Висконсин о подразумеваемом согласии, отказ от запрошенного химического теста отзывает право управления водителя минимум на какой срок?","options":["1 год","90 days","30 days","6 месяцев"],"explanation":"Wisconsin CDL Manual гласит, что если вы отказываетесь от теста, запрошенного сотрудником по закону о подразумеваемом согласии (Wis. Stat. § 343.305), ваше право управления будет отозвано минимум на один год, помимо прочих наказаний."},"46":{"q":"Сколько серьёзных нарушений ПДД в течение 3-летнего периода влекут 60-дневную дисквалификацию CDL в штате Висконсин?","options":["2","3","4","5"],"explanation":"Два серьёзных нарушения ПДД в отдельных случаях в течение 3 лет влекут 60-дневную дисквалификацию CDL (таблица дисквалификаций CDL WisDOT; Wis. Stat. § 343.315; 49 CFR 383.51)."},"47":{"q":"В штате Висконсин три серьёзных нарушения ПДД в течение 3-летнего периода влекут дисквалификацию CDL на какой срок?","options":["120 days","60 days","1 год","90 days"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет дисквалифицируют CDL на 120 days (таблица дисквалификаций CDL WisDOT; Wis. Stat. § 343.315). Два в течение 3 лет — это 60 days."},"48":{"q":"Какое из следующих классифицируется как СЕРЬЁЗНОЕ нарушение ПДД по правилам CDL штата Висконсин?","options":["Превышение скорости на 15 mph или более сверх предела","Нарушение правил парковки","Управление при BAC 0.04 или выше","Отказ от химического теста"],"explanation":"Превышение скорости на 15 mph или более сверх предела является серьёзным нарушением ПДД (таблица дисквалификаций CDL WisDOT). BAC 0.04 и отказ от теста являются СЕРЬЁЗНЫМИ (major) нарушениями, а не серьёзными нарушениями ПДД (serious), а штрафы за парковку не учитываются."},"49":{"q":"Какое из следующих НЕ входит в перечень серьёзных нарушений ПДД штата Висконсин для целей дисквалификации CDL?","options":["Управление CMV при BAC 0.04 или выше","Слишком близкое следование за другим транспортным средством","Безрассудное вождение","Неправильное или беспорядочное перестроение"],"explanation":"Слишком близкое следование, безрассудное вождение и неправильное/беспорядочное перестроение являются серьёзными нарушениями ПДД (таблица WisDOT). Управление при BAC 0.04 или выше является СЕРЬЁЗНЫМ (major) нарушением (1 год / пожизненно), а не серьёзным нарушением ПДД (serious)."},"50":{"q":"С July 1, 2016, в штате Висконсин сколько осуждений за использование ручного мобильного телефона при управлении CMV требуется, прежде чем CDL дисквалифицируется?","options":["2 или более","1","4 или более","3 или более"],"explanation":"Wisconsin CDL Manual гласит, что CDL дисквалифицируется после двух или более осуждений за использование ручного мобильного телефона при управлении CMV: 60 days за второе нарушение в течение 3 лет и 120 days за три или более в течение 3 лет."},"51":{"q":"Согласно Wisconsin CDL Manual, каков максимальный гражданский штраф, который может быть наложен на водителя CMV за отправку текстовых сообщений во время вождения?","options":["$2,750","$2,500","$11,000","$5,000"],"explanation":"Wisconsin CDL Manual гласит, что водитель, отправляющий текстовые сообщения при управлении CMV, подлежит гражданским штрафам до $2,750 за нарушение; автоперевозчики, которые это допускают или требуют, сталкиваются со штрафами до $11,000."},"52":{"q":"Согласно Wisconsin CDL Manual, каков максимальный гражданский штраф, с которым может столкнуться автоперевозчик за допущение или требование к своим водителям использовать ручной телефон или отправлять текстовые сообщения при вождении CMV?","options":["$11,000","$2,750","$10,000","$5,500"],"explanation":"Wisconsin CDL Manual гласит, что работодатели (автоперевозчики) могут подлежать гражданским штрафам до $11,000 за допущение или требование использования ручного телефона или отправки текстовых сообщений водителями CMV; собственный штраф водителя — до $2,750."},"53":{"q":"Два осуждения за отправку текстовых сообщений при управлении CMV в течение 3-летнего периода влекут какую дисквалификацию CDL в штате Висконсин?","options":["60 days","120 days","30 days","1 год"],"explanation":"Wisconsin CDL Manual гласит, что CDL дисквалифицируется на 60 days за второе нарушение, связанное с текстовыми сообщениями, в течение 3 лет, и на 120 days за три или более нарушений в течение 3 лет."},"54":{"q":"Какова дисквалификация CDL в штате Висконсин за ВТОРОЕ нарушение предписания о выводе из эксплуатации в течение 10 лет (без hazmat, без пассажиров)?","options":["2 года","90 days","1 год","5 лет"],"explanation":"Согласно таблице дисквалификаций CDL WisDOT, второе нарушение предписания о выводе из эксплуатации в течение 10 лет дисквалифицирует CDL на 2 года (3 года при наличии знаков-плакатов hazmat или пассажирском транспортном средстве)."},"55":{"q":"В штате Висконсин какова дисквалификация CDL за ПЕРВОЕ осуждение за нарушение на железнодорожном переезде (такое как непредоставление остановки, когда пути не свободны)?","options":["60 days","30 days","120 days","90 days"],"explanation":"Таблица дисквалификаций CDL WisDOT устанавливает первое нарушение на железнодорожном переезде как 60-дневную дисквалификацию; второе в течение 3 лет — 120 days, а третье в течение 3 лет — 1 год."},"56":{"q":"Какая дисквалификация CDL применяется в штате Висконсин за ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["1 год","120 days","60 days","Пожизненно"],"explanation":"Согласно таблице дисквалификаций CDL WisDOT, нарушения на железнодорожном переезде влекут 60 days (первое), 120 days (второе в течение 3 лет) и 1 год (третье в течение 3 лет)."},"57":{"q":"В штате Висконсин использование коммерческого транспортного средства при совершении тяжкого преступления, связанного с изготовлением, распространением или сбытом контролируемого вещества, влечёт какую дисквалификацию CDL?","options":["Пожизненно, без восстановления","1 год","3 года","10 лет"],"explanation":"Согласно таблице дисквалификаций CDL WisDOT и Wis. Stat. § 343.315, тяжкое преступление, связанное с контролируемым веществом, совершённое с использованием CMV, влечёт неотменяемую пожизненную дисквалификацию (без восстановления), даже за первое нарушение."},"58":{"q":"Согласно закону Висконсина \"Move Over\", когда вы приближаетесь к эвакуатору, патрульной машине или машине дорожной службы, остановившейся на обочине с включёнными мигающими аварийными огнями, и в вашем направлении есть более одной полосы движения, что вы обязаны сделать?","options":["Перестроиться на полосу, не примыкающую к остановившейся машине, если это можно сделать безопасно","Полностью остановиться и ждать, пока огни другой машины не будут выключены","Продолжать движение с установленной скоростью, так как закон Move Over распространяется только на полицейские машины","Подать звуковой сигнал и сохранять свою скорость, проезжая мимо остановившейся машины"],"explanation":"Закон Висконсина \"Move Over\" (Wis. Stat. s. 346.072) требует, чтобы водители, приближающиеся к аварийным, эвакуационным, коммунальным машинам или машинам дорожной службы с мигающими огнями, освобождали полосу, ближайшую к такой машине, перестраиваясь в сторону, если перестроение можно выполнить безопасно. Руководство Wisconsin CDL Manual (Section 2.8) и WisDOT указывают, что это касается правоохранительных органов, EMS, пожарных, эвакуаторов и придорожных рабочих, а не только полиции."},"59":{"q":"Согласно закону Висконсина \"Move Over\", что вы обязаны сделать, если не можете безопасно перестроиться в сторону от остановившейся аварийной или придорожной служебной машины с включёнными мигающими огнями?","options":["Снизить скорость и продолжать движение с осторожностью, пока безопасно не проедете машину","Полностью остановиться на обочине и ждать, пока машина не уедет","Сохранять установленную скорость, поскольку перестроиться невозможно","Съехать на противоположную сторону дороги, чтобы обеспечить максимальный зазор"],"explanation":"Wis. Stat. s. 346.072 и руководство Wisconsin CDL Manual (Section 2.8) указывают, что если перестроение небезопасно (или в вашем направлении есть только одна полоса), вы обязаны снизить скорость и продолжать движение с осторожностью, пока безопасно не проедете остановившуюся машину. Требования останавливаться или использовать встречную полосу нет."},"60":{"q":"В Висконсине транспортное средство, приближающееся к остановившемуся школьному автобусу с включёнными мигающими красными аварийными огнями, должно остановиться на каком минимальном расстоянии от автобуса?","options":["Не менее чем в 20 feet от автобуса","Не менее чем в 10 feet от автобуса","Не менее чем в 50 feet от автобуса","Не менее чем в 100 feet от автобуса"],"explanation":"Wisconsin Statute 346.48(1) требует, чтобы водитель транспортного средства, приближающийся спереди или сзади к школьному автобусу с включёнными мигающими красными аварийными огнями, остановился не менее чем в 20 feet от автобуса и оставался на месте, пока автобус не тронется или красные огни не будут выключены."},"61":{"q":"Согласно закону Висконсина, кто освобождается от обязанности останавливаться перед школьным автобусом с включёнными мигающими красными аварийными огнями?","options":["Водители, движущиеся в противоположном направлении по разделённой автомагистрали","Водители, движущиеся в том же направлении в пределах 100 feet от автобуса","Водители на любой дороге с двумя или более полосами в их направлении","Никто не освобождается; все водители обязаны останавливаться на дорогах любого типа"],"explanation":"Wisconsin Statute 346.48(1) предусматривает одно исключение: требование останавливаться не распространяется на водителей транспортных средств, движущихся в ПРОТИВОПОЛОЖНОМ направлении по РАЗДЕЛЁННОЙ автомагистрали. На неразделённых дорогах встречный транспорт всё равно обязан останавливаться. Транспорт, движущийся в том же направлении, обязан останавливаться всегда."},"62":{"q":"Водитель школьного автобуса в Висконсине приближается к железнодорожному переезду, перед которым обязан остановиться. Передняя часть автобуса должна полностью остановиться в каком диапазоне расстояний от ближайшего рельса?","options":["Не менее чем в 15 feet и не более чем в 50 feet","Не менее чем в 5 feet и не более чем в 15 feet","Не менее чем в 25 feet и не более чем в 75 feet","Не менее чем в 50 feet и не более чем в 100 feet"],"explanation":"Руководство Wisconsin CDL Manual (Sections 2.15 и 4.3.5) требует, чтобы автобус остановился в пределах от 15 до 50 feet перед железнодорожным переездом — не ближе 15 feet и не дальше 50 feet от ближайшего рельса, — а затем осмотрелся и прислушался в обоих направлениях перед тем, как продолжить движение."},"63":{"q":"Согласно руководству Wisconsin CDL Manual, транспортное средство с табличками опасных грузов должно остановиться в пределах от 15 до 50 feet перед железнодорожным переездом. Помимо грузов с табличками, что из перечисленного ТАКЖЕ требует остановки даже в пустом состоянии?","options":["Цистерна, используемая для опасных материалов, как загруженная, так и пустая","Любой грузовик-фургон массой более 26,000 pounds, перевозящий сухой груз","Бортовая платформа, перевозящая стальные рулоны, которые надлежащим образом закреплены","Рефрижераторный фургон, перевозящий скоропортящиеся пищевые продукты"],"explanation":"Wisconsin CDL Manual Section 9.6.12 указывает, что транспортное средство должно остановиться в пределах от 15 до 50 feet перед ближайшим рельсом, если оно имеет таблички, перевозит любое количество хлора ИЛИ имеет цистерны, используемые для опасных материалов, как загруженные, так и пустые. Обычные сухие грузы или рефрижераторные грузы не требуют остановки."},"64":{"q":"Если вам необходимо остановить коммерческое транспортное средство на двухполосной дороге или неразделённой автомагистрали в Висконсине, в течение скольких минут вы обязаны выставить аварийные предупреждающие устройства?","options":["В течение 10 минут","В течение 2 минут","В течение 15 минут","В течение 30 минут"],"explanation":"Руководство Wisconsin CDL Manual (Section 2.7) указывает, что если вам необходимо остановиться на дороге или обочине, вы обязаны выставить аварийные предупреждающие устройства в течение 10 минут после остановки."},"65":{"q":"При остановке на двухполосной дороге в Висконсине с движением в обоих направлениях, где, согласно руководству CDL Manual, следует размещать три светоотражающих треугольника?","options":["В пределах 10 feet от транспортного средства, а также в 100 feet позади и в 100 feet впереди","На расстоянии 10 feet, 100 feet и 200 feet только позади транспортного средства","На расстоянии 50 feet, 100 feet и 500 feet в сторону приближающегося транспорта","Все три в пределах 25 feet от заднего бампера транспортного средства"],"explanation":"Руководство Wisconsin CDL Manual (Section 2.7) предписывает, что на двухполосной/неразделённой дороге вы размещаете один треугольник в пределах 10 feet от переднего или заднего угла транспортного средства, один примерно в 100 feet позади и один примерно в 100 feet впереди, на обочине или на полосе, где вы остановились."},"66":{"q":"Согласно руководству Wisconsin CDL Manual, где следует размещать три предупреждающих треугольника при остановке на дороге с односторонним движением или на разделённой автомагистрали?","options":["На расстоянии 10 feet, 100 feet и 200 feet в сторону приближающегося транспорта","На расстоянии 10 feet, 100 feet и 100 feet с обеих сторон транспортного средства","На расстоянии 25 feet, 100 feet и 300 feet в сторону приближающегося транспорта","На расстоянии 50 feet, 150 feet и 250 feet позади транспортного средства"],"explanation":"Руководство Wisconsin CDL Manual (Section 2.7) указывает, что на дороге с односторонним движением или разделённой автомагистрали вы размещаете предупреждающие устройства на расстоянии 10 feet, 100 feet и 200 feet в сторону приближающегося транспорта (позади транспортного средства)."},"67":{"q":"Руководство Wisconsin CDL Manual указывает, что если вы останавливаетесь рядом с холмом, поворотом или препятствием, которое мешает другим водителям увидеть ваше транспортное средство в пределах определённого расстояния, вам следует отодвинуть самый дальний треугольник назад. Каково это значение расстояния видимости?","options":["500 feet","200 feet","300 feet","1,000 feet"],"explanation":"Руководство Wisconsin CDL Manual (Section 2.7) указывает, что если холм, поворот или иное препятствие мешает водителям увидеть ваше транспортное средство в пределах 500 feet, переместите самый дальний предупреждающий треугольник дальше по дороге, чтобы обеспечить достаточное заблаговременное предупреждение."},"68":{"q":"Каков максимальный предел скорости для коммерческого грузовика на сельской автостраде Висконсина, являющейся частью системы межштатных автомагистралей?","options":["70 miles per hour, так же как для легковых автомобилей","55 miles per hour для всех грузовиков массой более 26,000 pounds","65 miles per hour, ниже, чем предел 70 mph для легковых автомобилей","60 miles per hour для любого транспортного средства, буксирующего прицеп"],"explanation":"Согласно Wis. Stat. s. 346.57(4), предел скорости на автострадах Висконсина, включая межштатные автомагистрали, составляет 70 mph. Висконсин не устанавливает отдельного, более низкого предела скорости для грузовиков — в отличие от некоторых соседних штатов, — поэтому грузовики могут двигаться с той же установленной скоростью 70 mph там, где это обозначено, с учётом основного правила безопасной скорости."},"69":{"q":"Ограничивает ли закон Висконсина коммерческие грузовики определёнными полосами (например, запрещая им левую полосу) на межштатных автомагистралях в целом?","options":["Общештатного запрета на полосы только для грузовиков не существует; применяется общее правило \"держись правее, кроме обгона\"","Да, грузовикам запрещена крайняя левая полоса на всех межштатных автомагистралях Висконсина","Да, грузовики должны держаться правой полосы всегда, когда есть три или более полос","Да, грузовики массой более 10,000 pounds могут использовать только две правые полосы по всему штату"],"explanation":"В Висконсине нет общештатного закона, ограничивающего грузовики определёнными полосами. Общее правило (Wis. Stat. s. 346.05) требует движения по правой стороне и использования левой полосы преимущественно для обгона. Конкретные местные ограничения полос могут быть обозначены, но общего запрета на полосы для грузовиков на межштатных автомагистралях, как в некоторых штатах, нет."},"70":{"q":"Руководство Wisconsin CDL Manual содержит специфическую для штата заметку о школьных автобусах и железнодорожных путях. Какое утверждение отражает эту заметку Висконсина?","options":["В Висконсине школьные автобусы обязаны останавливаться на путях, используемых для промышленного маневрирования","В Висконсине школьные автобусы могут проезжать любой переезд на скорости менее 10 mph","В Висконсине школьные автобусы никогда не останавливаются на переездах в черте города","В Висконсине школьные автобусы останавливаются только на переездах с действующими шлагбаумами"],"explanation":"Руководство Wisconsin CDL Manual (Section 4.3.5) содержит \"Wisconsin Note\", где указано, что в Висконсине школьные автобусы обязаны останавливаться на путях, используемых для промышленного маневрирования, — это специфическое для штата требование сверх общих правил проезда переездов."},"71":{"q":"Согласно руководству Wisconsin CDL Manual, на каком типе переезда водителю автобуса НЕ нужно делать полную остановку (но всё равно нужно снизить скорость и проверить наличие транспорта)?","options":["Переезд, обозначенный как \"exempt\" (освобождённый) или \"abandoned\" (заброшенный)","Переезд со знаком crossbuck и без шлагбаумов","Переезд с несколькими путями в сельской местности","Переезд, где предупреждающие звонки молчат"],"explanation":"Руководство Wisconsin CDL Manual (Section 4.3.5) перечисляет места, где автобусу не нужно останавливаться, но нужно снизить скорость и проверить: переезды трамвайных путей, места, где движением управляет инспектор или регулировщик, когда светофор показывает зелёный, и переезды, обозначенные как \"exempt\" или \"abandoned\". Обычный crossbuck без этих условий всё равно требует остановки автобуса."},"72":{"q":"Какова максимальная разрешённая законом ширина транспортного средства в Висконсине, прежде чем потребуется разрешение на негабаритный груз для движения по автомагистралям?","options":["8 feet 6 inches (8.5 feet)","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Максимальная разрешённая законом ширина в Висконсине составляет 8 feet 6 inches (8.5 feet); грузы шире этого значения требуют разрешения на негабаритный груз через систему разрешений WisDOT. Стандартные законные пределы — 8.5 ft в ширину, 13.5 ft в высоту, 53 ft в длину для полуприцепа и 80,000 lbs полной массы."},"73":{"q":"В Висконсине действуют сезонные программы ограничения веса, характерные для его климата. Что разрешает зимняя декларация \"frozen road\" (промёрзшая дорога)?","options":["Более тяжёлые грузы на обозначенных дорогах, пока дорожное покрытие промёрзшее и более прочное","Полный запрет на все коммерческие грузовики до окончания весенней оттепели","Более высокие пределы скорости для грузовиков из-за сниженного летнего трафика","Освобождение от всех сборов за разрешения для грузов, движущихся только ночью"],"explanation":"Сезонные программы ограничения веса WisDOT используют преимущества климата Висконсина: зимняя декларация промёрзшей дороги (примерно с середины декабря до начала марта) разрешает более тяжёлые грузы, пока промёрзшее покрытие структурно прочнее, согласно программе WisDOT Seasonal Weight Restrictions."},"74":{"q":"Во время весенней оттепели в Висконсине программы для автомагистралей Class II и сезонных дорог с обозначенными ограничениями делают что с массой грузовиков?","options":["Снижают допустимые осевые нагрузки, чтобы защитить дорожное покрытие, ослабленное оттаиванием","Увеличивают допустимую массу, поскольку таяние снега освобождает дороги","Не влияют на массу; они изменяют только установленные пределы скорости","Применяются только к легковым автомобилям и автодомам, но не к грузовикам"],"explanation":"Программы весенней оттепели WisDOT (дороги Class II и сезонные дороги с обозначенными ограничениями, примерно с марта по май) снижают допустимые осевые нагрузки и полную массу и приостанавливают действие многих разрешений на делимые грузы, поскольку оттаивающее покрытие структурно слабое. Цель — продлить срок службы автомагистралей, согласно программе WisDOT Seasonal Weight Restrictions."},"75":{"q":"В Висконсине, когда негабаритный груз достаточно широк, чтобы потребовать одного сопровождения спереди, какой тип транспортного средства может выступать в качестве сопровождения?","options":["Легковой автомобиль или одиночный грузовик массой не более 16,000 pounds с необходимыми предупреждающими фонарями","Любой мотоцикл, оснащённый флажком и жёлтым маячком","Второй гружёный полуприцеп, движущийся непосредственно впереди груза","Только маркированная патрульная машина правоохранительных органов в каждом случае"],"explanation":"Согласно правилам Висконсина о разрешениях на негабаритные грузы (WisDOT/Trans code), сопровождающее (пилотное) транспортное средство должно быть легковым автомобилем или одиночным грузовиком массой не более 16,000 pounds, с беспрепятственным обзором, включённым ближним светом фар и включёнными предупреждающими фонарями во время сопровождения разрешённого груза."},"76":{"q":"На двухполосной дороге в Висконсине какая дополнительная дорожная разметка обычно сопровождает железнодорожный переезд для регулирования обгона?","options":["Разметка зоны запрета обгона (и знак запрета обгона) при приближении к путям","Прерывистая жёлтая осевая линия, поощряющая обгон перед путями","Сплошная белая линия полосы, позволяющая грузовикам совместно использовать переезд","Полоса велодорожки, направляющая грузовики к дальнему правому краю переезда"],"explanation":"Руководство Wisconsin CDL Manual (Section 2.15) отмечает, что на двухполосных дорогах железнодорожная дорожная разметка включает букву \"X\" с буквами \"RR\" и разметку запрета обгона, а также есть знак зоны запрета обгона при приближении к переезду. Белая стоп-линия, если она есть, — это место, где должна оставаться передняя часть автобуса во время остановки."},"77":{"q":"Водитель с CDL в Висконсине останавливается на обочине оживлённой разделённой автострады после поломки. После размещения трёх треугольников в сторону приближающегося транспорта на расстоянии 10, 100 и 200 feet, что советует руководство Wisconsin CDL Manual относительно того, как держать треугольники?","options":["Держать каждый треугольник между собой и встречным транспортом, чтобы другие водители могли вас видеть","Держать треугольники над головой и идти по центру полосы движения","Выбрасывать треугольники из кабины, чтобы вообще не покидать транспортное средство","Разместить все три с левой стороны лицом от потока движения"],"explanation":"Руководство Wisconsin CDL Manual (Section 2.7) советует при выставлении треугольников держать их между собой и встречным транспортом ради собственной безопасности, чтобы приближающиеся водители могли вас видеть, пока вы устанавливаете устройства."},"78":{"q":"Какое государственное ведомство выдаёт коммерческие водительские удостоверения (CDL) в Висконсине?","options":["Wisconsin Division of Motor Vehicles (DMV), часть WisDOT","Wisconsin State Patrol","Wisconsin Department of Public Safety","Federal Motor Carrier Safety Administration"],"explanation":"CDL в Висконсине выдаются Wisconsin Division of Motor Vehicles (DMV), подразделением Wisconsin Department of Transportation. State Patrol обеспечивает соблюдение законов об автоперевозчиках, но не выдаёт удостоверения, а FMCSA — федеральное ведомство, которое устанавливает стандарты, а не выдаёт CDL штатов. Источник: Wisconsin Commercial Driver's Manual; страница CDL Requirements на wisconsindot.gov."},"79":{"q":"Каково минимальное количество правильных ответов, необходимое для сдачи теста General Knowledge на CDL в Висконсине, который содержит 50 вопросов?","options":["40 правильных (80%)","30 правильных (60%)","35 правильных (70%)","45 правильных (90%)"],"explanation":"Тест General Knowledge в Висконсине содержит 50 вопросов, и вы должны правильно ответить как минимум на 40, что соответствует проходному баллу 80%. Стандарт 80% применяется к тестам знаний CDL в Висконсине. Источник: Wisconsin Commercial Driver's Manual; CDL Requirements на wisconsindot.gov."},"80":{"q":"Сколько действует Commercial Learner Permit (CLP) в Висконсине?","options":["180 days","90 days","1 year","60 days"],"explanation":"CLP в Висконсине действителен в течение 180 days и содержит перечень типов транспортных средств и подтверждений (endorsements), на которые квалифицировался его владелец. Источник: Wisconsin Commercial Driver's Manual, раздел Commercial Learner Permit (CLP)."},"81":{"q":"Сколько должен ждать владелец CLP в Висконсине после выдачи разрешения, прежде чем ему будет разрешено сдавать экзамен по навыкам вождения CDL?","options":["14 days","10 days","30 days","7 days"],"explanation":"Согласно федеральным правилам, принятым Висконсином, вы должны иметь CLP не менее 14 days, прежде чем вам будет разрешено сдавать экзамен по навыкам вождения. Источник: Wisconsin Commercial Driver's Manual, раздел Skills testing; 49 CFR 383.25."},"82":{"q":"Экзамен по навыкам вождения CDL в Висконсине состоит из трёх частей, которые должны сдаваться в установленном порядке. Каков правильный порядок?","options":["Осмотр транспортного средства, базовое управление транспортным средством, вождение по дороге","Вождение по дороге, осмотр транспортного средства, базовое управление транспортным средством","Базовое управление транспортным средством, вождение по дороге, осмотр транспортного средства","Осмотр транспортного средства, вождение по дороге, базовое управление транспортным средством"],"explanation":"Трёхчастный экзамен по навыкам вождения в Висконсине должен сдаваться по порядку: сначала осмотр транспортного средства, затем базовое управление транспортным средством, затем вождение по дороге. Источник: Wisconsin Commercial Driver's Manual, раздел Skills tests."},"83":{"q":"Прежде чем новый заявитель в Висконсине получит право сдавать экзамен на CDL, какое обучение должно быть пройдено?","options":["Entry Level Driver Training (ELDT) от провайдера, зарегистрированного в FMCSA","Курс безопасного вождения, одобренный округом","Двухлетняя стажировка у лицензированного перевозчика","Сертификация по безопасности труда OSHA"],"explanation":"Новые заявители на CDL (а также те, кто повышает класс или добавляет определённые подтверждения) должны пройти Entry Level Driver Training от провайдера, указанного в FMCSA Training Provider Registry, до сдачи экзамена. Источник: Wisconsin Commercial Driver's Manual; 49 CFR Part 380 Subpart F."},"84":{"q":"Какой документ используют заявители на CDL в Висконсине для самостоятельного подтверждения своего тира (типа) коммерческой деятельности?","options":["Form MV3230, Commercial Driver Certification: Tier of Operation","Form MV3001, общее заявление на водительское удостоверение","Form MV3740, самостоятельное подтверждение для школьного автобуса","FMCSA Medical Examination Report (MCSA-5875)"],"explanation":"Водители в Висконсине самостоятельно подтверждают свой тир деятельности с помощью Form MV3230. MV3001 — это общее заявление на удостоверение, MV3740 — самостоятельное подтверждение для школьного автобуса, а MCSA-5875 — отчёт о медицинском осмотре, заполняемый экзаменатором. Источник: страница Fed Med card на wisconsindot.gov; Form MV3230."},"85":{"q":"Из скольких категорий самостоятельного подтверждения (тиров деятельности) должен выбрать владелец CDL в Висконсине?","options":["Из четырёх","Из двух","Из трёх","Из пяти"],"explanation":"Существует четыре тира самостоятельного подтверждения: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate. Источник: страница Fed Med card на wisconsindot.gov; 49 CFR 383.71."},"86":{"q":"Какой тир самостоятельного подтверждения в Висконсине ТРЕБУЕТ, чтобы водитель имел действующий федеральный сертификат медицинского экзаменатора (Fed Med card)?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Любой водитель, который никогда не пересекает границы штата"],"explanation":"Водители Non-Excepted Interstate (NI) должны иметь действующую Fed Med card. Тиры Excepted Interstate и Excepted Intrastate её не требуют. Источник: страница Fed Med card на wisconsindot.gov; 49 CFR 383.71."},"87":{"q":"Согласно изменению процесса 2025 года, как информация о федеральном сертификате медицинского экзаменатора (Fed Med card) водителя в Висконсине обычно попадает в WI DMV после прохождения медосмотра DOT?","options":["FMCSA электронно передаёт её в WI DMV примерно в течение 48 часов после осмотра","Водитель всегда должен отправить бумажную копию по факсу в DMV в течение 10 дней","Работодатель-автоперевозчик отправляет её в DMV по почте от имени водителя","Она печатается на CDL и никогда не сообщается штату"],"explanation":"С 13 апреля 2025 года FMCSA автоматически предоставляет информацию о Fed Med card водителя в WI DMV, как правило, в течение 48 часов после прохождения медосмотра DOT. Осмотры, завершённые до этой даты, должны были подаваться водителем. Источник: страница Fed Med card на wisconsindot.gov."},"88":{"q":"Как часто нужно продлевать CDL в Висконсине?","options":["Каждые 8 years","Каждые 4 years","Каждые 6 years","Каждые 2 years"],"explanation":"CDL в Висконсине должен продлеваться каждые 8 years. Источник: Wisconsin Commercial Driver's Manual; информация о продлении на wisconsindot.gov."},"89":{"q":"Каков минимальный возраст для получения CDL в Висконсине для внутриштатного (в пределах Висконсина) коммерческого вождения?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"Вам должно быть не менее 18 лет, чтобы получить CDL/CLP в Висконсине для внутриштатной деятельности. Межштатная коммерческая деятельность обычно требует возраста не менее 21 года. Источник: Wisconsin Commercial Driver's Manual, раздел Commercial Learner Permit (CLP)."},"90":{"q":"При каком условии владелец CLP в Висконсине может управлять коммерческим транспортным средством в межштатной коммерческой деятельности?","options":["Только если ему не менее 21 года и он имеет действующий федеральный медицинский сертификат","В любом возрасте, поскольку CLP предоставляет полные межштатные полномочия","Только после владения CLP в течение 180 days","Только при наличии подтверждения на школьный автобус"],"explanation":"Владелец CLP не может осуществлять межштатную коммерческую деятельность, если ему не менее 21 года и у него нет действующей Fed Med card. Источник: Wisconsin Commercial Driver's Manual, раздел CLP."},"91":{"q":"На экзамене по навыкам вождения сколько из трёх сегментов должен сдать заявитель в Висконсине на одном и том же CLP?","options":["Все три сегмента должны быть сданы на одном и том же CLP","Только дорожный сегмент должен быть на одном и том же CLP","Любые два из трёх могут быть перенесены на новый CLP","Сегменты могут быть распределены между тремя различными CLP"],"explanation":"Висконсин требует, чтобы все три сегмента экзамена по навыкам вождения были сданы на одном и том же CLP. Источник: Wisconsin Commercial Driver's Manual, раздел Skills testing."},"92":{"q":"Какой тест должен сдать КАЖДЫЙ заявитель на CDL в Висконсине независимо от запрашиваемого класса или подтверждений?","options":["Тест General Knowledge","Тест Air Brakes","Тест Combination Vehicles","Тест Hazardous Materials"],"explanation":"Тест General Knowledge сдают все заявители на CDL; другие тесты знаний (air brakes, combination, hazmat и т. д.) требуются только для определённых классов или подтверждений. Источник: Wisconsin Commercial Driver's Manual, раздел Knowledge tests."},"93":{"q":"Помимо теста General Knowledge, какие ДВА документа/подтверждения требуются при подаче заявления на CLP/CDL в Висконсине?","options":["Действующее водительское удостоверение Висконсина и подтверждение гражданства или законного статуса","Паспорт и нотариально заверенное письмо от работодателя","Карточка Social Security и документ о праве собственности на транспортное средство","Аттестат об окончании средней школы и две характеристики"],"explanation":"Заявители в Висконсине должны иметь действующее водительское удостоверение Висконсина и предоставить подтверждение гражданства США или законного нахождения, а также заявление (MV3001) и самостоятельное подтверждение тира (MV3230). Источник: CDL Requirements на wisconsindot.gov; Wisconsin Commercial Driver's Manual."},"94":{"q":"Владелец CDL, у которого истекла Fed Med card и нет действующего медицинского сертификата в реестре Висконсина, ограничен каким типом деятельности?","options":["Только внутриштатной деятельностью (в пределах Висконсина)","Только межштатной деятельностью","Только эксплуатацией пустых транспортных средств","Эксплуатация любого коммерческого транспортного средства не разрешается"],"explanation":"Водитель без действующей федеральной медицинской карты ограничен внутриштатной (в пределах штата) деятельностью или внутриштатной excepted-деятельностью и теряет межштатные полномочия. Источник: Wisconsin Commercial Driver's Manual, раздел CLP/medical."},"95":{"q":"Кто, помимо экзаменаторов Wisconsin DMV, уполномочен проводить экзамены по навыкам вождения CDL в Висконсине?","options":["Сторонние экзаменаторы, авторизованные DMV","Любой лицензированный водитель CDL, выбранный заявителем","Полевые инспекторы FMCSA","Помощники шерифа округа"],"explanation":"Wisconsin DMV авторизует одобренных сторонних экзаменаторов для проведения экзаменов по навыкам вождения CDL; заявители связываются с авторизованным сторонним экзаменатором для записи. Источник: Wisconsin Commercial Driver's Manual, раздел skills testing."},"96":{"q":"В сегменте осмотра транспортного средства экзамена по навыкам вождения в Висконсине, что обязан сделать заявитель?","options":["Осмотреть транспортное средство и объяснить экзаменатору, что проверяется и почему","Наблюдать, как экзаменатор осматривает транспортное средство, и подписать контрольный лист","Предоставить письменный отчёт механика об осмотре за предыдущую неделю","Управлять транспортным средством на дороге, описывая приборы на панели"],"explanation":"В тесте на осмотр транспортного средства заявитель выполняет осмотр и объясняет экзаменатору, что бы он осмотрел и почему, демонстрируя знание того, что транспортное средство безопасно для вождения. Источник: Wisconsin Commercial Driver's Manual, Section 2.1 и Section 11M."},"97":{"q":"Какова связь между медицинским экзаменатором, который выдаёт Fed Med card, и FMCSA National Registry?","options":["Осмотр должен проводиться медицинским экзаменатором, внесённым в FMCSA National Registry of Certified Medical Examiners","Любой лицензированный врач может выдать карту без регистрации","Только штатные врачи Wisconsin DMV могут проводить осмотр","Карта выдаётся FMCSA напрямую после отправленной по почте анкеты"],"explanation":"Медосмотр DOT должен проводиться медицинским экзаменатором, внесённым в FMCSA National Registry of Certified Medical Examiners, который заполняет FMCSA Medical Examination Report и выдаёт Medical Examiner's Certificate. Источник: страница Fed Med card на wisconsindot.gov; 49 CFR 390.103."}},"tr":{"0":{"q":"Özel bir izin olmadan, Wisconsin'deki bir karayolunda bir aracın ve yükünün izin verilen maksimum toplam genişliği nedir?","options":["8 fit 0 inç","8 fit 6 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"Wis. Stat. 348.05(1), izin olmaksızın toplam genişliği 8 fit 6 inçi (102 inç) aşan bir aracın kullanılmasını yasaklar. Bu, Wisconsin tarafından benimsenen federal standartla uyumludur."},"1":{"q":"İzin olmadan, Wisconsin'deki bir karayolunda bir aracın (yük dahil) izin verilen maksimum yasal yüksekliği nedir?","options":["13 fit 0 inç","13 fit 6 inç","14 fit 0 inç","14 fit 6 inç"],"explanation":"Wis. Stat. 348.06(1), izin olmaksızın maksimum toplam yüksekliği 13 fit 6 inç (13 1/2 fit) olarak belirler. Bu sınıra bakılmaksızın, sürücüler fiili tepe açıklığından sorumlu kalmaya devam eder."},"2":{"q":"İzin olmadan, Wisconsin'deki bir karayolunda herhangi bir tek aksa uygulanan maksimum brüt ağırlık nedir?","options":["18.000 pound","20.000 pound","22.400 pound","24.000 pound"],"explanation":"Wis. Stat. 348.15(3)(b) uyarınca, herhangi bir tek aks üzerindeki brüt ağırlık 20.000 poundu aşamaz. Bu, federal tek aks sınırıyla aynıdır."},"3":{"q":"İzin olmadan, Wisconsin'deki bir Sınıf \"A\" karayolunda tandem aks grubu için izin verilen maksimum brüt ağırlık nedir?","options":["32.000 pound","34.000 pound","36.000 pound","40.000 pound"],"explanation":"Wis. Stat. 348.15(3)(d), bir tandem aks grubunun (iki ardışık set) federal tandem aks sınırıyla uyumlu olarak 34.000 pounda kadar taşımasına izin verir."},"4":{"q":"Wisconsin'deki bir Sınıf \"A\" karayolunda, izin olmadan çalışan, uygun şekilde aralanmış beş akslı bir kombinasyon için maksimum yasal brüt araç ağırlığı nedir?","options":["73.280 pound","76.000 pound","80.000 pound","84.000 pound"],"explanation":"Wis. Stat. 348.15(3)(g) içindeki ve federal köprü formülünü uygulayan aks grubu ağırlık tablosu, yasal brüt ağırlığı 80.000 poundla sınırlar. WisDOT, yasal sınır olarak 80.000 lb yayımlar."},"5":{"q":"İzin olmadan, Wisconsin'in bir aksın bir ucunu destekleyen herhangi bir tekerleğe veya tekerleklere izin verdiği maksimum brüt ağırlık nedir?","options":["9.000 pound","10.000 pound","11.000 pound","13.000 pound"],"explanation":"Wis. Stat. 348.15(3)(a), bir aksın bir ucunu destekleyen herhangi bir tekerlek veya tekerlekler üzerindeki brüt ağırlığı 11.000 poundla sınırlar."},"6":{"q":"İzin olmadan, Wisconsin'deki bir karayolunda tek bir aracın izin verilen maksimum toplam uzunluğu nedir?","options":["40 fit","45 fit","48 fit","53 fit"],"explanation":"Wis. Stat. 348.07(1), tek bir aracı izin olmaksızın 45 fitlik bir toplam uzunlukla sınırlar (tarım araç-gereçleri için ayrı ve daha yüksek bir izin vardır)."},"7":{"q":"İzin olmadan, Wisconsin'deki bir karayolunda iki araç ve yükten oluşan bir kombinasyonun izin verilen maksimum toplam uzunluğu nedir (toplam uzunluk sınırının geçerli olduğu durumda)?","options":["65 fit","70 fit","75 fit","80 fit"],"explanation":"Wis. Stat. 348.07(1), iki araçtan oluşan bir kombinasyon için genel toplam uzunluk sınırını 70 fit olarak belirler; ancak belirlenmiş karayollarında belirli çekici-yarı römork kombinasyonlarının toplam uzunluk sınırı yoktur."},"8":{"q":"s. 348.07(4) uyarınca belirlenmiş bir Wisconsin karayolunda, iki araçlı bir kombinasyon içinde çalıştırılan tek bir yarı römorkun (kingpin-aks mesafesi sınırlar dahilinde) maksimum uzunluğu nedir?","options":["48 fit","50 fit","53 fit","57 fit"],"explanation":"Wis. Stat. 348.07(2)(gv), belirlenmiş karayollarında iki araçlı bir kombinasyonda 53 fitlik bir yarı römorka (kingpin-aks mesafesi 43 fiti aşmayan) izin verir ve toplam kombinasyon uzunluk sınırı yoktur."},"9":{"q":"s. 348.07(4) uyarınca belirlenMEMİŞ Wisconsin karayollarında, iki araçlı bir kombinasyonun parçası olarak çalıştırılan bir yarı römork veya römorkun maksimum uzunluğu nedir?","options":["45 fit","48 fit","53 fit","57 fit"],"explanation":"Wis. Stat. 348.07(2)(g), s. 348.07(4) uyarınca belirlenmemiş karayollarında bir yarı römork veya römorku 48 fitle sınırlar; 53 fitlik izin yalnızca belirlenmiş karayollarında geçerlidir."},"10":{"q":"Üreticinin derecelendirmesi daha fazlasına izin vermediğinde, Wisconsin'de bir kamyon çekicisinin direksiyon aksına izin verilen maksimum ağırlık nedir?","options":["11.000 pound","12.000 pound","13.000 pound","15.000 pound"],"explanation":"Wis. Stat. 348.15(3)(b), bir kamyon çekicisinin direksiyon aksını 13.000 poundla sınırlar; ancak üreticinin derecelendirilmiş kapasitesi (lastikler, aks vb.) daha yüksekse, 20.000 pounda kadar çıkabilir."},"11":{"q":"Wisconsin'in iki veya daha fazla ardışık aks grubu için ağırlık sınırları hangi yöntem kullanılarak hesaplanır?","options":["Aralıktan bağımsız olarak sabit 80.000 poundluk bir üst sınır","s. 348.15(3)(g) içindeki federal köprü formülü / ağırlık tablosu","Yalnızca üreticinin GVWR derecelendirmesi","Aks grubu başına sabit 34.000 pound"],"explanation":"Wis. Stat. 348.15(3)(g), ardışık aks grupları için maksimum brüt ağırlıkları, aks aralığına ve aks sayısına dayanan, federal köprü formülünü uygulayan bir tabloya göre belirler."},"12":{"q":"Wisconsin'de, bir Ulaştırma Bakanlığı (Department of Transportation) gabari dışı/aşırı yük (OSOW) izni genellikle ne zaman gereklidir?","options":["Yalnızca 100.000 poundun üzerindeki yükler için","Bir araç veya yük, yasal boyut veya ağırlık sınırlarını aştığında","Yalnızca 10 fitten geniş araçlar için","Yalnızca Eyaletlerarası (Interstate) sistemde seyahat ederken"],"explanation":"Wis. Stat. ch. 348 ve WisDOT izin kurallarına göre, yasal boyut veya ağırlık sınırlarını (genişlik, yükseklik, uzunluk veya ağırlık) aşan bir araç veya yük, çalıştırılmadan önce bir OSOW izni almalıdır."},"13":{"q":"Bir sefer için Wisconsin'in yasal boyutlarını aşan bölünemez bir yük, genellikle hangi izin türüyle yetkilendirilir?","options":["Tek seferlik bir OSOW izni","Bir araç tescil etiketi","Bir CDL onayı (endorsement)","Bir IRP paylaştırılmış plakası"],"explanation":"WisDOT, belirli bir güzergahtaki bölünemez gabari dışı/aşırı yükler için tek seferlik OSOW izinleri (form MV2600) düzenler; çok seferlik ve yıllık izinler ise nitelikli, tekrarlanan hareketleri kapsar."},"14":{"q":"Wisconsin çok seferlik OSOW ağırlık izni kapsamında, bir araç kombinasyonunun daha yüksek brüt ağırlık iznine hak kazanması için en az kaç aksı olmalıdır?","options":["Dört aks","Beş aks","Altı aks","Sekiz aks"],"explanation":"WisDOT çok seferlik ağırlık izinleri, altı veya daha fazla akslı bir kombinasyon gerektirir; sayılan her aks genellikle toplam brüt ağırlığın en az yüzde 8'ini taşır."},"15":{"q":"İşlenmemiş orman ürünlerini daha yüksek ağırlıklarda taşıyan araçlar için Wisconsin OSOW izinleri kapsamında, izin verilen maksimum brüt ağırlık nedir?","options":["80.000 pound","90.000 pound","98.000 pound","120.000 pound"],"explanation":"WisDOT işlenmemiş orman ürünleri (RS) izinleri, altı veya daha fazla akslı bir kombinasyonla, hiçbir tek aks 18.000 poundu aşmayacak şekilde maksimum 98.000 poundluk bir brüt ağırlığa izin verir."},"16":{"q":"İzin olmadan, tarımsal genişlik izni kapsamında Wisconsin karayollarında çoğu tarımsal ticari motorlu taşıt için izin verilen maksimum genişlik nedir?","options":["8 fit 6 inç","9 fit 6 inç","10 fit","12 fit"],"explanation":"Wis. Stat. 348.05(2)(am), belirli tarımsal ticari motorlu taşıtlara izin olmaksızın 10 fite kadar bir genişlik tanır (püskürtücüler gibi belirli ekipmanlar için daha yüksek izinlerle birlikte)."},"17":{"q":"Wisconsin'in 80.000 poundluk yasal brüt ağırlık sınırı Sınıf \"A\" karayolları için geçerlidir. Bu sınır, eyaletteki Eyaletlerarası (Interstate) sistemde nasıl ele alınır?","options":["Eyaletlerarasında hiçbir ağırlık sınırı yoktur","Eyaletlerarasında aynı aks ve köprü formülü sınırları, 80.000 poundluk bir yasal maksimumla kullanılır","Eyaletlerarasında izin olmadan 120.000 pounda izin verilir","Eyaletlerarasında yalnızca 73.280 pounda izin verilir"],"explanation":"Wisconsin, Eyaletlerarası sisteme federal aks ve köprü formülü sınırlarını uygular ve bu da aynı 80.000 poundluk yasal maksimumu doğurur (Wis. Stat. 348.15; 23 U.S.C. 127); dolayısıyla aşırı yüklü yüklerin yine de bir izne ihtiyacı vardır."},"18":{"q":"Sıvı süt ürünlerinin taşınması için bir Wisconsin OSOW izni kapsamında, brüt ağırlık normal maksimumu en fazla ne kadar aşabilir?","options":["10.000 pound","15.000 pound","18.000 pound","25.000 pound"],"explanation":"WisDOT sıvı süt ürünleri (FMP) izinleri, altı veya daha fazla akslı bir kombinasyonda kombinasyonların maksimum brüt ağırlığı en fazla 18.000 pound (98.000 lb'ye kadar) aşmasına izin verir."},"19":{"q":"Wisconsin'de bir tandem aks grubu, yalnızca iki ardışık tandem setinin ilk ve son aksları arasındaki aralık hangi minimum mesafeyi karşıladığında 34.000 pounda yüklenebilir?","options":["28 fit veya daha fazla","30 fit veya daha fazla","36 fit veya daha fazla","40 fit veya daha fazla"],"explanation":"Wis. Stat. 348.15(3)(d), ilk ve son akslar arasındaki mesafe 36 fit veya daha fazla olduğunda, iki ardışık tandem aks setinin her birinin 34.000 pound taşımasına izin verir."},"20":{"q":"Wisconsin'de, 26.000 poundun üzerinde Brüt Kombinasyon Ağırlık Derecesine (GCWR) sahip olan ve GVWR'si 10.000 poundun üzerinde olan çekilen bir birim içeren bir kombinasyon aracını çalıştırmak için hangi CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Wisconsin, Sınıf A CDL'yi, GVWR'si 10.000 poundun üzerinde olan çekilen bir birim dahil olmak üzere, GCWR'si (veya fiili/tescilli ağırlığı) 26.000 poundun üzerinde olan bir kombinasyon aracı olarak tanımlar. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'"},"21":{"q":"Wisconsin kurallarına göre, GVWR'si 26.000 poundun üzerinde olan ve römorku olmayan (veya 10.000 pound ya da daha az olan çekilen bir birime sahip) tek bir ağır düz kamyon hangi CDL sınıfını gerektirir?","options":["Sınıf A","Sınıf B","Sınıf C","Hiçbir CDL gerekli değildir"],"explanation":"Wisconsin, Sınıf B CDL'yi, 10.000 pound ya da daha az bir birim çeken bir araç dahil olmak üzere, GVWR'si (veya fiili/tescilli ağırlığı) 26.000 poundun üzerinde olan ağır düz bir araç olarak tanımlar. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT)."},"22":{"q":"GVWR'si 26.000 pound veya daha az olan küçük bir araç, sürücü dahil 16 veya daha fazla kişi taşımak üzere tasarlanmıştır. Hangi Wisconsin CDL sınıfını gerektirir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"Wisconsin, Sınıf C CDL'yi, 26.000 pound veya daha az olup sürücü dahil 16 veya daha fazla kişi taşımak üzere tasarlanmış bir araç ya da 49 CFR 383.5'te tanımlandığı şekilde tehlikeli maddeleri taşımak için kullanılan herhangi bir boyuttaki araç olarak tanımlar. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT)."},"23":{"q":"Wisconsin CDL amaçları doğrultusunda bir ticari motorlu taşıtın sınıfını belirlerken, hangi değer kullanılmalıdır?","options":["Her zaman yalnızca üreticinin GVWR'si","GVWR, fiili brüt ağırlık veya tescilli ağırlıktan en düşük olanı","GVWR, fiili brüt ağırlık veya tescilli ağırlıktan en yüksek olanı","Aracın boşken donanımlı (curb) ağırlığı"],"explanation":"Wisconsin, sürücülere CMV sınıfını belirlemek için Brüt Araç Ağırlık Derecesi (GVWR), fiili brüt ağırlık veya tescilli ağırlıktan en yüksek olanını kullanmalarını söyler. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'"},"24":{"q":"Plakalama (placarding) gerektiren miktarlarda tehlikeli madde taşıyan ticari bir aracı kullanmak için bir Wisconsin CDL'sinde hangi onay (endorsement) gereklidir?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"49 CFR 383.5 kapsamında tanımlandığı şekilde tehlikeli maddeleri taşımak için 'H' (HazMat) onayı gereklidir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), onaylar bölümü."},"25":{"q":"Hangi Wisconsin CDL onayı, bir sürücünün dökme halde sıvı veya gaz taşımak için kullanılan bir kargo tankıyla donatılmış ticari bir aracı kullanmasına izin verir?","options":["P onayı","T onayı","N onayı","S onayı"],"explanation":"Dökme halde sıvı veya gaz halindeki maddeleri taşımak için bir kargo tankıyla donatılmış ticari araçlar için 'N' (Tank) onayı gereklidir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), onaylar listesi."},"26":{"q":"Wisconsin'in tank araç kuralı kapsamında, derecelendirilmiş kapasitesi 119 galondan fazla olan tek bir kapta sıvı veya gaz taşıyan ve toplam derecelendirilmiş kapasitesi en az ne kadar olan bir araç için tank onayı testi gereklidir?","options":["500 galon veya daha fazla","1.000 galon veya daha fazla","2.500 galon veya daha fazla","3.000 galon veya daha fazla"],"explanation":"Wisconsin, derecelendirilmiş kapasitesi 119 galondan fazla ve toplam derecelendirilmiş kapasitesi 1.000 galon veya daha fazla olan bir kapta sıvı veya gaz taşıyan araçlar için Tank Aracı testini gerektirir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), Section 8 / Tank Vehicle test."},"27":{"q":"Bir Wisconsin CDL sahibinin birden fazla römork (ikili veya üçlü) çekmek için hangi onaya ihtiyacı vardır?","options":["T onayı","N onayı","H onayı","P onayı"],"explanation":"'T' onayı (İkili/Üçlü), bir sürücünün birden fazla römork çeken kombinasyon araçlarını kullanmasına yetki verir ve İkili ve Üçlü bilgi testini geçmeyi gerektirir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT)."},"28":{"q":"Bir Wisconsin ticari aracı, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmıştır. Doğru CDL sınıfına ek olarak hangi onay gereklidir?","options":["S onayı","P onayı","N onayı","T onayı"],"explanation":"Sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış ya da fiilen taşıyan bir aracı kullanmak için 'P' (Yolcu) onayı gereklidir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), onaylar listesi."},"29":{"q":"Wisconsin okul otobüsü 'S' onayı hakkında hangi ifade DOĞRUDUR?","options":["Yalnızca asla sona ermeyen tek seferlik bir bilgi testi gerektirir","Hem ilk düzenlenirken hem de her yenilemede bir bilgi testi ve sürüş becerileri testi gerektirir","'P' onayına sahip olan herkese otomatik olarak verilir","Yalnızca Sınıf A CDL'de mevcuttur"],"explanation":"Wisconsin, okul otobüsü 'S' onayı başvuru sahibinin ilk düzenlendiğinde bilgi ve sürüş becerileri testlerini geçmesini ve her yenilemede yeniden test (bilgi, yol işaretleri, görme, kısaltılmış beceriler) geçmesini gerektirir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), okul otobüsü onayı bölümü."},"30":{"q":"Eyalet içi (Wisconsin içinde) ticari sürüş için geçerli bir Wisconsin CDL'si almak için minimum yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Eyalet içi ticaret için bir Wisconsin CDL'si almak için bir sürücünün en az 18 yaşında olması gerekir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT) / WisDOT CDL gereksinimleri."},"31":{"q":"Wisconsin ve federal kurallar kapsamında, eyaletlerarası ticarette (eyalet sınırları arasında) ticari bir motorlu taşıtı kullanmak için gereken minimum yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Bir sürücünün eyaletlerarası ticarette bir CMV kullanmak, tehlikeli madde taşımak ve eyalet sınırları arasında yolcu taşımak için en az 21 yaşında olması gerekir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT) / WisDOT CDL gereksinimleri."},"32":{"q":"Wisconsin'in Ticari Öğrenici İzni (CLP) kuralları kapsamında, CDL beceri (yol) testine girmenize izin verilmeden önce CLP'yi ne kadar süre elinizde tutmanız gerekir?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"Wisconsin (federal standardı izleyerek), beceri testine girmeden önce bir CLP'yi en az 14 gün elinizde tutmanızı gerektirir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), Ticari Öğrenici İzni bölümü."},"33":{"q":"Bir Wisconsin Ticari Öğrenici İzni (CLP), yenilenmesi gerekmeden önce kaç gün geçerlidir?","options":["90 gün","180 gün","1 yıl","2 yıl"],"explanation":"Bir Wisconsin CLP'si 180 gün geçerlidir ve yenilenebilir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), Ticari Öğrenici İzni bölümü / WisDOT CDL gereksinimleri sayfası."},"34":{"q":"Bir Wisconsin Ticari Öğrenici İzni (CLP) ile araç kullanırken, gözetmen sürücüden ne istenir?","options":["CLP sahibi 21 yaşındaysa gözetmen sürücü gerekmez","İznin sınıfı ve onay düzeyinde veya üzerinde olan geçerli bir CDL sahibi, CLP sahibinin yanında oturmalıdır","16 yaş veya üzeri herhangi bir ehliyetli sürücü arka koltukta seyahat edebilir","Her zaman bir WisDOT sınav görevlisi bulunmalıdır"],"explanation":"Bir CLP sahibine, iznin sınıf/onay düzeyinde veya üzerinde geçerli bir CDL'ye sahip olan ve önde CLP sahibinin yanında oturan bir kişi eşlik etmelidir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), CLP bölümü."},"35":{"q":"Bir Wisconsin HazMat 'H' onayı için başvururken veya yenilerken, başvuru sahibinin HazMat bilgi testini geçmenin ötesinde hangi ek federal gereksinimi karşılaması gerekir?","options":["Plakalı bir araçta ikinci bir yol becerileri testi","Bir FBI adli sicil / tehdit değerlendirmesi kontrolü için parmak izi alınması","Noter tasdikli bir işveren sponsorluk mektubu","Bir uyuşturucu ve alkol takas merkezi (clearinghouse) abonelik ücreti"],"explanation":"Wisconsin, 'H' onayı başvuru sahiplerinin bir FBI adli sicil kayıt kontrolü (TSA güvenlik tehdit değerlendirmesi) için parmak izi vermelerini ve ilk düzenleme ile her yenilemede ABD vatandaşlığı veya yasal statü kanıtı sunmalarını gerektirir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), HazMat 'H' onayı bölümü."},"36":{"q":"Wisconsin HazMat 'H' onayı için, belirli diskalifiye edici suçlardan biri için bir mahkumiyet, mahkumiyet başvuru tarihinden önceki kaç yıl içinde gerçekleşmişse düzenlemeyi engeller?","options":["3 yıl","5 yıl","7 yıl","10 yıl"],"explanation":"Başvuru sahibi, başvuru tarihinden önceki 7 yıl içinde belirli diskalifiye edici suçlardan mahkum edilmişse (veya akıl hastalığı nedeniyle suçsuz bulunmuşsa) bir 'H' onayı almasına, yenilemesine veya devretmesine izin verilmez. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), HazMat diskalifikasyonları."},"37":{"q":"Wisconsin'in bir HazMat 'H' onayı başvuru sahibinden sunmasını özellikle istediği ve diğer çoğu CDL onayı için gerekli OLMAYAN belge veya kanıt hangisidir?","options":["ABD vatandaşlığı veya ABD'de yasal statü kanıtı","Bir lise diploması","Bir ticari araç kiralama sözleşmesi","Bir taşıyıcının USDOT numarası"],"explanation":"Wisconsin, HazMat 'H' başvuru sahiplerinin FBI arka plan kontrolüne ek olarak bilgi testinde, ilk düzenlemede ve tüm yenilemelerde ABD vatandaşlığı veya ABD'de yasal statü kanıtı sunmalarını gerektirir. Kaynak: Wisconsin Commercial Driver's Manual (WisDOT), HazMat 'H' onayı bölümü."},"38":{"q":"Wisconsin'de Başlangıç Düzeyi Sürücü Eğitimi (ELDT) nerede listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır ve ilk kez CDL başvurusunda bulunanlar ile belirli onaylar için gereklidir?","options":["Wisconsin Technical College System kaydı","FMCSA Eğitim Sağlayıcı Kaydı (TPR)","National Safety Council veritabanı","Herhangi bir DMV onaylı üçüncü taraf test edici listesi"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Kaydı'nda (tpr.fmcsa.dot.gov) listelenen bir eğitim sağlayıcısından alınmalıdır. İlk CDL, bir sınıf yükseltmesi (B'den A'ya) ve H, P ve S onayları için gereklidir; CDL'si 7 Şubat 2022'den önce düzenlenen sürücüler muaftır. Kaynak: WisDOT CDL gereksinimleri sayfası / Wisconsin Commercial Driver's Manual."},"39":{"q":"Wisconsin'in CDL tıbbi öz-sertifikasyonunda, aşağıdakilerden hangisi dört geçerli faaliyet sertifikasyon kategorisinden biridir?","options":["Eyaletlerarası İstisnasız (NI)","Federal Hazmat Sertifikalı (FH)","Eyaletlerarası Askıya Alınmış (IS)","Ticari Muaf Çiftlik (CF)"],"explanation":"Wisconsin'in dört CDL öz-sertifikasyon kategorisi şunlardır: Eyaletlerarası İstisnasız (NI), Eyaletlerarası İstisnalı (EI), Eyalet içi İstisnasız (NA) ve Eyalet içi İstisnalı (EA); NI sürücüleri 49 CFR Part 391 tıbbi gereksinimlerini karşılamalı ve geçerli bir Fed Med kartı taşımalıdır. Kaynak: WisDOT MV3230 Commercial Driver Certification: Tier of Operation / Fed Med card sayfası."},"40":{"q":"Wisconsin'de, bir kişinin ticari bir motorlu taşıtı (CMV) yasal olarak kullanabileceği maksimum kan alkol konsantrasyonu (BAC) nedir?","options":["0.04","0.08","0.02","0.00"],"explanation":"Wisconsin, 0.04 veya daha yüksek bir BAC ile bir CMV kullanmayı yasaklar (Wis. Stat. § 346.63(5); Wisconsin CDL Manual). Bir CMV'de 0.04'e ulaşmak, sıradan (ticari olmayan) araçlar için geçerli olan 0.08 sınırının aksine, büyük bir diskalifiye edici suçtur."},"41":{"q":"Wisconsin'de, 0.04 veya daha yüksek bir BAC ile bir CMV kullanmak gibi ilk büyük bir suç için bir CDL ne kadar süreyle diskalifiye edilir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"Wisconsin Genel CDL Diskalifikasyonları tablosu (WisDOT) ve Wis. Stat. § 343.315 uyarınca, büyük bir suç için ilk mahkumiyet CDL'yi 1 yıl süreyle diskalifiye eder. 3 yıllık süre yalnızca sürücü plakalı tehlikeli madde taşırken geçerlidir."},"42":{"q":"Wisconsin kurallarına göre, ilk büyük bir suç (bir CMV'de OWI gibi), hangi koşulda 1 yıl yerine 3 yıllık bir CDL diskalifikasyonu taşır?","options":["Sürücü plakalı tehlikeli madde taşıyordu","Sürücü 65 yaşının üzerindeydi","Kaza maddi hasara neden oldu","Sürücünün yanında iki yolcu vardı"],"explanation":"WisDOT CDL Diskalifikasyonları tablosu ve Wis. Stat. § 343.315, ihlal CMV plakalı tehlikeli madde taşırken gerçekleştiğinde, ilk büyük suç diskalifikasyonunu 1 yıldan 3 yıla çıkarır."},"43":{"q":"Wisconsin'de İKİNCİ bir büyük suç için (örneğin, bir CMV'de ikinci bir OWI) CDL diskalifikasyon süresi nedir?","options":["Ömür boyu","3 yıl","10 yıl","5 yıl"],"explanation":"Herhangi bir büyük diskalifiye edici suç için ikinci bir mahkumiyet, WisDOT CDL Diskalifikasyonları tablosu ve Wis. Stat. § 343.315 (49 CFR 383.51'i yansıtarak) kapsamında ömür boyu CDL diskalifikasyonuyla sonuçlanır."},"44":{"q":"Wisconsin'in Zımni Rıza (Implied Consent) yasası kapsamında, bir CMV sürücüsü, bir kolluk görevlisinin alkol veya uyuşturucu için kimyasal teste tabi tutulma talebini reddederse ne olur?","options":["CDL 1 yıl süreyle diskalifiye edilir (ikinci kez olduğunda ömür boyu)","Diskalifikasyon olmadan bir uyarı verilir","CDL 60 gün süreyle diskalifiye edilir","CDL 6 ay süreyle diskalifiye edilir"],"explanation":"Reddetme büyük bir suç olarak ele alınır: ilk kez için 1 yıllık CDL diskalifikasyonu ve ikinci kez için ömür boyu diskalifikasyon (WisDOT CDL Diskalifikasyonları tablosu; Wis. Stat. §§ 343.305, 343.315)."},"45":{"q":"Wisconsin'in Zımni Rıza (Implied Consent) yasası kapsamında, talep edilen bir kimyasal testi reddetmek, bir sürücünün araç kullanma ayrıcalığını minimum ne kadar süreyle iptal eder?","options":["1 yıl","90 gün","30 gün","6 ay"],"explanation":"Wisconsin CDL Manual, Zımni Rıza yasası (Wis. Stat. § 343.305) kapsamında bir görevli tarafından talep edilen bir testi reddederseniz, araç kullanma ayrıcalığınızın diğer cezalarla birlikte minimum bir yıl süreyle iptal edileceğini belirtir."},"46":{"q":"Wisconsin'de 3 yıllık bir süre içinde kaç ciddi trafik ihlali, 60 günlük bir CDL diskalifikasyonunu tetikler?","options":["2","3","4","5"],"explanation":"3 yıl içinde ayrı olaylarda iki ciddi trafik ihlali, 60 günlük bir CDL diskalifikasyonuyla sonuçlanır (WisDOT CDL Diskalifikasyonları tablosu; Wis. Stat. § 343.315; 49 CFR 383.51)."},"47":{"q":"Wisconsin'de, 3 yıllık bir süre içinde üç ciddi trafik ihlali ne kadar süreyle bir CDL diskalifikasyonuyla sonuçlanır?","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, CDL'yi 120 gün süreyle diskalifiye eder (WisDOT CDL Diskalifikasyonları tablosu; Wis. Stat. § 343.315). 3 yıl içinde iki tanesi 60 gündür."},"48":{"q":"Wisconsin CDL kuralları kapsamında aşağıdakilerden hangisi CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Sınırın 15 mph veya daha fazla üzerinde hız yapmak","Bir park ihlali","0.04 veya daha yüksek bir BAC ile araç kullanmak","Bir kimyasal testi reddetmek"],"explanation":"Sınırın 15 mph veya daha fazla üzerinde hız yapmak ciddi bir trafik ihlalidir (WisDOT CDL Diskalifikasyonları tablosu). 0.04 BAC ve bir test reddi, ciddi ihlaller değil, BÜYÜK suçlardır ve park cezaları sayılmaz."},"49":{"q":"CDL diskalifikasyon amaçları doğrultusunda aşağıdakilerden hangisi Wisconsin'in ciddi trafik ihlalleri listesinde YOKTUR?","options":["0.04 veya daha yüksek bir BAC ile bir CMV kullanmak","Çok yakın takip etmek","Pervasız araç kullanmak","Hatalı veya düzensiz şerit değişimi"],"explanation":"Çok yakın takip etmek, pervasız araç kullanmak ve hatalı/düzensiz şerit değişimleri ciddi trafik ihlalleridir (WisDOT tablosu). 0.04 veya daha yüksek bir BAC ile araç kullanmak, ciddi bir ihlal değil, BÜYÜK bir suçtur (1 yıl / ömür boyu)."},"50":{"q":"1 Temmuz 2016'dan bu yana, Wisconsin'de, bir CMV kullanırken elde tutulan cep telefonu kullanmaktan kaynaklı kaç mahkumiyet, CDL'nin diskalifiye edilmesinden önce gereklidir?","options":["2 veya daha fazla","1","4 veya daha fazla","3 veya daha fazla"],"explanation":"Wisconsin CDL Manual, bir CMV kullanırken elde tutulan cep telefonu kullanımından iki veya daha fazla mahkumiyetten sonra CDL'nin diskalifiye edildiğini belirtir: 3 yıl içindeki ikinci suç için 60 gün ve 3 yıl içinde üç veya daha fazlası için 120 gün."},"51":{"q":"Wisconsin CDL Manual kapsamında, araç kullanırken mesaj yazma nedeniyle bir CMV sürücüsüne uygulanabilecek maksimum hukuki ceza nedir?","options":["$2,750","$2,500","$11,000","$5,000"],"explanation":"Wisconsin CDL Manual, bir CMV kullanırken mesaj yazan bir sürücünün ihlal başına $2,750'ye kadar hukuki cezalara tabi olduğunu belirtir; buna izin veren veya bunu gerektiren taşıyıcılar ise $11,000'a kadar cezalarla karşı karşıya kalır."},"52":{"q":"Wisconsin CDL Manual kapsamında, bir taşıyıcının, sürücülerinin bir CMV kullanırken elde tutulan telefon kullanmasına veya mesaj yazmasına izin vermesi ya da bunu gerektirmesi nedeniyle karşılaşabileceği maksimum hukuki ceza nedir?","options":["$11,000","$2,750","$10,000","$5,500"],"explanation":"Wisconsin CDL Manual, işverenlerin (taşıyıcıların) CMV sürücülerinin elde tutulan telefon kullanmasına veya mesaj yazmasına izin vermek ya da bunu gerektirmek nedeniyle $11,000'a kadar hukuki cezalara tabi olabileceğini belirtir; sürücünün kendi cezası $2,750'ye kadardır."},"53":{"q":"Bir CMV kullanırken 3 yıllık bir süre içinde mesaj yazmaktan iki mahkumiyet, Wisconsin'de hangi CDL diskalifikasyonuyla sonuçlanır?","options":["60 gün","120 gün","30 gün","1 yıl"],"explanation":"Wisconsin CDL Manual, 3 yıl içindeki ikinci mesaj yazma suçunda CDL'nin 60 gün süreyle ve 3 yıl içinde üç veya daha fazla suç için 120 gün süreyle diskalifiye edildiğini belirtir."},"54":{"q":"10 yıl içinde İKİNCİ bir hizmet dışı bırakma emri ihlali için Wisconsin'de CDL diskalifikasyonu nedir (hazmat değil, yolcu değil)?","options":["2 yıl","90 gün","1 yıl","5 yıl"],"explanation":"WisDOT CDL Diskalifikasyonları tablosu uyarınca, 10 yıl içinde ikinci bir hizmet dışı bırakma emri ihlali CDL'yi 2 yıl süreyle diskalifiye eder (hazmat-plakalı veya bir yolcu aracıysa 3 yıl)."},"55":{"q":"Wisconsin'de, bir demiryolu-karayolu hemzemin geçit ihlalinden (raylar boş değilken durmamak gibi) kaynaklı İLK mahkumiyet için CDL diskalifikasyonu nedir?","options":["60 gün","30 gün","120 gün","90 gün"],"explanation":"WisDOT CDL Diskalifikasyonları tablosu, ilk demiryolu-karayolu hemzemin geçit ihlalini 60 günlük bir diskalifikasyon olarak belirler; 3 yıl içinde ikincisi 120 gün ve 3 yıl içinde üçüncüsü 1 yıldır."},"56":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlaline Wisconsin'de hangi CDL diskalifikasyonu uygulanır?","options":["1 yıl","120 gün","60 gün","Ömür boyu"],"explanation":"WisDOT CDL Diskalifikasyonları tablosu uyarınca, demiryolu-karayolu hemzemin geçit ihlalleri 60 gün (ilk), 120 gün (3 yıl içinde ikinci) ve 1 yıl (3 yıl içinde üçüncü) taşır."},"57":{"q":"Wisconsin'de, bir kontrollü maddenin üretilmesi, dağıtılması veya temin edilmesini içeren bir suçun işlenmesinde ticari bir motorlu taşıt kullanmak, hangi CDL diskalifikasyonuyla sonuçlanır?","options":["Ömür boyu, yeniden tesis (reinstatement) olmaksızın","1 yıl","3 yıl","10 yıl"],"explanation":"WisDOT CDL Diskalifikasyonları tablosu ve Wis. Stat. § 343.315 uyarınca, bir CMV kullanılarak işlenen, kontrollü madde içeren bir suç, ilk suç için bile değiştirilemez ömür boyu diskalifikasyonla (yeniden tesis olmaksızın) sonuçlanır."},"58":{"q":"Wisconsin'in 'Şerit Değiştir' (Move Over) yasası kapsamında, yol kenarında durmuş ve yanıp sönen uyarı ışıkları yanan bir çekici aracına, polis aracına veya karayolu bakım aracına yaklaşırken, kendi yönünüzde birden fazla şerit varsa ne yapmanız gerekir?","options":["Güvenli bir şekilde yapılabiliyorsa, durmuş aracın yanındaki şeritten farklı bir şeride geçin","Diğer aracın ışıkları kapanana kadar tamamen durun","'Şerit Değiştir' yasası yalnızca polis araçlarını kapsadığı için belirlenen hızda devam edin","Kornanıza basın ve durmuş aracı geçerken hızınızı koruyun"],"explanation":"Wisconsin'in 'Şerit Değiştir' yasası (Wis. Stat. s. 346.072), yanıp sönen ışıkları yanan acil durum, çekici, kamu hizmeti veya karayolu bakım araçlarına yaklaşan sürücülerin, şerit değişikliği güvenli bir şekilde yapılabiliyorsa, araca en yakın şeridi terk ederek yan şeride geçmesini gerektirir. Wisconsin CDL Kılavuzu (Bölüm 2.8) ve WisDOT, bunun yalnızca polise değil, kolluk kuvvetleri, EMS, itfaiye, çekici ve yol kenarı çalışanları için de geçerli olduğunu belirtir."},"59":{"q":"Wisconsin'in 'Şerit Değiştir' (Move Over) yasası kapsamında, yanıp sönen ışıkları yanan, durmuş bir acil durum veya yol kenarı hizmet aracından güvenli bir şekilde uzağa şerit değiştiremiyorsanız ne yapmanız gerekir?","options":["Aracı güvenli bir şekilde geçene kadar yavaşlayın ve dikkatle ilerleyin","Banketin üzerinde tamamen durun ve aracın gitmesini bekleyin","Şerit değiştirmek imkansız olduğundan belirlenen hız sınırını koruyun","Maksimum açıklık sağlamak için yolun karşı tarafına geçin"],"explanation":"Wis. Stat. s. 346.072 ve Wisconsin CDL Kılavuzu (Bölüm 2.8), şerit değişikliği güvenli değilse (veya kendi yönünüzde yalnızca bir şerit varsa), durmuş aracı güvenli bir şekilde geçene kadar yavaşlamanız ve dikkatle ilerlemeniz gerektiğini belirtir. Durma veya karşı şeridi kullanma zorunluluğu yoktur."},"60":{"q":"Wisconsin'de, yanıp sönen kırmızı uyarı ışıkları yanan ve durmuş bir okul otobüsüne yaklaşan bir araç, otobüsten en az ne kadar mesafede durmalıdır?","options":["Otobüsten 20 feet'ten daha yakın olmamak üzere","Otobüsten 10 feet'ten daha yakın olmamak üzere","Otobüsten 50 feet'ten daha yakın olmamak üzere","Otobüsten 100 feet'ten daha yakın olmamak üzere"],"explanation":"Wisconsin Statute 346.48(1), yanıp sönen kırmızı uyarı ışıkları yanan bir okul otobüsüne önden veya arkadan yaklaşan bir aracın sürücüsünün, otobüsten en az 20 feet mesafede durmasını ve otobüs hareket edene veya kırmızı ışıklar kapanana kadar durmuş halde kalmasını gerektirir."},"61":{"q":"Wisconsin yasalarına göre, yanıp sönen kırmızı uyarı ışıkları yanan bir okul otobüsü için durma zorunluluğundan kim muaftır?","options":["Bölünmüş bir karayolunda karşı yönde ilerleyen sürücüler","Otobüsün 100 feet yakınında aynı yönde ilerleyen sürücüler","Kendi yönünde iki veya daha fazla şeridi olan herhangi bir karayolundaki sürücüler","Kimse muaf değildir; her tür yolda tüm sürücüler durmalıdır"],"explanation":"Wisconsin Statute 346.48(1) tek bir istisna sağlar: durma zorunluluğu, BÖLÜNMÜŞ bir karayolunda KARŞI yönde ilerleyen araçların sürücülerine uygulanmaz. Bölünmemiş yollarda, karşı yönden gelen trafik yine de durmalıdır. Aynı yöndeki trafik her zaman durmalıdır."},"62":{"q":"Wisconsin'de bir okul otobüsü sürücüsü, durulması gereken bir demiryolu-karayolu hemzemin geçidine yaklaşır. Otobüsün ön kısmı, en yakın raya ne kadarlık bir mesafe aralığında tam olarak durmalıdır?","options":["15 feet'ten az ve 50 feet'ten fazla olmamak üzere","5 feet'ten az ve 15 feet'ten fazla olmamak üzere","25 feet'ten az ve 75 feet'ten fazla olmamak üzere","50 feet'ten az ve 100 feet'ten fazla olmamak üzere"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.15 ve 4.3.5), bir otobüsün demiryolu geçidinden önce 15 ile 50 feet arasında durmasını gerektirir - en yakın raya 15 feet'ten daha yakın ve 50 feet'ten daha uzak olmamak üzere - ardından ilerlemeden önce her iki yöne bakıp dinlemesini ister."},"63":{"q":"Wisconsin CDL Kılavuzu'na göre, plaketli (tehlikeli madde işaretli) bir tehlikeli madde aracı, demiryolu geçidinden önce 15 ile 50 feet arasında durmalıdır. Plaketli yüklere ek olarak, aşağıdakilerden hangisi boşken bile durmayı GEREKTİRİR?","options":["Yüklü ya da boş olsun, tehlikeli maddeler için kullanılan bir kargo tankı","Kuru yük taşıyan, 26,000 pound üzeri herhangi bir düz kamyon","Düzgün şekilde sabitlenmiş çelik bobinler taşıyan bir platform (flatbed)","Çabuk bozulan gıda ürünleri taşıyan soğutmalı bir van"],"explanation":"Wisconsin CDL Kılavuzu Bölüm 9.6.12, bir aracın plaketliyse, herhangi bir miktarda klor taşıyorsa VEYA yüklü ya da boş olsun tehlikeli maddeler için kullanılan kargo tankları varsa, en yakın raydan önce 15 ile 50 feet arasında durması gerektiğini belirtir. Sıradan kuru yük veya soğutmalı (reefer) yükler durmayı gerektirmez."},"64":{"q":"Ticari aracınızı bir Wisconsin iki şeritli yolunda veya bölünmemiş karayolunda durdurmanız gerekiyorsa, acil durum uyarı cihazlarınızı kaç dakika içinde yerleştirmeniz gerekir?","options":["10 dakika içinde","2 dakika içinde","15 dakika içinde","30 dakika içinde"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.7), bir yolda veya bankette durmanız gerekiyorsa, durduktan sonra 10 dakika içinde acil durum uyarı cihazlarınızı yerleştirmeniz gerektiğini belirtir."},"65":{"q":"Her iki yönde de trafik taşıyan bir Wisconsin iki şeritli yolunda durduğunuzda, CDL Kılavuzu üç yansıtıcı üçgeninizi nereye yerleştirmenizi söyler?","options":["Aracın 10 feet yakınına, ve 100 feet arkasına ve 100 feet önüne","Yalnızca aracın arkasında 10 feet, 100 feet ve 200 feet'e","Yaklaşan trafiğe doğru 50 feet, 100 feet ve 500 feet'e","Üçünü de aracın arka tamponunun 25 feet yakınına"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.7), iki şeritli/bölünmemiş bir yolda bir üçgeni aracın ön veya arka köşesinin 10 feet yakınına, birini yaklaşık 100 feet arkaya ve birini yaklaşık 100 feet öne, durduğunuz banket veya şerit üzerine yerleştirmenizi yönlendirir."},"66":{"q":"Wisconsin CDL Kılavuzu'na göre, tek yönlü veya bölünmüş bir karayolunda durduğunuzda üç uyarı üçgeni nereye yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e","Aracın her iki tarafında 10 feet, 100 feet ve 100 feet'e","Yaklaşan trafiğe doğru 25 feet, 100 feet ve 300 feet'e","Aracın arkasında 50 feet, 150 feet ve 250 feet'e"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.7), tek yönlü veya bölünmüş bir karayolunda uyarı cihazlarını yaklaşan trafiğe doğru (aracın arkasına) 10 feet, 100 feet ve 200 feet'e yerleştirmeniz gerektiğini belirtir."},"67":{"q":"Wisconsin CDL Kılavuzu, bir tepe, viraj veya engelin yakınında durur ve bu durum diğer sürücülerin aracınızı belirli bir mesafe içinde görmesini engellerse, en arkadaki üçgeni daha geriye taşımanız gerektiğini söyler. Bu görüş mesafesi değeri nedir?","options":["500 feet","200 feet","300 feet","1,000 feet"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.7), bir tepe, viraj veya başka bir engel sürücülerin aracınızı 500 feet içinde görmesini engelliyorsa, yeterli önceden uyarı sağlamak için en arkadaki uyarı üçgenini yol boyunca daha geriye taşımanızı söyler."},"68":{"q":"Eyaletler arası (interstate) sistemin parçası olan kırsal bir Wisconsin otoyolunda (freeway) ticari bir kamyon için maksimum hız sınırı nedir?","options":["Otomobillerle aynı şekilde 70 mil/saat","26,000 pound üzeri tüm kamyonlar için 55 mil/saat","Otomobiller için olan 70 mph sınırından daha düşük, 65 mil/saat","Römork çeken herhangi bir araç için 60 mil/saat"],"explanation":"Wis. Stat. s. 346.57(4) uyarınca, eyaletler arası karayolları da dahil olmak üzere Wisconsin otoyollarındaki sınır 70 mph'dir. Wisconsin, bazı komşu eyaletlerin aksine kamyonlar için ayrı, daha düşük bir hız sınırı belirlemez - bu nedenle kamyonlar, temel güvenli hız kuralına tabi olmak kaydıyla işaretli yerlerde aynı belirlenen 70 mph'de gidebilir."},"69":{"q":"Wisconsin yasaları, ticari kamyonları genel olarak eyaletler arası karayollarında belirli şeritlerle mi sınırlar (örneğin sol şeritten yasaklamak gibi)?","options":["Eyalet çapında kamyon şeridi yasağı yoktur; genel 'geçiş hariç sağda kal' kuralı geçerlidir","Evet, kamyonlar tüm Wisconsin eyaletler arası karayollarında en soldaki şeritten yasaklanmıştır","Evet, kamyonlar üç veya daha fazla şerit olduğunda her zaman sağ şeritte kalmalıdır","Evet, 10,000 pound üzeri kamyonlar eyalet çapında yalnızca sağdaki iki şeridi kullanabilir"],"explanation":"Wisconsin'in kamyonları belirli şeritlerle sınırlayan eyalet çapında bir yasası yoktur. Genel kural (Wis. Stat. s. 346.05), sağda sürüş yapmayı ve sol şeridi esas olarak geçiş için kullanmayı gerektirir. Belirli yerel şerit kısıtlamaları işaretlenebilir, ancak bazı eyaletlerde bulunan türden genel bir eyaletler arası kamyon şeridi yasağı yoktur."},"70":{"q":"Wisconsin CDL Kılavuzu, okul otobüsleri ve demiryolu rayları hakkında eyalete özgü bir not içerir. Hangi ifade bu Wisconsin notunu yansıtır?","options":["Wisconsin'de okul otobüsleri, endüstriyel manevra için kullanılan raylarda durmalıdır","Wisconsin'de okul otobüsleri herhangi bir geçitten 10 mph altında geçebilir","Wisconsin'de okul otobüsleri şehir sınırları içindeki geçitlerde asla durmaz","Wisconsin'de okul otobüsleri yalnızca aktif bariyerli geçitlerde durur"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 4.3.5), Wisconsin'de okul otobüslerinin endüstriyel manevra için kullanılan raylarda durması gerektiğini belirten bir 'Wisconsin Notu' içerir - bu, genel geçit kurallarının ötesinde eyalete özgü bir gerekliliktir."},"71":{"q":"Wisconsin CDL Kılavuzu'na göre, bir otobüs sürücüsünün hangi tür geçitte tam olarak durması GEREKMEZ (ancak yine de yavaşlaması ve trafiği kontrol etmesi gerekir)?","options":["'Muaf' (exempt) veya 'terk edilmiş' (abandoned) olarak işaretlenmiş bir geçit","Çapraz işaret (crossbuck) levhası olan ve bariyeri olmayan bir geçit","Kırsal bir alanda çok raylı bir geçit","Uyarı zillerinin sessiz olduğu bir geçit"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 4.3.5), bir otobüsün durmasının gerekmediği ancak yavaşlayıp kontrol etmesi gereken yerleri listeler: tramvay geçitleri, bir memurun veya işaretçinin trafiği yönlendirdiği yerler, bir trafik sinyalinin yeşil gösterdiği durumlar ve 'muaf' veya 'terk edilmiş' olarak işaretlenmiş geçitler. Bu koşullar olmaksızın düz bir çapraz işaret, bir otobüs için yine de durmayı gerektirir."},"72":{"q":"Wisconsin'de, karayollarında seyahat için aşırı boyut izni (oversize permit) gerekmeden önce yasal maksimum araç genişliği nedir?","options":["8 feet 6 inches (8.5 feet)","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Wisconsin'in yasal maksimum genişliği 8 feet 6 inches'tir (8.5 feet); bundan daha geniş yükler WisDOT'un izin sistemi aracılığıyla bir aşırı boyut izni gerektirir. Standart yasal sınırlar 8.5 ft genişlik, 13.5 ft yükseklik, bir yarı römork için 53 ft uzunluk ve 80,000 lbs brüt ağırlıktır."},"73":{"q":"Wisconsin, iklimine özgü mevsimsel ağırlık kısıtlaması programları işletir. Kış 'donmuş yol bildirimi' (frozen road declaration) neye izin verir?","options":["Yol kaplaması donmuş ve daha sağlamken belirlenmiş yollarda daha ağır yüklere","İlkbahar erimesi bitene kadar tüm ticari kamyonlara tam yasak","Azalan yaz trafiği nedeniyle kamyonlar için daha yüksek hız sınırları","Yalnızca geceleri seyahat eden yükler için tüm izin ücretlerinin muafiyeti"],"explanation":"WisDOT'un mevsimsel ağırlık kısıtlaması programları Wisconsin'in iklimini avantaja çevirir: kış donmuş yol bildirimi (kabaca aralık ortasından mart başına kadar), WisDOT'un Mevsimsel Ağırlık Kısıtlamaları programı uyarınca, donmuş yol kaplaması yapısal olarak daha sağlamken daha ağır yüklere izin verir."},"74":{"q":"Wisconsin'in ilkbahar erimesi (spring thaw) sırasında, Sınıf II (Class II) karayolu ve mevsimsel işaretli yol programları kamyon ağırlıklarına ne yapar?","options":["Erimeyle zayıflayan yol kaplamasını korumak için izin verilen aks ağırlıklarını azaltır","Eriyen kar yolları temizlediği için izin verilen ağırlıkları artırır","Ağırlık üzerinde etkisi yoktur; yalnızca belirlenen hız sınırlarını değiştirir","Yalnızca binek otomobillere ve eğlence araçlarına uygulanır, kamyonlara değil"],"explanation":"WisDOT'un ilkbahar erimesi programları (Sınıf II yolları ve mevsimsel işaretli yollar, kabaca marttan mayısa kadar), eriyen yol kaplaması yapısal olarak zayıf olduğundan izin verilen aks ve brüt ağırlıkları azaltır ve birçok bölünebilir yük iznini askıya alır. Amaç, WisDOT'un Mevsimsel Ağırlık Kısıtlamaları programı uyarınca karayolu ömrünü uzatmaktır."},"75":{"q":"Wisconsin'de, bir aşırı boyutlu yük tek bir ön refakat (escort) gerektirecek kadar geniş olduğunda, hangi tür araç refakatçi olarak hizmet verebilir?","options":["Gerekli uyarı lambaları bulunan, 16,000 pound'u aşmayan bir otomobil veya tek üniteli kamyon","Bayrak ve amber ışıkla donatılmış herhangi bir motosiklet","Yükün hemen önünde seyahat eden ikinci bir yüklü yarı römork","Her durumda yalnızca işaretli bir kolluk kuvveti polis aracı"],"explanation":"Wisconsin aşırı boyut izni kuralları (WisDOT/Trans kodu) uyarınca, bir refakat (pilot) aracı, 16,000 pound'dan fazla olmayan, engelsiz görüşe sahip, kısa hüzmeli farları açık ve izinli yüke refakat ederken uyarı lambaları yanan bir otomobil veya tek üniteli kamyon olmalıdır."},"76":{"q":"Bir Wisconsin iki şeritli yolunda, geçişi kontrol etmek için bir demiryolu geçidine tipik olarak hangi ek yol kaplaması işareti eşlik eder?","options":["Raylara yaklaşırken bir geçiş yasağı bölgesi işareti (ve bir geçiş yasağı levhası)","Raylardan önce geçişi teşvik eden kesik sarı bir orta çizgi","Kamyonların geçidi paylaşmasına izin veren düz beyaz bir şerit çizgisi","Kamyonları geçidin en sağına yönlendiren bir bisiklet şeridi çizgisi"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.15), iki şeritli yollarda demiryolu kaplama işaretlerinin 'RR' harfleriyle birlikte bir 'X' ve bir geçiş yasağı işareti içerdiğini, ayrıca geçide yaklaşırken bir geçiş yasağı bölgesi levhası bulunduğunu belirtir. Varsa beyaz bir stop çizgisi, otobüsün ön kısmının durduğunda kalması gereken yerdir."},"77":{"q":"Bir Wisconsin CDL sürücüsü, bir arıza sonrası yoğun bölünmüş bir otoyolun banketinde durur. Yaklaşan trafiğe doğru 10, 100 ve 200 feet'e üç üçgeni yerleştirdikten sonra, Wisconsin CDL Kılavuzu üçgenleri tutma konusunda ne tavsiye eder?","options":["Diğer sürücülerin sizi görebilmesi için her üçgeni kendinizle gelen trafik arasında tutun","Üçgenleri başınızın üzerinde tutun ve seyahat şeridinin ortasında yürüyün","Aracı tamamen terk etmemek için üçgenleri kabinden atın","Üçünü de trafik akışından uzağa bakacak şekilde sol tarafa yerleştirin"],"explanation":"Wisconsin CDL Kılavuzu (Bölüm 2.7), üçgenleri yerleştirirken kendi güvenliğiniz için onları kendinizle gelen trafik arasında tutmanızı tavsiye eder; böylece yaklaşan sürücüler cihazları yerleştirirken sizi görebilir."},"78":{"q":"Wisconsin'de Ticari Sürücü Belgelerini (CDL) hangi eyalet kurumu düzenler?","options":["WisDOT'un bir parçası olan Wisconsin Motorlu Taşıtlar Dairesi (DMV)","Wisconsin Eyalet Devriyesi (State Patrol)","Wisconsin Kamu Güvenliği Departmanı","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)"],"explanation":"Wisconsin CDL'leri, Wisconsin Ulaştırma Departmanı'nın bir bölümü olan Wisconsin Motorlu Taşıtlar Dairesi (DMV) tarafından düzenlenir. Eyalet Devriyesi motorlu taşıyıcı yasalarını uygular ancak belge düzenlemez ve FMCSA, eyalet CDL'leri düzenlemek yerine standartlar belirleyen bir federal kurumdur. Kaynak: Wisconsin Commercial Driver's Manual; wisconsindot.gov CDL Gereksinimleri sayfası."},"79":{"q":"50 soru içeren Wisconsin CDL Genel Bilgi (General Knowledge) testini geçmek için gereken minimum doğru cevap sayısı kaçtır?","options":["40 doğru (%80)","30 doğru (%60)","35 doğru (%70)","45 doğru (%90)"],"explanation":"Wisconsin Genel Bilgi testi 50 soru içerir ve en az 40'ını doğru cevaplamanız gerekir; bu %80'lik bir geçer not demektir. %80 standardı, Wisconsin'deki CDL bilgi testleri için geçerlidir. Kaynak: Wisconsin Commercial Driver's Manual; wisconsindot.gov CDL Gereksinimleri."},"80":{"q":"Bir Wisconsin Ticari Öğrenme İzni (CLP) ne kadar süre geçerlidir?","options":["180 gün","90 gün","1 yıl","60 gün"],"explanation":"Bir Wisconsin CLP'si 180 gün geçerlidir ve sahibinin nitelik kazandığı araç türlerini ve onayları (endorsement) listeler. Kaynak: Wisconsin Commercial Driver's Manual, Ticari Öğrenme İzni (CLP) bölümü."},"81":{"q":"Bir Wisconsin CLP sahibinin, CDL beceri (skills) testine girmesine izin verilmeden önce izin verildikten sonra ne kadar beklemesi gerekir?","options":["14 gün","10 gün","30 gün","7 gün"],"explanation":"Wisconsin tarafından benimsenen federal kurallar uyarınca, bir beceri testine girmenize izin verilmeden önce CLP'yi en az 14 gün elinizde bulundurmanız gerekir. Kaynak: Wisconsin Commercial Driver's Manual, Beceri testi bölümü; 49 CFR 383.25."},"82":{"q":"Wisconsin CDL beceri testinin, belirli bir sırayla yapılması gereken üç bölümü vardır. Doğru sıra nedir?","options":["Araç muayenesi, temel araç kontrolü, yolda sürüş","Yolda sürüş, araç muayenesi, temel araç kontrolü","Temel araç kontrolü, yolda sürüş, araç muayenesi","Araç muayenesi, yolda sürüş, temel araç kontrolü"],"explanation":"Wisconsin'in üç bölümlü beceri testi şu sırayla yapılmalıdır: önce araç muayenesi, ardından temel araç kontrolü, sonra yolda sürüş. Kaynak: Wisconsin Commercial Driver's Manual, Beceri testleri bölümü."},"83":{"q":"Wisconsin'de yeni bir başvuru sahibi CDL testine girmeye hak kazanmadan önce hangi eğitimi tamamlaması gerekir?","options":["FMCSA'ya kayıtlı bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","İlçe tarafından onaylanmış bir defansif sürüş kursu","Lisanslı bir taşıyıcı altında iki yıllık bir çıraklık","Bir OSHA işyeri güvenliği sertifikası"],"explanation":"Yeni CDL başvuru sahipleri (ve sınıf yükseltenler veya belirli onayları ekleyenler), test öncesinde FMCSA Eğitim Sağlayıcı Kütüğü'nde (Training Provider Registry) listelenen bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi'ni tamamlamalıdır. Kaynak: Wisconsin Commercial Driver's Manual; 49 CFR Part 380 Subpart F."},"84":{"q":"Wisconsin CDL başvuru sahipleri ticari operasyon kademelerini (tier) kendi beyanlarıyla onaylamak için hangi belgeyi kullanır?","options":["Form MV3230, Ticari Sürücü Sertifikasyonu: Operasyon Kademesi","Form MV3001, genel sürücü belgesi başvurusu","Form MV3740, okul otobüsü öz beyanı","FMCSA Tıbbi Muayene Raporu (MCSA-5875)"],"explanation":"Wisconsin sürücüleri operasyon kademelerini Form MV3230 üzerinde kendi beyanlarıyla onaylar. MV3001 genel belge başvurusudur, MV3740 bir okul otobüsü öz beyanıdır ve MCSA-5875, bir muayene uzmanı tarafından tamamlanan tıbbi muayene raporudur. Kaynak: wisconsindot.gov Fed Med card sayfası; Form MV3230."},"85":{"q":"Bir Wisconsin CDL sahibinin arasından seçim yapması gereken kaç öz beyan kategorisi (operasyon kademesi) vardır?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz beyan kademesi vardır: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate ve Excepted Intrastate. Kaynak: wisconsindot.gov Fed Med card sayfası; 49 CFR 383.71."},"86":{"q":"Hangi Wisconsin öz beyan kademesi, sürücünün geçerli bir Federal tıbbi muayene uzmanı sertifikası (Fed Med card) bulundurmasını GEREKTİRİR?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Eyalet sınırlarını hiç geçmeyen herhangi bir sürücü"],"explanation":"Non-Excepted Interstate (NI) sürücüleri geçerli bir Fed Med card bulundurmalıdır. Excepted Interstate ve Excepted Intrastate kademeleri bir tane gerektirmez. Kaynak: wisconsindot.gov Fed Med card sayfası; 49 CFR 383.71."},"87":{"q":"2025 süreç değişikliği itibarıyla, bir DOT fizik muayenesinden sonra bir Wisconsin sürücüsünün Federal tıbbi muayene uzmanı sertifikası bilgileri normalde WI DMV'ye nasıl ulaşır?","options":["FMCSA, muayeneden sonra yaklaşık 48 saat içinde bunu WI DMV'ye elektronik olarak iletir","Sürücü her zaman 10 gün içinde DMV'ye bir kağıt kopyasını fakslamalıdır","Kamyon taşımacılığı işvereni, sürücü adına bunu DMV'ye postalar","CDL üzerine basılır ve asla eyalete bildirilmez"],"explanation":"13 Nisan 2025'ten itibaren, FMCSA sürücünün Fed Med card bilgilerini genellikle DOT fizik muayenesinden sonra 48 saat içinde otomatik olarak WI DMV'ye sağlar. Bu tarihten önce tamamlanan muayenelerin sürücü tarafından sunulması gerekiyordu. Kaynak: wisconsindot.gov Fed Med card sayfası."},"88":{"q":"Bir Wisconsin CDL'si ne sıklıkla yenilenmelidir?","options":["Her 8 yılda bir","Her 4 yılda bir","Her 6 yılda bir","Her 2 yılda bir"],"explanation":"Bir Wisconsin CDL'si her 8 yılda bir yenilenmelidir. Kaynak: Wisconsin Commercial Driver's Manual; wisconsindot.gov yenileme bilgileri."},"89":{"q":"Eyalet içi (Wisconsin içinde) ticari sürüş için bir Wisconsin CDL'si almak için minimum yaş kaçtır?","options":["18 yaşında","21 yaşında","19 yaşında","16 yaşında"],"explanation":"Eyalet içi operasyon için bir Wisconsin CDL/CLP almak için en az 18 yaşında olmanız gerekir. Eyaletler arası ticaret genellikle en az 21 yaşında olmayı gerektirir. Kaynak: Wisconsin Commercial Driver's Manual, Ticari Öğrenme İzni (CLP) bölümü."},"90":{"q":"Wisconsin'de bir CLP sahibi hangi koşulda eyaletler arası ticarette ticari bir araç kullanabilir?","options":["Yalnızca en az 21 yaşındaysa ve geçerli bir federal tıbbi sertifikaya sahipse","Herhangi bir yaşta, çünkü bir CLP tam eyaletler arası yetki verir","Yalnızca CLP'yi 180 gün elinde bulundurduktan sonra","Yalnızca bir okul otobüsü onayıyla"],"explanation":"Bir CLP sahibi, en az 21 yaşında değilse ve geçerli bir Fed Med card bulundurmuyorsa eyaletler arası ticarette araç kullanamaz. Kaynak: Wisconsin Commercial Driver's Manual, CLP bölümü."},"91":{"q":"Beceri testinde, bir Wisconsin başvuru sahibinin üç bölümün kaçını aynı CLP üzerinde geçmesi gerekir?","options":["Üç bölümün tamamı aynı CLP üzerinde geçilmelidir","Yalnızca yolda sürüş bölümünün aynı CLP üzerinde olması gerekir","Üçünden herhangi ikisi yeni bir CLP'ye taşınabilir","Bölümler en fazla üç farklı CLP'ye yayılabilir"],"explanation":"Wisconsin, beceri testinin üç bölümünün tamamının aynı CLP üzerinde geçilmesini gerektirir. Kaynak: Wisconsin Commercial Driver's Manual, Beceri testi bölümü."},"92":{"q":"Aranan sınıf veya onaylardan bağımsız olarak HER Wisconsin CDL başvuru sahibinin geçmesi gereken test hangisidir?","options":["Genel Bilgi (General Knowledge) testi","Hava Frenleri (Air Brakes) testi","Kombinasyon Araçları (Combination Vehicles) testi","Tehlikeli Maddeler (Hazardous Materials) testi"],"explanation":"Genel Bilgi testi tüm CDL başvuru sahipleri tarafından alınır; diğer bilgi testleri (hava frenleri, kombinasyon, hazmat vb.) yalnızca belirli sınıflar veya onaylar için gereklidir. Kaynak: Wisconsin Commercial Driver's Manual, Bilgi testleri bölümü."},"93":{"q":"Genel Bilgi testine ek olarak, bir Wisconsin CLP/CDL için başvururken hangi İKİ belge/kanıt gereklidir?","options":["Geçerli bir Wisconsin sürücü belgesi ve vatandaşlık veya yasal statü kanıtı","Bir pasaport ve noter onaylı bir işveren mektubu","Bir Sosyal Güvenlik kartı ve bir araç ruhsatı","Bir lise diploması ve iki referans mektubu"],"explanation":"Wisconsin başvuru sahipleri geçerli bir Wisconsin sürücü belgesine sahip olmalı ve başvuru (MV3001) ile kademe öz beyanı (MV3230) ile birlikte ABD vatandaşlığı veya yasal mevcudiyet kanıtı sağlamalıdır. Kaynak: wisconsindot.gov CDL Gereksinimleri; Wisconsin Commercial Driver's Manual."},"94":{"q":"Fed Med card'ının süresinin dolmasına izin veren ve Wisconsin'de dosyasında geçerli bir tıbbi sertifikası bulunmayan bir CDL sahibi hangi tür operasyonla sınırlandırılır?","options":["Yalnızca eyalet içi operasyon (Wisconsin içinde)","Yalnızca eyaletler arası operasyon","Yalnızca boş araçların kullanımı","Hiçbir ticari aracın kullanımına izin verilmez"],"explanation":"Geçerli bir federal tıbbi kartı olmayan bir sürücü, eyalet içi (eyalet içinde) operasyonla veya eyalet içi muaf operasyonla sınırlandırılır ve eyaletler arası yetkisini kaybeder. Kaynak: Wisconsin Commercial Driver's Manual, CLP/tıbbi bölümü."},"95":{"q":"Wisconsin DMV muayene uzmanlarının yanı sıra, Wisconsin CDL beceri testlerini uygulamaya başka kim yetkilidir?","options":["DMV tarafından yetkilendirilmiş üçüncü taraf muayene uzmanları","Başvuru sahibi tarafından seçilen herhangi bir lisanslı CDL sürücüsü","FMCSA saha müfettişleri","İlçe şerif yardımcıları"],"explanation":"Wisconsin DMV, CDL beceri testlerini uygulamak için onaylı üçüncü taraf muayene uzmanlarını yetkilendirir; başvuru sahipleri randevu almak için yetkili bir üçüncü taraf muayene uzmanıyla iletişime geçer. Kaynak: Wisconsin Commercial Driver's Manual, beceri testi bölümü."},"96":{"q":"Wisconsin beceri testinin araç muayenesi bölümünde, başvuru sahibinin ne yapması gerekir?","options":["Aracı muayene etmek ve muayene uzmanına neyin neden kontrol edildiğini açıklamak","Muayene uzmanının aracı muayene etmesini izlemek ve bir kontrol listesini imzalamak","Önceki haftadan bir tamircinin yazılı muayene raporunu sunmak","Aracı yolda kullanırken gösterge panelindeki göstergeleri anlatmak"],"explanation":"Araç muayenesi testinde, başvuru sahibi muayeneyi gerçekleştirir ve muayene uzmanına neyin neden inceleneceğini açıklayarak aracın sürmek için güvenli olduğu bilgisini gösterir. Kaynak: Wisconsin Commercial Driver's Manual, Bölüm 2.1 ve Bölüm 11M."},"97":{"q":"Bir Fed Med card düzenleyen tıbbi muayene uzmanı ile FMCSA Ulusal Kütüğü (National Registry) arasındaki ilişki nedir?","options":["Muayene, FMCSA Sertifikalı Tıbbi Muayene Uzmanları Ulusal Kütüğü'nde listelenen bir tıbbi muayene uzmanı tarafından yapılmalıdır","Herhangi bir lisanslı hekim, kayıt olmaksızın kartı düzenleyebilir","Muayeneyi yalnızca Wisconsin DMV kadrolu hekimleri yapabilir","Kart, postayla gönderilen bir anketten sonra doğrudan FMCSA tarafından düzenlenir"],"explanation":"DOT fizik muayenesi, FMCSA Sertifikalı Tıbbi Muayene Uzmanları Ulusal Kütüğü'nde listelenen ve FMCSA Tıbbi Muayene Raporu'nu tamamlayıp Tıbbi Muayene Uzmanı Sertifikası'nı düzenleyen bir tıbbi muayene uzmanı tarafından yapılmalıdır. Kaynak: wisconsindot.gov Fed Med card sayfası; 49 CFR 390.103."}},"es":{"0":{"q":"Sin un permiso especial, ¿cuál es el ancho total máximo de un vehículo y su carga en una carretera de Wisconsin?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El estatuto Wis. Stat. 348.05(1) prohíbe operar un vehículo con un ancho total superior a 8 pies 6 pulgadas (102 inches) sin un permiso. Esto coincide con el estándar federal adoptado por Wisconsin."},"1":{"q":"Sin un permiso, ¿cuál es la altura legal máxima de un vehículo (incluida la carga) en una carretera de Wisconsin?","options":["13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas","14 pies 6 pulgadas"],"explanation":"El estatuto Wis. Stat. 348.06(1) establece la altura total máxima en 13 pies 6 pulgadas (13 1/2 pies) sin un permiso. Los conductores siguen siendo responsables del espacio libre real por encima del vehículo, independientemente de este límite."},"2":{"q":"¿Cuál es el peso bruto máximo que se impone en una carretera de Wisconsin para cualquier eje individual sin un permiso?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"Conforme al estatuto Wis. Stat. 348.15(3)(b), el peso bruto sobre cualquier eje individual no puede exceder las 20,000 libras. Esto es igual al límite federal para eje individual."},"3":{"q":"Sin un permiso, ¿cuál es el peso bruto máximo permitido en un grupo de ejes en tándem en una carretera Clase \"A\" de Wisconsin?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"El estatuto Wis. Stat. 348.15(3)(d) permite que un grupo de ejes en tándem (dos conjuntos consecutivos) lleve hasta 34,000 libras, en consonancia con el límite federal para ejes en tándem."},"4":{"q":"En una carretera Clase \"A\" de Wisconsin, ¿cuál es el peso bruto vehicular legal máximo para una combinación de cinco ejes con el espaciado adecuado que opera sin un permiso?","options":["73,280 libras","76,000 libras","80,000 libras","84,000 libras"],"explanation":"La tabla de pesos por grupo de ejes del estatuto Wis. Stat. 348.15(3)(g), que aplica la fórmula federal de puentes (bridge formula), limita el peso bruto legal a 80,000 libras. WisDOT publica 80,000 lb como el límite legal."},"5":{"q":"¿Cuál es el peso bruto máximo que Wisconsin permite sobre cualquier rueda, o ruedas, que sostienen un extremo de un eje, sin un permiso?","options":["9,000 libras","10,000 libras","11,000 libras","13,000 libras"],"explanation":"El estatuto Wis. Stat. 348.15(3)(a) limita el peso bruto sobre cualquier rueda o ruedas que sostienen un extremo de un eje a 11,000 libras."},"6":{"q":"Sin un permiso, ¿cuál es la longitud total máxima de un vehículo individual en una carretera de Wisconsin?","options":["40 pies","45 pies","48 pies","53 pies"],"explanation":"El estatuto Wis. Stat. 348.07(1) limita un vehículo individual a una longitud total de 45 pies sin un permiso (los implementos agrícolas tienen una asignación mayor por separado)."},"7":{"q":"Sin un permiso, ¿cuál es la longitud total máxima de una combinación de dos vehículos y carga en una carretera de Wisconsin (donde aplica un límite de longitud total)?","options":["65 pies","70 pies","75 pies","80 pies"],"explanation":"El estatuto Wis. Stat. 348.07(1) establece el límite general de longitud total para una combinación de dos vehículos en 70 pies, aunque ciertas combinaciones de tractor y semirremolque en carreteras designadas no tienen límite de longitud total."},"8":{"q":"En una carretera de Wisconsin designada bajo la sección 348.07(4), ¿cuál es la longitud máxima de un semirremolque individual operado en una combinación de dos vehículos (con la distancia del pivote de enganche al eje dentro de los límites)?","options":["48 pies","50 pies","53 pies","57 pies"],"explanation":"El estatuto Wis. Stat. 348.07(2)(gv) permite un semirremolque de 53 pies (con distancia del pivote de enganche al eje no superior a 43 pies) en una combinación de dos vehículos en carreteras designadas, sin límite de longitud total de la combinación."},"9":{"q":"En las carreteras de Wisconsin NO designadas bajo la sección 348.07(4), ¿cuál es la longitud máxima de un semirremolque o remolque operado como parte de una combinación de dos vehículos?","options":["45 pies","48 pies","53 pies","57 pies"],"explanation":"El estatuto Wis. Stat. 348.07(2)(g) limita un semirremolque o remolque a 48 pies en carreteras no designadas bajo la sección 348.07(4); la asignación de 53 pies aplica únicamente en carreteras designadas."},"10":{"q":"¿Cuál es el peso máximo permitido sobre el eje de dirección de un tractocamión en Wisconsin cuando la clasificación del fabricante no autoriza más?","options":["11,000 libras","12,000 libras","13,000 libras","15,000 libras"],"explanation":"El estatuto Wis. Stat. 348.15(3)(b) limita el eje de dirección de un tractocamión a 13,000 libras, a menos que la capacidad nominal del fabricante (neumáticos, eje, etc.) sea mayor, hasta 20,000 libras."},"11":{"q":"Los límites de peso de Wisconsin para grupos de dos o más ejes consecutivos se calculan utilizando ¿cuál método?","options":["Un tope fijo de 80,000 libras independientemente del espaciado","La fórmula federal de puentes (bridge formula) / tabla de pesos de la sección 348.15(3)(g)","Únicamente la clasificación GVWR del fabricante","Un valor fijo de 34,000 libras por grupo de ejes"],"explanation":"El estatuto Wis. Stat. 348.15(3)(g) establece los pesos brutos máximos para grupos de ejes consecutivos según una tabla que aplica la fórmula federal de puentes (bridge formula), basada en el espaciado de los ejes y el número de ejes."},"12":{"q":"En Wisconsin, ¿cuándo se requiere generalmente un permiso del Departamento de Transporte para cargas con sobredimensión/sobrepeso (OSOW)?","options":["Solo para cargas de más de 100,000 libras","Cuando un vehículo o carga excede los límites legales de tamaño o peso","Solo para vehículos de más de 10 pies de ancho","Solo al circular por el sistema de autopistas interestatales"],"explanation":"Conforme al capítulo Wis. Stat. ch. 348 y las normas de permisos de WisDOT, un vehículo o carga que excede los límites legales de tamaño o peso (ancho, altura, longitud o peso) debe obtener un permiso OSOW antes de operar."},"13":{"q":"Una carga indivisible que excede las dimensiones legales de Wisconsin para un solo viaje normalmente se autoriza mediante ¿qué tipo de permiso?","options":["Un permiso OSOW de viaje único","Una calcomanía de registro vehicular","Un endoso de la CDL","Una placa prorrateada del IRP"],"explanation":"WisDOT emite permisos OSOW de viaje único (formulario MV2600) para cargas indivisibles con sobredimensión/sobrepeso en una ruta especificada; los permisos de viajes múltiples y anuales cubren movimientos repetidos que cumplen los requisitos."},"14":{"q":"Bajo un permiso de peso OSOW de viajes múltiples de Wisconsin, una combinación de vehículos debe tener al menos cuántos ejes para calificar para la asignación de peso bruto más alta?","options":["Cuatro ejes","Cinco ejes","Seis ejes","Ocho ejes"],"explanation":"Los permisos de peso de viajes múltiples de WisDOT requieren una combinación de seis o más ejes, en la que cada eje contado generalmente lleve al menos el 8 por ciento del peso bruto total."},"15":{"q":"Bajo los permisos OSOW de Wisconsin para vehículos que transportan productos forestales en bruto a pesos más altos, ¿cuál es el peso bruto máximo permitido?","options":["80,000 libras","90,000 libras","98,000 libras","120,000 libras"],"explanation":"Los permisos de WisDOT para productos forestales en bruto (RS) permiten un peso bruto máximo de 98,000 libras con una combinación de seis o más ejes, sin que ningún eje individual exceda las 18,000 libras."},"16":{"q":"Sin un permiso, ¿cuál es el ancho máximo permitido para la mayoría de los vehículos comerciales agrícolas en las carreteras de Wisconsin bajo la asignación de ancho agrícola?","options":["8 pies 6 pulgadas","9 pies 6 pulgadas","10 pies","12 pies"],"explanation":"El estatuto Wis. Stat. 348.05(2)(am) permite a ciertos vehículos comerciales agrícolas un ancho de hasta 10 pies sin un permiso (con asignaciones mayores para equipos específicos como las fumigadoras)."},"17":{"q":"El límite legal de peso bruto de 80,000 libras de Wisconsin aplica a las carreteras Clase \"A\". ¿Cómo se trata el límite en el sistema de autopistas interestatales dentro del estado?","options":["Las interestatales no tienen ningún límite de peso","Las interestatales usan los mismos límites de ejes y de la fórmula de puentes, con un máximo legal de 80,000 libras","Las interestatales permiten 120,000 libras sin un permiso","Las interestatales solo permiten 73,280 libras"],"explanation":"Wisconsin aplica los límites federales de ejes y de la fórmula de puentes al sistema de autopistas interestatales, lo que resulta en el mismo máximo legal de 80,000 libras (Wis. Stat. 348.15; 23 U.S.C. 127), de modo que las cargas con sobrepeso siguen necesitando un permiso."},"18":{"q":"Bajo un permiso OSOW de Wisconsin para el transporte de productos lácteos líquidos, el peso bruto puede exceder el máximo normal por no más de ¿cuánto?","options":["10,000 libras","15,000 libras","18,000 libras","25,000 libras"],"explanation":"Los permisos de WisDOT para productos lácteos líquidos (FMP) permiten que las combinaciones excedan el peso bruto máximo por no más de 18,000 libras (hasta 98,000 lb) en una combinación de seis o más ejes."},"19":{"q":"Un grupo de ejes en tándem en Wisconsin puede cargarse hasta 34,000 libras solo si el espaciado entre el primer y el último eje de dos conjuntos de tándem consecutivos cumple ¿qué distancia mínima?","options":["28 pies o más","30 pies o más","36 pies o más","40 pies o más"],"explanation":"El estatuto Wis. Stat. 348.15(3)(d) permite que cada uno de dos conjuntos de ejes en tándem consecutivos lleve 34,000 libras cuando la distancia entre el primer y el último eje es de 36 pies o más."},"20":{"q":"En Wisconsin, ¿qué clase de CDL se requiere para operar un vehículo combinado con una Clasificación de Peso Bruto Combinado (GCWR) superior a 26,000 libras que incluye una unidad remolcada con un GVWR superior a 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Wisconsin define una CDL Clase A como un vehículo combinado con un GCWR (o peso real/registrado) superior a 26,000 libras, que incluye una unidad remolcada con un GVWR superior a 10,000 libras. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), '¿Qué CDL necesito?'"},"21":{"q":"Bajo las normas de Wisconsin, un solo camión rígido pesado con un GVWR superior a 26,000 libras y sin remolque (o con una unidad remolcada de 10,000 libras o menos) requiere ¿qué clase de CDL?","options":["Clase A","Clase B","Clase C","No se requiere CDL"],"explanation":"Wisconsin define una CDL Clase B como un vehículo rígido pesado con un GVWR (o peso real/registrado) superior a 26,000 libras, incluido un vehículo de ese tipo que remolca una unidad de 10,000 libras o menos. Fuente: Wisconsin Commercial Driver's Manual (WisDOT)."},"22":{"q":"Un vehículo pequeño con un GVWR de 26,000 libras o menos está diseñado para transportar 16 o más personas, incluido el conductor. ¿Qué clase de CDL de Wisconsin requiere?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Wisconsin define una CDL Clase C como un vehículo de 26,000 libras o menos que está diseñado para transportar 16 o más personas (incluido el conductor), o de cualquier tamaño usado para transportar materiales peligrosos según se define en 49 CFR 383.5. Fuente: Wisconsin Commercial Driver's Manual (WisDOT)."},"23":{"q":"Al determinar la clase de un vehículo comercial motorizado para fines de la CDL de Wisconsin, ¿qué valor debe utilizarse?","options":["Siempre únicamente el GVWR del fabricante","El menor entre el GVWR, el peso bruto real o el peso registrado","El mayor entre el GVWR, el peso bruto real o el peso registrado","El peso en vacío del vehículo cuando está descargado"],"explanation":"Wisconsin instruye a los conductores a usar el mayor entre la Clasificación de Peso Bruto Vehicular (GVWR), el peso bruto real o el peso registrado para determinar la clase del CMV. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), '¿Qué CDL necesito?'"},"24":{"q":"¿Qué endoso se requiere en una CDL de Wisconsin para conducir un vehículo comercial que transporta materiales peligrosos en cantidades que requieren rótulos (placarding)?","options":["Endoso N","Endoso H","Endoso T","Endoso X"],"explanation":"El endoso 'H' (HazMat) se requiere para transportar materiales peligrosos según se define en 49 CFR 383.5. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección de endosos."},"25":{"q":"¿Qué endoso de la CDL de Wisconsin permite a un conductor operar un vehículo comercial equipado con un tanque de carga usado para transportar líquidos o gases a granel?","options":["Endoso P","Endoso T","Endoso N","Endoso S"],"explanation":"El endoso 'N' (Tanque) se requiere para vehículos comerciales equipados con un tanque de carga para transportar materiales líquidos o gaseosos a granel. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), lista de endosos."},"26":{"q":"Bajo la norma de vehículos cisterna de Wisconsin, el examen del endoso de tanque se requiere para un vehículo que transporta un líquido o gas en un recipiente individual con una capacidad nominal de más de 119 galones y una capacidad nominal agregada de al menos ¿cuánto?","options":["500 galones o más","1,000 galones o más","2,500 galones o más","3,000 galones o más"],"explanation":"Wisconsin requiere el examen de Vehículo Cisterna para vehículos que transportan líquidos o gases en un recipiente con una capacidad nominal de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), Sección 8 / examen de Vehículo Cisterna."},"27":{"q":"¿Qué endoso necesita un titular de una CDL de Wisconsin para arrastrar más de un remolque (dobles o triples)?","options":["Endoso T","Endoso N","Endoso H","Endoso P"],"explanation":"El endoso 'T' (Dobles/Triples) autoriza a un conductor a operar vehículos combinados que arrastran más de un remolque y requiere aprobar el examen de conocimientos de Dobles y Triples. Fuente: Wisconsin Commercial Driver's Manual (WisDOT)."},"28":{"q":"Un vehículo comercial de Wisconsin está diseñado para transportar 16 o más pasajeros, incluido el conductor. ¿Qué endoso se requiere además de la clase de CDL correcta?","options":["Endoso S","Endoso P","Endoso N","Endoso T"],"explanation":"El endoso 'P' (Pasajeros) se requiere para operar un vehículo diseñado para transportar, o que efectivamente transporta, 16 o más pasajeros, incluido el conductor. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), lista de endosos."},"29":{"q":"¿Cuál afirmación es VERDADERA sobre el endoso de autobús escolar 'S' de Wisconsin?","options":["Solo requiere un examen de conocimientos único que nunca vence","Requiere un examen de conocimientos y un examen de habilidades de manejo tanto al emitirse por primera vez como en cada renovación","Se otorga automáticamente a cualquier persona que tenga un endoso 'P'","Solo está disponible en una CDL Clase A"],"explanation":"Wisconsin requiere que el solicitante del endoso de autobús escolar 'S' apruebe los exámenes de conocimientos y de habilidades de manejo al emitirse originalmente, y que vuelva a aprobar los exámenes (conocimientos, señales de tránsito, visión, habilidades abreviadas) en cada renovación. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección de endoso de autobús escolar."},"30":{"q":"¿Cuál es la edad mínima para obtener una CDL de Wisconsin válida para la conducción comercial intraestatal (dentro de Wisconsin)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Un conductor debe tener al menos 18 años para obtener una CDL de Wisconsin para comercio intraestatal. Fuente: Wisconsin Commercial Driver's Manual (WisDOT) / requisitos de CDL de WisDOT."},"31":{"q":"¿Cuál es la edad mínima requerida para conducir un vehículo comercial motorizado en comercio interestatal (cruzando líneas estatales) bajo las normas de Wisconsin y federales?","options":["18 años","19 años","20 años","21 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un CMV en comercio interestatal, para transportar materiales peligrosos y para transportar pasajeros a través de líneas estatales. Fuente: Wisconsin Commercial Driver's Manual (WisDOT) / requisitos de CDL de WisDOT."},"32":{"q":"Bajo las normas del Permiso de Aprendiz Comercial (CLP) de Wisconsin, ¿cuánto tiempo debe tener el CLP antes de que se le permita presentar el examen de habilidades (de manejo) de la CDL?","options":["7 días","14 días","30 días","60 días"],"explanation":"Wisconsin (siguiendo el estándar federal) requiere que tenga un CLP durante al menos 14 días antes de presentar el examen de habilidades. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección del Permiso de Aprendiz Comercial."},"33":{"q":"¿Por cuántos días es válido un Permiso de Aprendiz Comercial (CLP) de Wisconsin antes de que deba renovarse?","options":["90 días","180 días","1 año","2 años"],"explanation":"Un CLP de Wisconsin es válido por 180 días y puede renovarse. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección del Permiso de Aprendiz Comercial / página de requisitos de CDL de WisDOT."},"34":{"q":"Mientras conduce con un Permiso de Aprendiz Comercial (CLP) de Wisconsin, ¿qué se requiere del conductor supervisor?","options":["No se requiere conductor supervisor si el titular del CLP tiene 21 años","Un titular de una CDL válida, de un nivel de clase y endoso igual o superior al del permiso, debe estar sentado junto al titular del CLP","Cualquier conductor con licencia de 16 años o más puede viajar en el asiento trasero","Un examinador de WisDOT debe estar presente en todo momento"],"explanation":"Un titular de CLP debe estar acompañado por una persona que tenga una CDL válida de un nivel de clase/endoso igual o superior al del permiso, sentada junto al titular del CLP en la parte delantera. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección del CLP."},"35":{"q":"Al solicitar o renovar un endoso HazMat 'H' de Wisconsin, ¿qué requisito federal adicional debe cumplir el solicitante más allá de aprobar el examen de conocimientos de HazMat?","options":["Un segundo examen de habilidades de manejo en un vehículo con rótulos","Toma de huellas dactilares para una verificación de antecedentes penales/evaluación de amenazas del FBI","Una carta notariada de patrocinio del empleador","Una cuota de suscripción al clearinghouse de drogas y alcohol"],"explanation":"Wisconsin requiere que los solicitantes del endoso 'H' proporcionen huellas dactilares para una verificación de antecedentes penales del FBI (evaluación de amenazas de seguridad de la TSA) y presenten prueba de ciudadanía estadounidense o estatus legal, en la emisión original y en cada renovación. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección del endoso HazMat 'H'."},"36":{"q":"Para el endoso HazMat 'H' de Wisconsin, una condena por ciertos delitos descalificantes impedirá su emisión si la condena ocurrió dentro de cuántos años previos a la fecha de solicitud?","options":["3 años","5 años","7 años","10 años"],"explanation":"A un solicitante no se le permitirá obtener, renovar o transferir un endoso 'H' si fue condenado (o declarado no culpable por razón de demencia) de ciertos delitos descalificantes durante los 7 años previos a la fecha de solicitud. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), descalificaciones de HazMat."},"37":{"q":"¿Qué documento o prueba requiere Wisconsin específicamente que presente un solicitante del endoso HazMat 'H' que NO se requiere para la mayoría de los demás endosos de CDL?","options":["Prueba de ciudadanía estadounidense o estatus legal en los EE. UU.","Un diploma de escuela secundaria","Un contrato de arrendamiento de vehículo comercial","El número USDOT de un transportista"],"explanation":"Wisconsin requiere que los solicitantes del endoso HazMat 'H' presenten prueba de ciudadanía estadounidense o estatus legal en los EE. UU. en el examen de conocimientos, la emisión original y todas las renovaciones, además de la verificación de antecedentes del FBI. Fuente: Wisconsin Commercial Driver's Manual (WisDOT), sección del endoso HazMat 'H'."},"38":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) en Wisconsin debe completarse a través de un proveedor listado, ¿dónde, y se requiere para solicitantes de CDL por primera vez y ciertos endosos?","options":["El registro del Wisconsin Technical College System","El FMCSA Training Provider Registry (TPR)","La base de datos del National Safety Council","Cualquier lista de examinadores externos aprobados por el DMV"],"explanation":"La ELDT debe obtenerse de un proveedor de capacitación listado en el FMCSA Training Provider Registry (tpr.fmcsa.dot.gov). Se requiere para una primera CDL, una mejora de clase (de B a A) y los endosos H, P y S; los conductores cuya CDL fue emitida antes del 7 de febrero de 2022 están exentos. Fuente: página de requisitos de CDL de WisDOT / Wisconsin Commercial Driver's Manual."},"39":{"q":"En la autocertificación médica de la CDL de Wisconsin, ¿cuál de las siguientes es una de las cuatro categorías de operación de certificación válidas?","options":["Interestatal No Exceptuada (NI)","Certificado Federal Hazmat (FH)","Interestatal Suspendida (IS)","Granja Comercial Exenta (CF)"],"explanation":"Las cuatro categorías de autocertificación de la CDL de Wisconsin son Interestatal No Exceptuada (NI), Interestatal Exceptuada (EI), Intraestatal No Exceptuada (NA) e Intraestatal Exceptuada (EA); los conductores NI deben cumplir los requisitos médicos de 49 CFR Part 391 y tener una tarjeta Fed Med válida. Fuente: WisDOT MV3230 Commercial Driver Certification: Tier of Operation / página de la tarjeta Fed Med."},"40":{"q":"En Wisconsin, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo comercial motorizado (CMV)?","options":["0.04","0.08","0.02","0.00"],"explanation":"Wisconsin prohíbe operar un CMV con un BAC de 0.04 o más (Wis. Stat. § 346.63(5); Wisconsin CDL Manual). Alcanzar 0.04 en un CMV es una infracción descalificante mayor, a diferencia del límite de 0.08 que aplica a los vehículos ordinarios (no comerciales)."},"41":{"q":"¿Por cuánto tiempo se descalifica una CDL en Wisconsin por una primera infracción mayor, como operar un CMV con un BAC de 0.04 o más?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Según la tabla General de Descalificaciones de la CDL de Wisconsin (WisDOT) y Wis. Stat. § 343.315, una primera condena por una infracción mayor descalifica la CDL por 1 año. El período de 3 años aplica únicamente cuando el conductor transportaba materiales peligrosos con rótulos."},"42":{"q":"Bajo las normas de Wisconsin, una primera infracción mayor (como un OWI en un CMV) conlleva una descalificación de la CDL de 3 años en lugar de 1 año bajo ¿qué condición?","options":["El conductor transportaba materiales peligrosos con rótulos","El conductor tenía más de 65 años","El choque causó daños materiales","El conductor llevaba dos pasajeros a bordo"],"explanation":"La tabla de Descalificaciones de la CDL de WisDOT y Wis. Stat. § 343.315 elevan la descalificación por una primera infracción mayor de 1 año a 3 años cuando la infracción ocurrió mientras el CMV transportaba materiales peligrosos con rótulos."},"43":{"q":"¿Cuál es el período de descalificación de la CDL en Wisconsin por una SEGUNDA infracción mayor (por ejemplo, un segundo OWI en un CMV)?","options":["De por vida","3 años","10 años","5 años"],"explanation":"Una segunda condena por cualquier infracción descalificante mayor resulta en una descalificación de la CDL de por vida según la tabla de Descalificaciones de la CDL de WisDOT y Wis. Stat. § 343.315 (que refleja 49 CFR 383.51)."},"44":{"q":"Bajo la ley de Consentimiento Implícito de Wisconsin, ¿qué sucede si un conductor de CMV se niega a la solicitud de un oficial de la ley de someterse a una prueba química para detectar alcohol o drogas?","options":["La CDL se descalifica por 1 año (de por vida en una segunda ocurrencia)","Se emite una advertencia sin descalificación","La CDL se descalifica por 60 días","La CDL se descalifica por 6 meses"],"explanation":"La negativa se trata como una infracción mayor: descalificación de la CDL de 1 año por una primera ocurrencia y descalificación de por vida por una segunda (tabla de Descalificaciones de la CDL de WisDOT; Wis. Stat. §§ 343.305, 343.315)."},"45":{"q":"Bajo la ley de Consentimiento Implícito de Wisconsin, negarse a una prueba química solicitada revoca el privilegio de conducir de un conductor por un mínimo de ¿cuánto tiempo?","options":["1 año","90 días","30 días","6 meses"],"explanation":"El Wisconsin CDL Manual establece que si usted se niega a una prueba solicitada por un oficial bajo la ley de Consentimiento Implícito (Wis. Stat. § 343.305), su privilegio de conducir será revocado por un mínimo de un año, además de otras sanciones."},"46":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años desencadenan una descalificación de la CDL de 60 días en Wisconsin?","options":["2","3","4","5"],"explanation":"Dos infracciones de tránsito graves en incidentes separados dentro de 3 años resultan en una descalificación de la CDL de 60 días (tabla de Descalificaciones de la CDL de WisDOT; Wis. Stat. § 343.315; 49 CFR 383.51)."},"47":{"q":"En Wisconsin, tres infracciones de tránsito graves dentro de un período de 3 años resultan en una descalificación de la CDL de ¿cuánto tiempo?","options":["120 días","60 días","1 año","90 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años descalifican la CDL por 120 días (tabla de Descalificaciones de la CDL de WisDOT; Wis. Stat. § 343.315). Dos dentro de 3 años son 60 días."},"48":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE bajo las normas de la CDL de Wisconsin?","options":["Exceso de velocidad de 15 mph o más sobre el límite","Una infracción de estacionamiento","Operar con un BAC de 0.04 o más","Negarse a una prueba química"],"explanation":"El exceso de velocidad de 15 mph o más sobre el límite es una infracción de tránsito grave (tabla de Descalificaciones de la CDL de WisDOT). Un BAC de 0.04 y la negativa a una prueba son infracciones MAYORES, no infracciones graves, y las multas de estacionamiento no cuentan."},"49":{"q":"¿Cuál de las siguientes NO está en la lista de infracciones de tránsito graves de Wisconsin a efectos de descalificación de la CDL?","options":["Operar un CMV con un BAC de 0.04 o más","Seguir a otro vehículo demasiado de cerca","Conducción temeraria","Cambio de carril indebido o errático"],"explanation":"Seguir demasiado de cerca, la conducción temeraria y los cambios de carril indebidos/erráticos son infracciones de tránsito graves (tabla de WisDOT). Operar con un BAC de 0.04 o más es una infracción MAYOR (1 año / de por vida), no una infracción grave."},"50":{"q":"Desde el 1 de julio de 2016, en Wisconsin, ¿cuántas condenas por usar un teléfono móvil de mano mientras se opera un CMV se requieren antes de que se descalifique la CDL?","options":["2 o más","1","4 o más","3 o más"],"explanation":"El Wisconsin CDL Manual establece que la CDL se descalifica después de dos o más condenas por el uso de un teléfono móvil de mano mientras se opera un CMV: 60 días por la segunda infracción dentro de 3 años y 120 días por tres o más dentro de 3 años."},"51":{"q":"Bajo el Wisconsin CDL Manual, ¿cuál es la sanción civil máxima que puede imponerse a un conductor de CMV por enviar mensajes de texto mientras conduce?","options":["$2,750","$2,500","$11,000","$5,000"],"explanation":"El Wisconsin CDL Manual establece que un conductor que envía mensajes de texto mientras opera un CMV está sujeto a sanciones civiles de hasta $2,750 por infracción; los transportistas que lo permiten o exigen enfrentan sanciones de hasta $11,000."},"52":{"q":"Bajo el Wisconsin CDL Manual, ¿cuál es la sanción civil máxima que puede enfrentar un transportista por permitir o exigir que sus conductores usen un teléfono de mano o envíen mensajes de texto mientras conducen un CMV?","options":["$11,000","$2,750","$10,000","$5,500"],"explanation":"El Wisconsin CDL Manual establece que los empleadores (transportistas) pueden estar sujetos a sanciones civiles de hasta $11,000 por permitir o exigir el uso de teléfono de mano o el envío de mensajes de texto por parte de los conductores de CMV; la sanción propia del conductor es de hasta $2,750."},"53":{"q":"Dos condenas por enviar mensajes de texto mientras se opera un CMV dentro de un período de 3 años resultan en ¿qué descalificación de la CDL en Wisconsin?","options":["60 días","120 días","30 días","1 año"],"explanation":"El Wisconsin CDL Manual establece que la CDL se descalifica por 60 días en la segunda infracción de mensajes de texto dentro de 3 años, y 120 días por tres o más infracciones dentro de 3 años."},"54":{"q":"¿Cuál es la descalificación de la CDL en Wisconsin por una SEGUNDA violación de una orden de fuera de servicio dentro de 10 años (sin materiales peligrosos, sin pasajeros)?","options":["2 años","90 días","1 año","5 años"],"explanation":"Según la tabla de Descalificaciones de la CDL de WisDOT, una segunda violación de una orden de fuera de servicio dentro de 10 años descalifica la CDL por 2 años (3 años si lleva materiales peligrosos con rótulos o es un vehículo de pasajeros)."},"55":{"q":"En Wisconsin, ¿cuál es la descalificación de la CDL por una PRIMERA condena por una violación en un cruce ferroviario a nivel (railroad-highway grade crossing) (como no detenerse cuando las vías no están despejadas)?","options":["60 días","30 días","120 días","90 días"],"explanation":"La tabla de Descalificaciones de la CDL de WisDOT establece una primera violación en un cruce ferroviario a nivel en una descalificación de 60 días; una segunda dentro de 3 años son 120 días y una tercera dentro de 3 años es 1 año."},"56":{"q":"¿Qué descalificación de la CDL aplica en Wisconsin a una TERCERA violación en un cruce ferroviario a nivel dentro de un período de 3 años?","options":["1 año","120 días","60 días","De por vida"],"explanation":"Según la tabla de Descalificaciones de la CDL de WisDOT, las violaciones en cruces ferroviarios a nivel conllevan 60 días (primera), 120 días (segunda dentro de 3 años) y 1 año (tercera dentro de 3 años)."},"57":{"q":"En Wisconsin, usar un vehículo comercial motorizado en la comisión de un delito grave que involucra la fabricación, distribución o suministro de una sustancia controlada resulta en ¿qué descalificación de la CDL?","options":["De por vida, sin posibilidad de reinstauración","1 año","3 años","10 años"],"explanation":"Según la tabla de Descalificaciones de la CDL de WisDOT y Wis. Stat. § 343.315, un delito grave que involucra una sustancia controlada cometido usando un CMV resulta en una descalificación de por vida inalterable (sin reinstauración), incluso en una primera infracción."},"58":{"q":"Según la ley de \"Cambia de Carril\" (Move Over) de Wisconsin, cuando te acercas a una grúa, una patrulla o un vehículo de mantenimiento de carreteras detenido en el costado del camino con luces de advertencia intermitentes y hay más de un carril en tu dirección, ¿qué debes hacer?","options":["Cambiarte a un carril que no esté junto al vehículo detenido si es seguro hacerlo","Detenerte por completo hasta que se apaguen las luces del otro vehículo","Continuar a la velocidad indicada porque Move Over solo cubre las patrullas de policía","Tocar la bocina y mantener tu velocidad al pasar junto al vehículo detenido"],"explanation":"La ley de \"Cambia de Carril\" (Move Over) de Wisconsin (Wis. Stat. s. 346.072) exige que los conductores que se acercan a vehículos de emergencia, de remolque, de servicios públicos o de mantenimiento de carreteras con luces intermitentes desocupen el carril más cercano al vehículo cambiándose de carril, si el cambio puede hacerse de forma segura. El Wisconsin CDL Manual (Sección 2.8) y WisDOT establecen que esto aplica a las fuerzas del orden, EMS, bomberos, grúas y trabajadores en el camino, no solo a la policía."},"59":{"q":"Según la ley de \"Cambia de Carril\" (Move Over) de Wisconsin, ¿qué debes hacer si no puedes cambiarte de carril de forma segura para alejarte de un vehículo de emergencia o de servicio en el camino que está detenido y muestra luces intermitentes?","options":["Reducir la velocidad y proceder con precaución hasta que hayas pasado el vehículo de forma segura","Detenerte por completo en el acotamiento y esperar a que el vehículo se vaya","Mantener el límite de velocidad indicado, ya que cambiar de carril es imposible","Orillarte al lado opuesto del camino para dar el máximo espacio libre"],"explanation":"El Wis. Stat. s. 346.072 y el Wisconsin CDL Manual (Sección 2.8) establecen que si el cambio de carril no es seguro (o solo existe un carril en tu dirección), debes reducir la velocidad y proceder con precaución hasta que hayas pasado el vehículo detenido de forma segura. No hay obligación de detenerte ni de usar el carril opuesto."},"60":{"q":"En Wisconsin, un vehículo que se acerca a un autobús escolar detenido que muestra luces rojas de advertencia intermitentes debe detenerse ¿a qué distancia mínima del autobús?","options":["No menos de 20 feet del autobús","No menos de 10 feet del autobús","No menos de 50 feet del autobús","No menos de 100 feet del autobús"],"explanation":"El Estatuto de Wisconsin 346.48(1) exige que el operador de un vehículo que se acerca por el frente o por atrás de un autobús escolar que muestra luces rojas de advertencia intermitentes se detenga a no menos de 20 feet del autobús y permanezca detenido hasta que el autobús se mueva o se apaguen las luces rojas."},"61":{"q":"Según la ley de Wisconsin, ¿quién está exento del requisito de detenerse ante un autobús escolar que muestra luces rojas de advertencia intermitentes?","options":["Los conductores que circulan en sentido contrario en una carretera dividida","Los conductores que circulan en el mismo sentido a menos de 100 feet del autobús","Los conductores en cualquier carretera con dos o más carriles en su dirección","Nadie está exento; todos los conductores deben detenerse en todo tipo de camino"],"explanation":"El Estatuto de Wisconsin 346.48(1) prevé una excepción: el requisito de detenerse no aplica a los operadores de vehículos que circulan en sentido CONTRARIO en una carretera DIVIDIDA. En caminos no divididos, el tránsito en sentido contrario aún debe detenerse. El tránsito en el mismo sentido siempre debe detenerse."},"62":{"q":"Un conductor de autobús escolar en Wisconsin se acerca a un cruce a nivel de ferrocarril donde se requiere detenerse. El frente del autobús debe detenerse por completo dentro de qué rango respecto al riel más cercano?","options":["No menos de 15 feet ni más de 50 feet","No menos de 5 feet ni más de 15 feet","No menos de 25 feet ni más de 75 feet","No menos de 50 feet ni más de 100 feet"],"explanation":"El Wisconsin CDL Manual (Secciones 2.15 y 4.3.5) exige que un autobús se detenga entre 15 y 50 feet antes de un cruce de ferrocarril -no más cerca de 15 feet ni más lejos de 50 feet del riel más cercano- y luego mire y escuche en ambas direcciones antes de continuar."},"63":{"q":"Según el Wisconsin CDL Manual, un vehículo que transporta materiales peligrosos con placards debe detenerse de 15 a 50 feet antes de un cruce de ferrocarril. Además de las cargas con placards, ¿cuál de estos TAMBIÉN requiere detenerse incluso cuando va vacío?","options":["Un tanque de carga usado para materiales peligrosos, esté cargado o vacío","Cualquier camión rígido de más de 26,000 pounds que transporte carga seca","Una plataforma plana que transporta rollos de acero debidamente asegurados","Una camioneta refrigerada que transporta productos alimenticios perecederos"],"explanation":"La Sección 9.6.12 del Wisconsin CDL Manual establece que un vehículo debe detenerse de 15 a 50 feet antes del riel más cercano si tiene placards, transporta cualquier cantidad de cloro, O tiene tanques de carga usados para materiales peligrosos, estén cargados o vacíos. Las cargas comunes de carga seca o refrigeradas no requieren detenerse."},"64":{"q":"Si debes detener tu vehículo comercial en un camino de dos carriles o una carretera no dividida de Wisconsin, ¿en cuántos minutos deben colocarse tus dispositivos de advertencia de emergencia?","options":["Dentro de 10 minutes","Dentro de 2 minutes","Dentro de 15 minutes","Dentro de 30 minutes"],"explanation":"El Wisconsin CDL Manual (Sección 2.7) establece que si debes detenerte en un camino o en el acotamiento, debes colocar tus dispositivos de advertencia de emergencia dentro de 10 minutes después de detenerte."},"65":{"q":"Cuando estás detenido en un camino de dos carriles de Wisconsin que lleva tránsito en ambas direcciones, ¿dónde dice el CDL Manual que debes colocar tus tres triángulos reflectantes?","options":["Dentro de 10 feet del vehículo, y 100 feet atrás y 100 feet adelante","A 10 feet, 100 feet y 200 feet solo detrás del vehículo","A 50 feet, 100 feet y 500 feet hacia el tránsito que se aproxima","Los tres dentro de 25 feet de la defensa trasera del vehículo"],"explanation":"El Wisconsin CDL Manual (Sección 2.7) indica que en un camino de dos carriles/no dividido coloques un triángulo dentro de 10 feet de la esquina delantera o trasera del vehículo, uno a aproximadamente 100 feet atrás y uno a aproximadamente 100 feet adelante, en el acotamiento o en el carril donde estás detenido."},"66":{"q":"Según el Wisconsin CDL Manual, ¿dónde deben colocarse los tres triángulos de advertencia cuando estás detenido en una carretera de un solo sentido o dividida?","options":["A 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima","A 10 feet, 100 feet y 100 feet en ambos lados del vehículo","A 25 feet, 100 feet y 300 feet hacia el tránsito que se aproxima","A 50 feet, 150 feet y 250 feet detrás del vehículo"],"explanation":"El Wisconsin CDL Manual (Sección 2.7) establece que en una carretera de un solo sentido o dividida coloques los dispositivos de advertencia a 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima (detrás del vehículo)."},"67":{"q":"El Wisconsin CDL Manual dice que si te detienes cerca de una colina, una curva o una obstrucción que impide que otros conductores vean tu vehículo dentro de cierta distancia, debes mover el triángulo más alejado más hacia atrás. ¿Cuál es esa cifra de distancia de visibilidad?","options":["500 feet","200 feet","300 feet","1,000 feet"],"explanation":"El Wisconsin CDL Manual (Sección 2.7) dice que si una colina, una curva u otra obstrucción impide que los conductores vean tu vehículo dentro de 500 feet, mueve el triángulo de advertencia más alejado más atrás por el camino para dar una advertencia anticipada adecuada."},"68":{"q":"¿Cuál es el límite máximo de velocidad para un camión comercial en una autopista rural de Wisconsin que forma parte del sistema interestatal?","options":["70 miles per hour, igual que para los autos","55 miles per hour para todos los camiones de más de 26,000 pounds","65 miles per hour, menor que el límite de 70 mph para los autos","60 miles per hour para cualquier vehículo que arrastre un remolque"],"explanation":"Conforme al Wis. Stat. s. 346.57(4), el límite en las autopistas de Wisconsin, incluidas las carreteras interestatales, es de 70 mph. Wisconsin no establece un límite de velocidad separado y menor para los camiones -a diferencia de algunos estados vecinos- por lo que los camiones pueden circular al mismo límite indicado de 70 mph donde esté señalizado, sujeto a la regla básica de velocidad segura."},"69":{"q":"¿La ley de Wisconsin restringe a los camiones comerciales a carriles específicos (como prohibirles el carril izquierdo) en las carreteras interestatales en general?","options":["No existe una prohibición estatal de carriles solo para camiones; aplica la regla general de \"mantente a la derecha excepto para rebasar\"","Sí, los camiones tienen prohibido el carril más a la izquierda en todas las interestatales de Wisconsin","Sí, los camiones deben permanecer en el carril derecho siempre que haya tres o más carriles","Sí, los camiones de más de 10,000 pounds solo pueden usar los dos carriles derechos en todo el estado"],"explanation":"Wisconsin no tiene ningún estatuto estatal que restrinja a los camiones a carriles específicos. La regla general (Wis. Stat. s. 346.05) exige conducir por la derecha y usar el carril izquierdo principalmente para rebasar. Pueden señalizarse restricciones locales específicas de carril, pero no existe una prohibición general de carril para camiones en las interestatales como en algunos estados."},"70":{"q":"El Wisconsin CDL Manual incluye una nota específica del estado sobre los autobuses escolares y las vías de ferrocarril. ¿Cuál de las siguientes afirmaciones refleja esa nota de Wisconsin?","options":["En Wisconsin, los autobuses escolares deben detenerse en vías usadas para maniobras industriales","En Wisconsin, los autobuses escolares pueden cruzar cualquier paso a menos de 10 mph sin detenerse","En Wisconsin, los autobuses escolares nunca se detienen en cruces dentro de los límites de la ciudad","En Wisconsin, los autobuses escolares solo se detienen en cruces con barreras activas"],"explanation":"El Wisconsin CDL Manual (Sección 4.3.5) incluye una \"Nota de Wisconsin\" que establece que en Wisconsin los autobuses escolares deben detenerse en vías usadas para maniobras industriales, un requisito específico del estado que va más allá de las reglas generales de cruces."},"71":{"q":"Según el Wisconsin CDL Manual, ¿en qué tipo de cruce un conductor de autobús NO necesita hacer una parada completa (pero aún debe reducir la velocidad y verificar el tránsito)?","options":["Un cruce marcado como \"exento\" (exempt) o \"abandonado\" (abandoned)","Un cruce con una señal de cruz de San Andrés (crossbuck) y sin barreras","Un cruce de múltiples vías en una zona rural","Un cruce donde las campanas de advertencia están en silencio"],"explanation":"El Wisconsin CDL Manual (Sección 4.3.5) enumera dónde un autobús no necesita detenerse pero debe reducir la velocidad y verificar: cruces de tranvía, donde un oficial o señalero dirige el tránsito, cuando un semáforo está en verde, y en cruces marcados como \"exento\" (exempt) o \"abandonado\" (abandoned). Una simple cruz de San Andrés (crossbuck) sin esas condiciones aún requiere que un autobús se detenga."},"72":{"q":"¿Cuál es el ancho máximo legal de un vehículo en Wisconsin antes de que se requiera un permiso de sobredimensión para circular por las carreteras?","options":["8 feet 6 inches (8.5 feet)","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"El ancho máximo legal de Wisconsin es de 8 feet 6 inches (8.5 feet); las cargas más anchas que esto requieren un permiso de sobredimensión a través del sistema de permisos de WisDOT. Los límites legales estándar son 8.5 ft de ancho, 13.5 ft de alto, 53 ft de largo para un semirremolque, y 80,000 lbs de peso bruto."},"73":{"q":"Wisconsin opera programas estacionales de restricción de peso que son distintivos de su clima. ¿Qué permite la \"declaración de camino congelado\" (frozen road declaration) del invierno?","options":["Cargas más pesadas en caminos designados mientras el pavimento está congelado y es más resistente","Una prohibición total de todos los camiones comerciales hasta que termine el deshielo de primavera","Límites de velocidad más altos para los camiones debido al menor tránsito en verano","Una exención de todas las tarifas de permiso para cargas que viajan solo de noche"],"explanation":"Los programas estacionales de restricción de peso de WisDOT aprovechan el clima de Wisconsin: la declaración de camino congelado del invierno (aproximadamente de mediados de diciembre a principios de marzo) permite cargas más pesadas mientras el pavimento congelado es estructuralmente más resistente, según el programa de Restricciones Estacionales de Peso (Seasonal Weight Restrictions) de WisDOT."},"74":{"q":"Durante el deshielo de primavera de Wisconsin, los programas de carreteras Clase II y de caminos con restricciones estacionales señalizadas, ¿qué hacen con los pesos de los camiones?","options":["Reducen los pesos por eje permitidos para proteger el pavimento debilitado por el deshielo","Aumentan los pesos permitidos porque la nieve derretida despeja los caminos","No tienen efecto sobre el peso; solo cambian los límites de velocidad indicados","Aplican solo a autos de pasajeros y vehículos recreativos, no a camiones"],"explanation":"Los programas de deshielo de primavera de WisDOT (caminos Clase II y caminos con restricciones estacionales señalizadas, aproximadamente de marzo a mayo) reducen los pesos por eje y los pesos brutos permitidos y suspenden muchos permisos de carga divisible porque el pavimento que se deshiela es estructuralmente débil. El objetivo es prolongar la vida de la carretera, según el programa de Restricciones Estacionales de Peso (Seasonal Weight Restrictions) de WisDOT."},"75":{"q":"En Wisconsin, cuando una carga de sobredimensión es lo suficientemente ancha como para requerir una sola escolta delantera, ¿qué tipo de vehículo puede servir como escolta?","options":["Un automóvil o camión de una sola unidad de no más de 16,000 pounds con las luces de advertencia requeridas","Cualquier motocicleta equipada con una bandera y una luz ámbar","Un segundo semirremolque cargado que viaje directamente adelante de la carga","Únicamente una patrulla identificada de las fuerzas del orden en todos los casos"],"explanation":"Según las reglas de permisos de sobredimensión de Wisconsin (WisDOT/Trans code), un vehículo de escolta (piloto) debe ser un automóvil o camión de una sola unidad de no más de 16,000 pounds, con una vista despejada, las luces bajas encendidas y las luces de advertencia encendidas mientras escolta la carga autorizada."},"76":{"q":"En un camino de dos carriles de Wisconsin, ¿qué marca adicional en el pavimento suele acompañar a un cruce de ferrocarril para controlar el rebase?","options":["Una marca de zona de no rebasar (y una señal de no rebasar) al acercarse a las vías","Una línea central amarilla discontinua que fomenta el rebase antes de las vías","Una línea de carril blanca continua que permite a los camiones compartir el cruce","Una franja de ciclovía que dirige a los camiones al extremo derecho del cruce"],"explanation":"El Wisconsin CDL Manual (Sección 2.15) señala que en los caminos de dos carriles, las marcas de pavimento de ferrocarril incluyen una \"X\" con las letras \"RR\" y una marca de no rebasar, y también hay una señal de zona de no rebasar al acercarse al cruce. Una línea de alto blanca, si está presente, es donde el frente del autobús debe permanecer mientras está detenido."},"77":{"q":"Un conductor con CDL de Wisconsin se detiene en el acotamiento de una concurrida autopista dividida tras una avería. Después de colocar los tres triángulos hacia el tránsito que se aproxima a 10, 100 y 200 feet, ¿qué aconseja el Wisconsin CDL Manual sobre cómo sostener los triángulos?","options":["Sostener cada triángulo entre ti y el tránsito que viene de frente para que otros conductores puedan verte","Sostener los triángulos por encima de la cabeza y caminar por el centro del carril de circulación","Lanzar los triángulos desde la cabina para evitar salir del vehículo por completo","Colocar los tres en el lado izquierdo mirando en sentido contrario al flujo del tránsito"],"explanation":"El Wisconsin CDL Manual (Sección 2.7) aconseja que al colocar los triángulos los sostengas entre ti y el tránsito que viene de frente por tu propia seguridad, para que los conductores que se aproximan puedan verte mientras colocas los dispositivos."},"78":{"q":"¿Qué agencia estatal emite las Licencias de Conducir Comerciales (CDLs) en Wisconsin?","options":["La Wisconsin Division of Motor Vehicles (DMV), parte de WisDOT","La Wisconsin State Patrol","El Wisconsin Department of Public Safety","La Federal Motor Carrier Safety Administration"],"explanation":"Las CDLs de Wisconsin son emitidas por la Wisconsin Division of Motor Vehicles (DMV), una división del Wisconsin Department of Transportation. La State Patrol hace cumplir las leyes de transportistas pero no emite licencias, y la FMCSA es una agencia federal que establece estándares en lugar de emitir CDLs estatales. Fuente: Wisconsin Commercial Driver's Manual; página de Requisitos de CDL de wisconsindot.gov."},"79":{"q":"¿Cuál es el número mínimo de respuestas correctas necesarias para aprobar el examen de Conocimientos Generales (General Knowledge) de CDL de Wisconsin, que contiene 50 questions?","options":["40 correct (80%)","30 correct (60%)","35 correct (70%)","45 correct (90%)"],"explanation":"El examen de Conocimientos Generales (General Knowledge) de Wisconsin tiene 50 questions y debes responder correctamente al menos 40, una calificación aprobatoria de 80%. El estándar de 80% aplica a los exámenes de conocimientos de CDL en Wisconsin. Fuente: Wisconsin Commercial Driver's Manual; Requisitos de CDL de wisconsindot.gov."},"80":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Wisconsin?","options":["180 days","90 days","1 year","60 days"],"explanation":"Un CLP de Wisconsin es válido por 180 days y enumera los tipos de vehículos y los endorsements para los que el titular ha calificado. Fuente: Wisconsin Commercial Driver's Manual, sección del Permiso de Aprendiz Comercial (CLP)."},"81":{"q":"¿Cuánto tiempo debe esperar el titular de un CLP de Wisconsin después de que se emite el permiso antes de que se le permita tomar el examen de habilidades (skills test) de CDL?","options":["14 days","10 days","30 days","7 days"],"explanation":"Conforme a las reglas federales adoptadas por Wisconsin, debes tener el CLP durante al menos 14 days antes de que se te permita tomar un examen de habilidades. Fuente: Wisconsin Commercial Driver's Manual, sección de exámenes de habilidades; 49 CFR 383.25."},"82":{"q":"El examen de habilidades (skills test) de CDL de Wisconsin tiene tres partes que deben tomarse en un orden establecido. ¿Cuál es el orden correcto?","options":["Inspección del vehículo, control básico del vehículo, conducción en carretera","Conducción en carretera, inspección del vehículo, control básico del vehículo","Control básico del vehículo, conducción en carretera, inspección del vehículo","Inspección del vehículo, conducción en carretera, control básico del vehículo"],"explanation":"El examen de habilidades de tres partes de Wisconsin debe tomarse en orden: inspección del vehículo, luego control básico del vehículo, y luego conducción en carretera. Fuente: Wisconsin Commercial Driver's Manual, sección de exámenes de habilidades."},"83":{"q":"Antes de que un nuevo solicitante en Wisconsin sea elegible para tomar las pruebas de CDL, ¿qué capacitación debe completar?","options":["Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor registrado ante la FMCSA","Un curso de manejo defensivo aprobado por el condado","Un aprendizaje de dos años bajo un transportista con licencia","Una certificación de seguridad en el lugar de trabajo de OSHA"],"explanation":"Los nuevos solicitantes de CDL (y quienes actualizan de clase o agregan ciertos endorsements) deben completar la Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor listado en el FMCSA Training Provider Registry antes de las pruebas. Fuente: Wisconsin Commercial Driver's Manual; 49 CFR Part 380 Subpart F."},"84":{"q":"¿Qué documento usan los solicitantes de CDL de Wisconsin para autocertificar su nivel (tipo) de operación comercial?","options":["Formulario MV3230, Commercial Driver Certification: Tier of Operation","Formulario MV3001, la solicitud general de licencia de conducir","Formulario MV3740, la autocertificación de autobús escolar","FMCSA Medical Examination Report (MCSA-5875)"],"explanation":"Los conductores de Wisconsin autocertifican su nivel de operación en el Formulario MV3230. El MV3001 es la solicitud general de licencia, el MV3740 es una autocertificación de autobús escolar, y el MCSA-5875 es el informe del examen médico completado por un examinador. Fuente: página de Fed Med card de wisconsindot.gov; Formulario MV3230."},"85":{"q":"¿Entre cuántas categorías de autocertificación (niveles de operación) debe elegir el titular de una CDL de Wisconsin?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro niveles de autocertificación: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate y Excepted Intrastate. Fuente: página de Fed Med card de wisconsindot.gov; 49 CFR 383.71."},"86":{"q":"¿Cuál nivel de autocertificación de Wisconsin EXIGE que el conductor mantenga un certificado válido de examinador médico federal (Fed Med card)?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Cualquier conductor que nunca cruce las líneas estatales"],"explanation":"Los conductores Non-Excepted Interstate (NI) deben tener una Fed Med card válida. Los niveles Excepted Interstate y Excepted Intrastate no requieren una. Fuente: página de Fed Med card de wisconsindot.gov; 49 CFR 383.71."},"87":{"q":"A partir del cambio de proceso de 2025, ¿cómo llega normalmente la información del certificado de examinador médico federal (Fed Med card) de un conductor de Wisconsin a la WI DMV después de un examen físico de DOT?","options":["La FMCSA la transmite electrónicamente a la WI DMV dentro de aproximadamente 48 hours del examen","El conductor siempre debe enviar por fax una copia en papel a la DMV dentro de 10 days","El empleador de transporte la envía por correo a la DMV en nombre del conductor","Se imprime en la CDL y nunca se reporta al estado"],"explanation":"A partir del 13 de abril de 2025, la FMCSA proporciona automáticamente la información de la Fed Med card del conductor a la WI DMV, generalmente dentro de 48 hours del examen físico de DOT. Los exámenes completados antes de esa fecha debían ser presentados por el conductor. Fuente: página de Fed Med card de wisconsindot.gov."},"88":{"q":"¿Con qué frecuencia debe renovarse una CDL de Wisconsin?","options":["Cada 8 years","Cada 4 years","Cada 6 years","Cada 2 years"],"explanation":"Una CDL de Wisconsin debe renovarse cada 8 years. Fuente: Wisconsin Commercial Driver's Manual; información de renovación de wisconsindot.gov."},"89":{"q":"¿Cuál es la edad mínima para obtener una CDL de Wisconsin para conducción comercial intraestatal (dentro de Wisconsin)?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"Debes tener al menos 18 años para obtener una CDL/CLP de Wisconsin para operación intraestatal. El comercio interestatal generalmente requiere tener al menos 21 años. Fuente: Wisconsin Commercial Driver's Manual, sección del Permiso de Aprendiz Comercial (CLP)."},"90":{"q":"¿Bajo qué condición puede el titular de un CLP en Wisconsin operar un vehículo comercial en el comercio interestatal?","options":["Solo si tiene al menos 21 años y posee un certificado médico federal válido","A cualquier edad, ya que un CLP otorga plena autoridad interestatal","Solo después de tener el CLP durante 180 days","Solo con un endorsement de autobús escolar"],"explanation":"El titular de un CLP no puede operar en el comercio interestatal a menos que tenga al menos 21 años y posea una Fed Med card válida. Fuente: Wisconsin Commercial Driver's Manual, sección del CLP."},"91":{"q":"En el examen de habilidades, ¿cuántos de los tres segmentos debe aprobar un solicitante de Wisconsin con el mismo CLP?","options":["Los tres segmentos deben aprobarse con el mismo CLP","Solo el segmento de conducción en carretera debe ser con el mismo CLP","Dos cualesquiera de los tres pueden trasladarse a un nuevo CLP","Los segmentos pueden repartirse entre hasta tres CLP diferentes"],"explanation":"Wisconsin exige que los tres segmentos del examen de habilidades se aprueben con el mismo CLP. Fuente: Wisconsin Commercial Driver's Manual, sección de exámenes de habilidades."},"92":{"q":"¿Qué examen debe aprobar TODO solicitante de CDL de Wisconsin sin importar la clase o los endorsements que busque?","options":["El examen de Conocimientos Generales (General Knowledge)","El examen de Frenos de Aire (Air Brakes)","El examen de Vehículos Combinados (Combination Vehicles)","El examen de Materiales Peligrosos (Hazardous Materials)"],"explanation":"El examen de Conocimientos Generales (General Knowledge) lo toman todos los solicitantes de CDL; otros exámenes de conocimientos (frenos de aire, combinación, hazmat, etc.) se requieren solo para clases o endorsements específicos. Fuente: Wisconsin Commercial Driver's Manual, sección de exámenes de conocimientos."},"93":{"q":"Además del examen de Conocimientos Generales (General Knowledge), ¿qué DOS documentos/pruebas se requieren al solicitar un CLP/CDL de Wisconsin?","options":["Una licencia de conducir válida de Wisconsin y prueba de ciudadanía o estatus legal","Un pasaporte y una carta notariada del empleador","Una tarjeta de Seguro Social y un título de vehículo","Un diploma de preparatoria y dos referencias personales"],"explanation":"Los solicitantes de Wisconsin deben tener una licencia de conducir válida de Wisconsin y proporcionar prueba de ciudadanía estadounidense o presencia legal, junto con la solicitud (MV3001) y la autocertificación de nivel (MV3230). Fuente: Requisitos de CDL de wisconsindot.gov; Wisconsin Commercial Driver's Manual."},"94":{"q":"El titular de una CDL que deja vencer su Fed Med card y no tiene un certificado médico válido en archivo en Wisconsin está restringido a ¿qué tipo de operación?","options":["Operación intraestatal únicamente (dentro de Wisconsin)","Operación interestatal únicamente","Operación únicamente de vehículos vacíos","No se permite la operación de ningún vehículo comercial"],"explanation":"Un conductor sin una tarjeta médica federal válida está restringido a la operación intraestatal (dentro del estado), o a la operación intraestatal exenta, y pierde la autoridad interestatal. Fuente: Wisconsin Commercial Driver's Manual, sección de CLP/médica."},"95":{"q":"Además de los examinadores de la DMV de Wisconsin, ¿quién está autorizado para administrar los exámenes de habilidades de CDL de Wisconsin?","options":["Examinadores externos autorizados por la DMV (third party examiners)","Cualquier conductor con CDL con licencia elegido por el solicitante","Inspectores de campo de la FMCSA","Agentes del sheriff del condado"],"explanation":"La DMV de Wisconsin autoriza a examinadores externos (third party examiners) aprobados para administrar los exámenes de habilidades de CDL; los solicitantes se ponen en contacto con un examinador externo autorizado para programar la cita. Fuente: Wisconsin Commercial Driver's Manual, sección de exámenes de habilidades."},"96":{"q":"En el segmento de inspección del vehículo del examen de habilidades de Wisconsin, ¿qué se requiere que haga el solicitante?","options":["Inspeccionar el vehículo y explicar al examinador qué se está revisando y por qué","Observar al examinador inspeccionar el vehículo y firmar una lista de verificación","Presentar un informe de inspección por escrito de un mecánico de la semana anterior","Conducir el vehículo en la carretera mientras describe los indicadores del tablero"],"explanation":"En el examen de inspección del vehículo, el solicitante realiza la inspección y explica al examinador qué se inspeccionaría y por qué, demostrando el conocimiento de que el vehículo es seguro para conducir. Fuente: Wisconsin Commercial Driver's Manual, Sección 2.1 y Sección 11M."},"97":{"q":"¿Cuál es la relación entre el examinador médico que emite una Fed Med card y el FMCSA National Registry?","options":["El examen debe ser realizado por un examinador médico listado en el FMCSA National Registry of Certified Medical Examiners","Cualquier médico con licencia puede emitir la tarjeta sin registrarse","Solo los médicos del personal de la DMV de Wisconsin pueden realizar el examen","La tarjeta es emitida directamente por la FMCSA después de un cuestionario enviado por correo"],"explanation":"El examen físico de DOT debe ser realizado por un examinador médico listado en el FMCSA National Registry of Certified Medical Examiners, quien completa el FMCSA Medical Examination Report y emite el Certificado del Examinador Médico (Medical Examiner's Certificate). Fuente: página de Fed Med card de wisconsindot.gov; 49 CFR 390.103."}},"hi":{"0":{"q":"बिना किसी विशेष परमिट के, विस्कॉन्सिन राजमार्ग पर किसी वाहन और उसके लोड की अधिकतम कुल चौड़ाई कितनी हो सकती है?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Wis. Stat. 348.05(1) बिना परमिट के 8 feet 6 inches (102 inches) से अधिक कुल चौड़ाई वाले वाहन को चलाने पर रोक लगाता है। यह विस्कॉन्सिन द्वारा अपनाए गए संघीय मानक से मेल खाता है।"},"1":{"q":"बिना परमिट के, विस्कॉन्सिन राजमार्ग पर किसी वाहन (लोड सहित) की अधिकतम कानूनी ऊँचाई कितनी हो सकती है?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","14 feet 6 inches"],"explanation":"Wis. Stat. 348.06(1) बिना परमिट के अधिकतम कुल ऊँचाई 13 feet 6 inches (13 1/2 feet) निर्धारित करता है। इस सीमा के बावजूद चालक वास्तविक ऊपरी निकासी (overhead clearance) के लिए जिम्मेदार रहते हैं।"},"2":{"q":"बिना परमिट के विस्कॉन्सिन राजमार्ग पर किसी एकल एक्सल (single axle) पर लगाई जा सकने वाली अधिकतम सकल वजन (gross weight) सीमा क्या है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Wis. Stat. 348.15(3)(b) के तहत, किसी एकल एक्सल पर सकल वजन 20,000 pounds से अधिक नहीं हो सकता। यह संघीय एकल-एक्सल सीमा के समान है।"},"3":{"q":"बिना परमिट के, विस्कॉन्सिन Class \"A\" राजमार्ग पर एक टैंडम एक्सल समूह (tandem axle group) पर अनुमत अधिकतम सकल वजन कितना है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Wis. Stat. 348.15(3)(d) एक टैंडम एक्सल समूह (दो लगातार सेट) को 34,000 pounds तक ले जाने की अनुमति देता है, जो संघीय टैंडम-एक्सल सीमा के अनुरूप है।"},"4":{"q":"विस्कॉन्सिन Class \"A\" राजमार्ग पर, बिना परमिट के चलने वाले उचित रूप से दूरी पर रखे गए पाँच-एक्सल संयोजन के लिए अधिकतम कानूनी सकल वाहन वजन कितना है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"Wis. Stat. 348.15(3)(g) में दी गई एक्सल-समूह वजन तालिका, जो संघीय ब्रिज फॉर्मूला लागू करती है, कानूनी सकल वजन को 80,000 pounds पर सीमित करती है। WisDOT 80,000 lb को कानूनी सीमा के रूप में प्रकाशित करता है।"},"5":{"q":"बिना परमिट के, विस्कॉन्सिन किसी एक पहिये, या किसी एक्सल के एक सिरे को सहारा देने वाले पहियों पर अधिकतम कितना सकल वजन अनुमत करता है?","options":["9,000 pounds","10,000 pounds","11,000 pounds","13,000 pounds"],"explanation":"Wis. Stat. 348.15(3)(a) किसी एक पहिये या किसी एक्सल के एक सिरे को सहारा देने वाले पहियों पर सकल वजन को 11,000 pounds तक सीमित करता है।"},"6":{"q":"बिना परमिट के, विस्कॉन्सिन राजमार्ग पर किसी एकल वाहन की अधिकतम कुल लंबाई कितनी हो सकती है?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"Wis. Stat. 348.07(1) बिना परमिट के एकल वाहन की कुल लंबाई को 45 feet तक सीमित करता है (कृषि उपकरणों के लिए एक अलग अधिक छूट है)।"},"7":{"q":"बिना परमिट के, विस्कॉन्सिन राजमार्ग पर दो वाहनों और लोड के संयोजन की अधिकतम कुल लंबाई कितनी हो सकती है (जहाँ कुल लंबाई सीमा लागू होती है)?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"Wis. Stat. 348.07(1) दो वाहनों के संयोजन के लिए सामान्य कुल-लंबाई सीमा 70 feet निर्धारित करता है, हालाँकि निर्दिष्ट राजमार्गों पर कुछ ट्रैक्टर-सेमीट्रेलर संयोजनों के लिए कोई कुल लंबाई सीमा नहीं है।"},"8":{"q":"s. 348.07(4) के तहत निर्दिष्ट विस्कॉन्सिन राजमार्ग पर, दो-वाहन संयोजन में चलाए जाने वाले एकल सेमीट्रेलर की अधिकतम लंबाई कितनी है (किंगपिन-से-एक्सल दूरी सीमाओं के भीतर)?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"Wis. Stat. 348.07(2)(gv) निर्दिष्ट राजमार्गों पर दो-वाहन संयोजन में 53-foot सेमीट्रेलर (किंगपिन-से-एक्सल 43 feet से अधिक नहीं) की अनुमति देता है, जिसमें कोई कुल संयोजन लंबाई सीमा नहीं है।"},"9":{"q":"विस्कॉन्सिन के उन राजमार्गों पर जो s. 348.07(4) के तहत निर्दिष्ट नहीं हैं, दो-वाहन संयोजन के भाग के रूप में चलाए जाने वाले सेमीट्रेलर या ट्रेलर की अधिकतम लंबाई कितनी है?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"Wis. Stat. 348.07(2)(g) s. 348.07(4) के तहत निर्दिष्ट न किए गए राजमार्गों पर सेमीट्रेलर या ट्रेलर को 48 feet तक सीमित करता है; 53-foot की छूट केवल निर्दिष्ट राजमार्गों पर लागू होती है।"},"10":{"q":"जब निर्माता की रेटिंग अधिक अनुमति नहीं देती, तब विस्कॉन्सिन में किसी ट्रक ट्रैक्टर के स्टीयरिंग एक्सल पर अनुमत अधिकतम वजन कितना है?","options":["11,000 pounds","12,000 pounds","13,000 pounds","15,000 pounds"],"explanation":"Wis. Stat. 348.15(3)(b) किसी ट्रक ट्रैक्टर के स्टीयरिंग एक्सल को 13,000 pounds तक सीमित करता है, जब तक कि निर्माता की रेटेड क्षमता (टायर, एक्सल, आदि) अधिक न हो, जो 20,000 pounds तक हो सकती है।"},"11":{"q":"विस्कॉन्सिन में दो या अधिक लगातार एक्सल समूहों के लिए वजन सीमा किस विधि का उपयोग करके निकाली जाती है?","options":["दूरी की परवाह किए बिना एक निश्चित 80,000-pound सीमा","s. 348.15(3)(g) में संघीय ब्रिज फॉर्मूला / वजन तालिका","केवल निर्माता की GVWR रेटिंग","प्रति एक्सल समूह एक निश्चित 34,000 pounds"],"explanation":"Wis. Stat. 348.15(3)(g) लगातार एक्सल समूहों के लिए अधिकतम सकल वजन एक तालिका के अनुसार निर्धारित करता है जो एक्सल की दूरी और एक्सल की संख्या के आधार पर संघीय ब्रिज फॉर्मूला लागू करती है।"},"12":{"q":"विस्कॉन्सिन में, Department of Transportation का oversize/overweight (OSOW) परमिट आम तौर पर कब आवश्यक होता है?","options":["केवल 100,000 pounds से अधिक के लोड के लिए","जब कोई वाहन या लोड वैधानिक आकार या वजन सीमाओं से अधिक हो","केवल 10 feet से चौड़े वाहनों के लिए","केवल जब Interstate प्रणाली पर यात्रा कर रहे हों"],"explanation":"Wis. Stat. ch. 348 और WisDOT परमिट नियमों के अनुसार, वह वाहन या लोड जो कानूनी आकार या वजन सीमाओं (चौड़ाई, ऊँचाई, लंबाई, या वजन) से अधिक हो, उसे चलाने से पहले OSOW परमिट प्राप्त करना होगा।"},"13":{"q":"एक अविभाज्य (non-divisible) लोड जो एक यात्रा के लिए विस्कॉन्सिन के कानूनी आयामों से अधिक है, उसे आम तौर पर किस प्रकार के परमिट द्वारा अधिकृत किया जाता है?","options":["एक single-trip OSOW परमिट","एक वाहन पंजीकरण स्टिकर","एक CDL एंडोर्समेंट","एक IRP विभाजित प्लेट"],"explanation":"WisDOT एक निर्दिष्ट मार्ग पर अविभाज्य oversize/overweight लोड के लिए single-trip OSOW परमिट (फॉर्म MV2600) जारी करता है; multiple-trip और वार्षिक परमिट योग्य बार-बार होने वाले आवागमन को कवर करते हैं।"},"14":{"q":"विस्कॉन्सिन के multiple-trip OSOW वजन परमिट के तहत, उच्चतर सकल-वजन छूट के योग्य होने के लिए किसी वाहन संयोजन में कम से कम कितने एक्सल होने चाहिए?","options":["चार एक्सल","पाँच एक्सल","छह एक्सल","आठ एक्सल"],"explanation":"WisDOT के multiple-trip वजन परमिट के लिए छह या अधिक एक्सल वाले संयोजन की आवश्यकता होती है, जिसमें प्रत्येक गिने गए एक्सल पर आम तौर पर कुल सकल वजन का कम से कम 8 प्रतिशत होना चाहिए।"},"15":{"q":"उच्च वजन पर कच्चे वन उत्पाद (raw forest products) ढोने वाले वाहनों के लिए विस्कॉन्सिन OSOW परमिट के तहत, अधिकतम अनुमत सकल वजन कितना है?","options":["80,000 pounds","90,000 pounds","98,000 pounds","120,000 pounds"],"explanation":"WisDOT के raw forest products (RS) परमिट छह-या-अधिक-एक्सल संयोजन के साथ अधिकतम 98,000 pounds सकल वजन की अनुमति देते हैं, जिसमें कोई एकल एक्सल 18,000 pounds से अधिक नहीं होना चाहिए।"},"16":{"q":"बिना परमिट के, कृषि चौड़ाई छूट के तहत विस्कॉन्सिन राजमार्गों पर अधिकांश कृषि वाणिज्यिक मोटर वाहनों के लिए अनुमत अधिकतम चौड़ाई कितनी है?","options":["8 feet 6 inches","9 feet 6 inches","10 feet","12 feet"],"explanation":"Wis. Stat. 348.05(2)(am) कुछ कृषि वाणिज्यिक मोटर वाहनों को बिना परमिट के 10 feet तक की चौड़ाई की अनुमति देता है (स्प्रेयर जैसे विशिष्ट उपकरणों के लिए अधिक छूट के साथ)।"},"17":{"q":"विस्कॉन्सिन की 80,000-pound कानूनी सकल वजन सीमा Class \"A\" राजमार्गों पर लागू होती है। राज्य में Interstate प्रणाली पर इस सीमा को कैसे माना जाता है?","options":["Interstate पर कोई वजन सीमा बिल्कुल नहीं है","Interstate समान एक्सल और ब्रिज-फॉर्मूला सीमाओं का उपयोग करते हैं, जिसमें 80,000-pound कानूनी अधिकतम है","Interstate बिना परमिट के 120,000 pounds की अनुमति देते हैं","Interstate केवल 73,280 pounds की अनुमति देते हैं"],"explanation":"विस्कॉन्सिन Interstate प्रणाली पर संघीय एक्सल और ब्रिज-फॉर्मूला सीमाएँ लागू करता है, जिससे वही 80,000-pound कानूनी अधिकतम प्राप्त होता है (Wis. Stat. 348.15; 23 U.S.C. 127), इसलिए अधिक वजन वाले लोड को अभी भी परमिट की आवश्यकता होती है।"},"18":{"q":"तरल दूध उत्पादों (fluid milk products) के परिवहन के लिए विस्कॉन्सिन OSOW परमिट के तहत, सकल वजन सामान्य अधिकतम से कितना अधिक हो सकता है, इससे ज्यादा नहीं?","options":["10,000 pounds","15,000 pounds","18,000 pounds","25,000 pounds"],"explanation":"WisDOT के fluid milk products (FMP) परमिट संयोजनों को छह-या-अधिक-एक्सल संयोजन पर अधिकतम सकल वजन से 18,000 pounds से अधिक नहीं (98,000 lb तक) बढ़ने की अनुमति देते हैं।"},"19":{"q":"विस्कॉन्सिन में एक टैंडम एक्सल समूह को 34,000 pounds तक केवल तभी लोड किया जा सकता है जब दो लगातार टैंडम सेटों के पहले और अंतिम एक्सल के बीच की दूरी किस न्यूनतम दूरी को पूरा करती हो?","options":["28 feet या अधिक","30 feet या अधिक","36 feet या अधिक","40 feet या अधिक"],"explanation":"Wis. Stat. 348.15(3)(d) दो लगातार टैंडम एक्सल सेटों में से प्रत्येक को 34,000 pounds ले जाने की अनुमति देता है जब पहले और अंतिम एक्सल के बीच की दूरी 36 feet या अधिक हो।"},"20":{"q":"विस्कॉन्सिन में, 26,000 pounds से अधिक Gross Combination Weight Rating वाले संयोजन वाहन को चलाने के लिए कौन सी CDL श्रेणी आवश्यक है, जिसमें 10,000 pounds से अधिक GVWR वाली खींची गई इकाई शामिल हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"विस्कॉन्सिन एक Class A CDL को एक ऐसे संयोजन वाहन के रूप में परिभाषित करता है जिसका GCWR (या वास्तविक/पंजीकृत वजन) 26,000 pounds से अधिक हो, जिसमें 10,000 pounds से अधिक GVWR वाली खींची गई इकाई शामिल हो। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'"},"21":{"q":"विस्कॉन्सिन के नियमों के तहत, 26,000 pounds से अधिक GVWR वाला एकल भारी सीधा ट्रक (straight truck) जिसमें कोई ट्रेलर न हो (या 10,000 pounds या उससे कम की खींची गई इकाई हो), उसके लिए कौन सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"विस्कॉन्सिन एक Class B CDL को एक भारी सीधे वाहन के रूप में परिभाषित करता है जिसका GVWR (या वास्तविक/पंजीकृत वजन) 26,000 pounds से अधिक हो, जिसमें 10,000 pounds या उससे कम की इकाई खींचने वाला ऐसा वाहन भी शामिल है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT)।"},"22":{"q":"26,000 pounds या उससे कम GVWR वाला एक छोटा वाहन चालक सहित 16 या अधिक व्यक्तियों को ले जाने के लिए डिज़ाइन किया गया है। इसके लिए कौन सी विस्कॉन्सिन CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","Class M"],"explanation":"विस्कॉन्सिन एक Class C CDL को 26,000 pounds या उससे कम के ऐसे वाहन के रूप में परिभाषित करता है जो (चालक सहित) 16 या अधिक व्यक्तियों को ले जाने के लिए डिज़ाइन किया गया हो, या किसी भी आकार का वह वाहन जिसका उपयोग 49 CFR 383.5 में परिभाषित खतरनाक सामग्री ले जाने के लिए किया जाता हो। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT)।"},"23":{"q":"विस्कॉन्सिन CDL उद्देश्यों के लिए किसी वाणिज्यिक मोटर वाहन की श्रेणी निर्धारित करते समय, किस मान का उपयोग किया जाना चाहिए?","options":["हमेशा केवल निर्माता का GVWR","GVWR, वास्तविक सकल वजन, या पंजीकृत वजन में से सबसे कम","GVWR, वास्तविक सकल वजन, या पंजीकृत वजन में से सबसे अधिक","खाली होने पर वाहन का curb weight"],"explanation":"विस्कॉन्सिन चालकों को CMV श्रेणी निर्धारित करने के लिए Gross Vehicle Weight Rating, वास्तविक सकल वजन, या पंजीकृत वजन में से सबसे अधिक का उपयोग करने का निर्देश देता है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), 'What CDL do I need?'"},"24":{"q":"ऐसे वाणिज्यिक वाहन को चलाने के लिए जो प्लेकार्डिंग की आवश्यकता वाली मात्रा में खतरनाक सामग्री ले जाता है, विस्कॉन्सिन CDL पर कौन सा एंडोर्समेंट आवश्यक है?","options":["N एंडोर्समेंट","H एंडोर्समेंट","T एंडोर्समेंट","X एंडोर्समेंट"],"explanation":"49 CFR 383.5 के तहत परिभाषित खतरनाक सामग्री के परिवहन के लिए 'H' (HazMat) एंडोर्समेंट आवश्यक है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), एंडोर्समेंट अनुभाग।"},"25":{"q":"कौन सा विस्कॉन्सिन CDL एंडोर्समेंट किसी चालक को ऐसे वाणिज्यिक वाहन को चलाने की अनुमति देता है जो थोक (bulk) में तरल या गैस ढोने के लिए उपयोग किए जाने वाले कार्गो टैंक से सुसज्जित हो?","options":["P एंडोर्समेंट","T एंडोर्समेंट","N एंडोर्समेंट","S एंडोर्समेंट"],"explanation":"थोक में तरल या गैसीय सामग्री ले जाने के लिए कार्गो टैंक से सुसज्जित वाणिज्यिक वाहनों के लिए 'N' (Tank) एंडोर्समेंट आवश्यक है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), एंडोर्समेंट सूची।"},"26":{"q":"विस्कॉन्सिन के टैंक वाहन नियम के तहत, टैंक एंडोर्समेंट परीक्षण ऐसे वाहन के लिए आवश्यक है जो किसी एकल कंटेनर में 119 gallons से अधिक रेटेड क्षमता वाला तरल या गैस ले जाता है और जिसकी कुल रेटेड क्षमता कम से कम कितनी हो?","options":["500 gallons या अधिक","1,000 gallons या अधिक","2,500 gallons या अधिक","3,000 gallons या अधिक"],"explanation":"विस्कॉन्सिन उन वाहनों के लिए Tank Vehicle परीक्षण की आवश्यकता रखता है जो 119 gallons से अधिक रेटेड क्षमता वाले कंटेनर में और 1,000 gallons या अधिक की कुल रेटेड क्षमता के साथ तरल या गैस ले जाते हैं। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), Section 8 / Tank Vehicle परीक्षण।"},"27":{"q":"एक से अधिक ट्रेलर (doubles या triples) खींचने के लिए विस्कॉन्सिन CDL धारक को किस एंडोर्समेंट की आवश्यकता होती है?","options":["T एंडोर्समेंट","N एंडोर्समेंट","H एंडोर्समेंट","P एंडोर्समेंट"],"explanation":"'T' एंडोर्समेंट (Doubles/Triples) किसी चालक को एक से अधिक ट्रेलर खींचने वाले संयोजन वाहनों को चलाने के लिए अधिकृत करता है और इसके लिए Doubles and Triples ज्ञान परीक्षण पास करना आवश्यक है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT)।"},"28":{"q":"एक विस्कॉन्सिन वाणिज्यिक वाहन चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है। उचित CDL श्रेणी के अतिरिक्त कौन सा एंडोर्समेंट आवश्यक है?","options":["S एंडोर्समेंट","P एंडोर्समेंट","N एंडोर्समेंट","T एंडोर्समेंट"],"explanation":"चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए या वास्तव में ले जाने वाले वाहन को चलाने के लिए 'P' (Passenger) एंडोर्समेंट आवश्यक है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), एंडोर्समेंट सूची।"},"29":{"q":"विस्कॉन्सिन स्कूल बस 'S' एंडोर्समेंट के बारे में कौन सा कथन सत्य है?","options":["इसके लिए केवल एक बार का ज्ञान परीक्षण आवश्यक है जो कभी समाप्त नहीं होता","इसके लिए पहली बार जारी होने पर और हर नवीनीकरण पर ज्ञान परीक्षण और ड्राइविंग कौशल परीक्षण दोनों आवश्यक हैं","यह 'P' एंडोर्समेंट रखने वाले किसी भी व्यक्ति को स्वचालित रूप से दिया जाता है","यह केवल Class A CDL पर उपलब्ध है"],"explanation":"विस्कॉन्सिन के लिए आवश्यक है कि स्कूल बस 'S' एंडोर्समेंट आवेदक मूल रूप से जारी होने पर ज्ञान और ड्राइविंग कौशल परीक्षण पास करे, और हर नवीनीकरण पर फिर से परीक्षण (ज्ञान, सड़क संकेत, दृष्टि, संक्षिप्त कौशल) पास करे। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), स्कूल बस एंडोर्समेंट अनुभाग।"},"30":{"q":"intrastate (विस्कॉन्सिन के भीतर) वाणिज्यिक ड्राइविंग के लिए वैध विस्कॉन्सिन CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"intrastate वाणिज्य के लिए विस्कॉन्सिन CDL प्राप्त करने के लिए चालक की आयु कम से कम 18 वर्ष होनी चाहिए। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT) / WisDOT CDL आवश्यकताएँ।"},"31":{"q":"विस्कॉन्सिन और संघीय नियमों के तहत interstate वाणिज्य (राज्य की सीमाओं के पार) में वाणिज्यिक मोटर वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"interstate वाणिज्य में CMV चलाने के लिए, खतरनाक सामग्री ढोने के लिए, और राज्य की सीमाओं के पार यात्रियों को ले जाने के लिए चालक की आयु कम से कम 21 वर्ष होनी चाहिए। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT) / WisDOT CDL आवश्यकताएँ।"},"32":{"q":"विस्कॉन्सिन के Commercial Learner Permit (CLP) नियमों के तहत, CDL कौशल (सड़क) परीक्षण देने की अनुमति मिलने से पहले आपको CLP कितने समय तक रखना होगा?","options":["7 days","14 days","30 days","60 days"],"explanation":"विस्कॉन्सिन (संघीय मानक का पालन करते हुए) के लिए आवश्यक है कि आप कौशल परीक्षण देने से पहले कम से कम 14 days तक CLP रखें। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), Commercial Learner Permit अनुभाग।"},"33":{"q":"नवीनीकरण की आवश्यकता से पहले विस्कॉन्सिन Commercial Learner Permit (CLP) कितने दिनों के लिए वैध होता है?","options":["90 days","180 days","1 year","2 years"],"explanation":"विस्कॉन्सिन CLP 180 days के लिए वैध है और इसका नवीनीकरण किया जा सकता है। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), Commercial Learner Permit अनुभाग / WisDOT CDL आवश्यकताएँ पृष्ठ।"},"34":{"q":"विस्कॉन्सिन Commercial Learner Permit (CLP) के साथ ड्राइविंग करते समय, पर्यवेक्षण करने वाले चालक से क्या आवश्यक है?","options":["यदि CLP धारक 21 वर्ष का है तो किसी पर्यवेक्षण चालक की आवश्यकता नहीं है","एक वैध CDL धारक, जो परमिट की श्रेणी और एंडोर्समेंट स्तर पर या उससे ऊपर हो, उसे CLP धारक के बगल में बैठना चाहिए","16 वर्ष या उससे अधिक उम्र का कोई भी लाइसेंस प्राप्त चालक पीछे की सीट पर बैठ सकता है","हर समय एक WisDOT परीक्षक उपस्थित होना चाहिए"],"explanation":"एक CLP धारक के साथ ऐसा व्यक्ति होना चाहिए जिसके पास परमिट की श्रेणी/एंडोर्समेंट स्तर पर या उससे ऊपर वैध CDL हो, जो आगे CLP धारक के बगल में बैठा हो। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), CLP अनुभाग।"},"35":{"q":"विस्कॉन्सिन HazMat 'H' एंडोर्समेंट के लिए आवेदन या नवीनीकरण करते समय, HazMat ज्ञान परीक्षण पास करने के अलावा आवेदक को किस अतिरिक्त संघीय आवश्यकता को पूरा करना होगा?","options":["प्लेकार्ड वाले वाहन में दूसरा सड़क कौशल परीक्षण","FBI आपराधिक पृष्ठभूमि/खतरा मूल्यांकन जाँच के लिए फिंगरप्रिंटिंग","एक नोटरीकृत नियोक्ता प्रायोजन पत्र","एक ड्रग और अल्कोहल clearinghouse सदस्यता शुल्क"],"explanation":"विस्कॉन्सिन के लिए आवश्यक है कि 'H' एंडोर्समेंट आवेदक FBI आपराधिक पृष्ठभूमि रिकॉर्ड जाँच (TSA सुरक्षा खतरा मूल्यांकन) के लिए फिंगरप्रिंट प्रदान करें और मूल जारी होने पर तथा हर नवीनीकरण पर U.S. नागरिकता या वैध स्थिति का प्रमाण प्रस्तुत करें। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), HazMat 'H' एंडोर्समेंट अनुभाग।"},"36":{"q":"विस्कॉन्सिन HazMat 'H' एंडोर्समेंट के लिए, कुछ अयोग्यता वाले अपराधों के लिए दोषसिद्धि जारी होने पर रोक लगाएगी यदि वह दोषसिद्धि आवेदन तिथि से कितने वर्ष पहले हुई हो?","options":["3 years","5 years","7 years","10 years"],"explanation":"किसी आवेदक को 'H' एंडोर्समेंट प्राप्त करने, नवीनीकृत करने, या स्थानांतरित करने की अनुमति नहीं दी जाएगी यदि आवेदन तिथि से पूर्व 7 years के दौरान कुछ अयोग्यता वाले अपराधों के लिए दोषी ठहराया गया हो (या विक्षिप्तता के कारण निर्दोष पाया गया हो)। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), HazMat अयोग्यताएँ।"},"37":{"q":"विस्कॉन्सिन HazMat 'H' एंडोर्समेंट आवेदक से विशेष रूप से कौन सा दस्तावेज़ या प्रमाण प्रस्तुत करने की आवश्यकता है जो अधिकांश अन्य CDL एंडोर्समेंट के लिए आवश्यक नहीं है?","options":["U.S. में U.S. नागरिकता या वैध स्थिति का प्रमाण","एक हाई स्कूल डिप्लोमा","एक वाणिज्यिक वाहन पट्टा (lease) समझौता","एक मोटर वाहक का USDOT नंबर"],"explanation":"विस्कॉन्सिन के लिए आवश्यक है कि HazMat 'H' आवेदक FBI पृष्ठभूमि जाँच के अलावा, ज्ञान परीक्षण, मूल जारी होने और सभी नवीनीकरणों पर U.S. में U.S. नागरिकता या वैध स्थिति का प्रमाण प्रस्तुत करें। स्रोत: Wisconsin Commercial Driver's Manual (WisDOT), HazMat 'H' एंडोर्समेंट अनुभाग।"},"38":{"q":"विस्कॉन्सिन में Entry-Level Driver Training (ELDT) को कहाँ सूचीबद्ध प्रदाता के माध्यम से पूरा किया जाना चाहिए, और यह पहली बार के CDL आवेदकों और कुछ एंडोर्समेंट के लिए आवश्यक है?","options":["Wisconsin Technical College System रजिस्ट्री","FMCSA Training Provider Registry (TPR)","National Safety Council डेटाबेस","कोई भी DMV-अनुमोदित तृतीय-पक्ष परीक्षक सूची"],"explanation":"ELDT को FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध प्रशिक्षण प्रदाता से प्राप्त किया जाना चाहिए। यह पहली CDL, श्रेणी उन्नयन (B से A), और H, P, तथा S एंडोर्समेंट के लिए आवश्यक है; जिन चालकों की CDL February 7, 2022 से पहले जारी की गई थी, वे छूट प्राप्त हैं। स्रोत: WisDOT CDL आवश्यकताएँ पृष्ठ / Wisconsin Commercial Driver's Manual।"},"39":{"q":"विस्कॉन्सिन के CDL चिकित्सा स्व-प्रमाणन (self-certification) पर, निम्नलिखित में से कौन सा संचालन की चार वैध प्रमाणन श्रेणियों में से एक है?","options":["Interstate Non-Excepted (NI)","Federal Hazmat Certified (FH)","Interstate Suspended (IS)","Commercial Exempt Farm (CF)"],"explanation":"विस्कॉन्सिन की चार CDL स्व-प्रमाणन श्रेणियाँ Interstate Non-Excepted (NI), Interstate Excepted (EI), Intrastate Non-Excepted (NA), और Intrastate Excepted (EA) हैं; NI चालकों को 49 CFR Part 391 चिकित्सा आवश्यकताओं को पूरा करना होगा और एक वैध Fed Med card रखना होगा। स्रोत: WisDOT MV3230 Commercial Driver Certification: Tier of Operation / Fed Med card पृष्ठ।"},"40":{"q":"विस्कॉन्सिन में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर कोई व्यक्ति कानूनी रूप से वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.04","0.08","0.02","0.00"],"explanation":"विस्कॉन्सिन 0.04 या अधिक BAC के साथ CMV चलाने पर रोक लगाता है (Wis. Stat. § 346.63(5); Wisconsin CDL Manual)। CMV में 0.04 तक पहुँचना एक प्रमुख अयोग्यता वाला अपराध है, साधारण (गैर-वाणिज्यिक) वाहनों पर लागू होने वाली 0.08 सीमा के विपरीत।"},"41":{"q":"विस्कॉन्सिन में पहले प्रमुख अपराध के लिए, जैसे कि 0.04 या अधिक BAC के साथ CMV चलाना, CDL कितने समय के लिए अयोग्य घोषित की जाती है?","options":["1 year","60 days","6 months","3 years"],"explanation":"Wisconsin General CDL Disqualifications तालिका (WisDOT) और Wis. Stat. § 343.315 के अनुसार, किसी प्रमुख अपराध के लिए पहली दोषसिद्धि CDL को 1 year के लिए अयोग्य कर देती है। 3-year की अवधि केवल तभी लागू होती है जब चालक प्लेकार्ड वाली खतरनाक सामग्री का परिवहन कर रहा हो।"},"42":{"q":"विस्कॉन्सिन नियमों के तहत, पहला प्रमुख अपराध (जैसे CMV में OWI) किस स्थिति में 1 year के बजाय 3-year CDL अयोग्यता ले आता है?","options":["चालक प्लेकार्ड वाली खतरनाक सामग्री का परिवहन कर रहा था","चालक की आयु 65 वर्ष से अधिक थी","दुर्घटना से संपत्ति को नुकसान हुआ","चालक के पास दो यात्री सवार थे"],"explanation":"WisDOT CDL Disqualifications तालिका और Wis. Stat. § 343.315 पहले प्रमुख-अपराध की अयोग्यता को 1 year से बढ़ाकर 3 years कर देते हैं जब उल्लंघन तब हुआ जब CMV प्लेकार्ड वाली खतरनाक सामग्री का परिवहन कर रहा था।"},"43":{"q":"विस्कॉन्सिन में दूसरे प्रमुख अपराध (उदाहरण के लिए, CMV में दूसरा OWI) के लिए CDL अयोग्यता अवधि क्या है?","options":["आजीवन (Lifetime)","3 years","10 years","5 years"],"explanation":"किसी भी प्रमुख अयोग्यता वाले अपराध के लिए दूसरी दोषसिद्धि के परिणामस्वरूप WisDOT CDL Disqualifications तालिका और Wis. Stat. § 343.315 (49 CFR 383.51 को प्रतिबिंबित करते हुए) के तहत आजीवन CDL अयोग्यता होती है।"},"44":{"q":"विस्कॉन्सिन के Implied Consent कानून के तहत, यदि कोई CMV चालक किसी कानून प्रवर्तन अधिकारी के अल्कोहल या ड्रग्स के लिए रासायनिक परीक्षण कराने के अनुरोध को अस्वीकार करता है तो क्या होता है?","options":["CDL 1 year के लिए अयोग्य हो जाती है (दूसरी बार होने पर आजीवन)","बिना अयोग्यता के एक चेतावनी जारी की जाती है","CDL 60 days के लिए अयोग्य हो जाती है","CDL 6 months के लिए अयोग्य हो जाती है"],"explanation":"अस्वीकृति को एक प्रमुख अपराध माना जाता है: पहली बार होने पर 1-year CDL अयोग्यता और दूसरी बार के लिए आजीवन अयोग्यता (WisDOT CDL Disqualifications तालिका; Wis. Stat. §§ 343.305, 343.315)।"},"45":{"q":"विस्कॉन्सिन के Implied Consent कानून के तहत, अनुरोधित रासायनिक परीक्षण को अस्वीकार करने से चालक का संचालन विशेषाधिकार न्यूनतम कितने समय के लिए रद्द हो जाता है?","options":["1 year","90 days","30 days","6 months"],"explanation":"Wisconsin CDL Manual बताता है कि यदि आप Implied Consent कानून (Wis. Stat. § 343.305) के तहत किसी अधिकारी द्वारा अनुरोधित परीक्षण को अस्वीकार करते हैं, तो आपका संचालन विशेषाधिकार न्यूनतम एक वर्ष के लिए रद्द कर दिया जाएगा, साथ ही अन्य दंड भी होंगे।"},"46":{"q":"विस्कॉन्सिन में 3-year की अवधि के भीतर कितने गंभीर यातायात उल्लंघन 60-day CDL अयोग्यता को ट्रिगर करते हैं?","options":["2","3","4","5"],"explanation":"3 years के भीतर अलग-अलग घटनाओं में दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप 60-day CDL अयोग्यता होती है (WisDOT CDL Disqualifications तालिका; Wis. Stat. § 343.315; 49 CFR 383.51)।"},"47":{"q":"विस्कॉन्सिन में, 3-year की अवधि के भीतर तीन गंभीर यातायात उल्लंघनों के परिणामस्वरूप कितने समय की CDL अयोग्यता होती है?","options":["120 days","60 days","1 year","90 days"],"explanation":"3 years के भीतर तीन गंभीर यातायात उल्लंघन CDL को 120 days के लिए अयोग्य कर देते हैं (WisDOT CDL Disqualifications तालिका; Wis. Stat. § 343.315)। 3 years के भीतर दो उल्लंघन 60 days हैं।"},"48":{"q":"निम्नलिखित में से किसे विस्कॉन्सिन CDL नियमों के तहत एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["सीमा से 15 mph या अधिक तेज गति से चलना","एक पार्किंग उल्लंघन","0.04 या अधिक BAC के साथ चलाना","एक रासायनिक परीक्षण को अस्वीकार करना"],"explanation":"सीमा से 15 mph या अधिक तेज गति से चलना एक गंभीर यातायात उल्लंघन है (WisDOT CDL Disqualifications तालिका)। 0.04 BAC और परीक्षण अस्वीकृति प्रमुख अपराध हैं, गंभीर उल्लंघन नहीं, और पार्किंग टिकट गिनती में नहीं आते।"},"49":{"q":"CDL अयोग्यता उद्देश्यों के लिए निम्नलिखित में से कौन सा विस्कॉन्सिन की गंभीर यातायात उल्लंघनों की सूची में नहीं है?","options":["0.04 या अधिक BAC के साथ CMV चलाना","बहुत पास से पीछे चलना (following too closely)","लापरवाह ड्राइविंग (reckless driving)","अनुचित या अनियमित लेन परिवर्तन"],"explanation":"बहुत पास से पीछे चलना, लापरवाह ड्राइविंग, और अनुचित/अनियमित लेन परिवर्तन गंभीर यातायात उल्लंघन हैं (WisDOT तालिका)। 0.04 या अधिक BAC के साथ चलाना एक प्रमुख अपराध है (1 year / आजीवन), गंभीर उल्लंघन नहीं।"},"50":{"q":"विस्कॉन्सिन में July 1, 2016 से, CMV चलाते समय हाथ में पकड़े जाने वाले मोबाइल फोन के उपयोग के लिए CDL अयोग्य होने से पहले कितनी दोषसिद्धियाँ आवश्यक हैं?","options":["2 या अधिक","1","4 या अधिक","3 या अधिक"],"explanation":"Wisconsin CDL Manual बताता है कि CMV चलाते समय हाथ में पकड़े जाने वाले मोबाइल फोन के उपयोग के लिए दो या अधिक दोषसिद्धियों के बाद CDL अयोग्य हो जाती है: 3 years के भीतर दूसरे अपराध के लिए 60 days और 3 years के भीतर तीन या अधिक के लिए 120 days।"},"51":{"q":"Wisconsin CDL Manual के तहत, ड्राइविंग करते समय टेक्स्टिंग के लिए किसी CMV चालक पर लगाया जा सकने वाला अधिकतम सिविल दंड क्या है?","options":["$2,750","$2,500","$11,000","$5,000"],"explanation":"Wisconsin CDL Manual बताता है कि CMV चलाते समय टेक्स्ट करने वाला चालक प्रति उल्लंघन $2,750 तक के सिविल दंड के अधीन है; जो मोटर वाहक इसकी अनुमति देते हैं या इसकी मांग करते हैं उन्हें $11,000 तक का दंड भुगतना पड़ता है।"},"52":{"q":"Wisconsin CDL Manual के तहत, किसी CMV को चलाते समय अपने चालकों को हाथ में पकड़े जाने वाले फोन का उपयोग करने या टेक्स्ट करने की अनुमति देने या मांग करने के लिए किसी मोटर वाहक को अधिकतम कितना सिविल दंड भुगतना पड़ सकता है?","options":["$11,000","$2,750","$10,000","$5,500"],"explanation":"Wisconsin CDL Manual बताता है कि नियोक्ता (मोटर वाहक) CMV चालकों द्वारा हाथ में पकड़े जाने वाले फोन के उपयोग या टेक्स्टिंग की अनुमति देने या मांग करने के लिए $11,000 तक के सिविल दंड के अधीन हो सकते हैं; चालक का अपना दंड $2,750 तक है।"},"53":{"q":"विस्कॉन्सिन में 3-year की अवधि के भीतर CMV चलाते समय टेक्स्टिंग के लिए दो दोषसिद्धियों के परिणामस्वरूप क्या CDL अयोग्यता होती है?","options":["60 days","120 days","30 days","1 year"],"explanation":"Wisconsin CDL Manual बताता है कि 3 years के भीतर दूसरे टेक्स्टिंग अपराध पर CDL 60 days के लिए अयोग्य हो जाती है, और 3 years के भीतर तीन या अधिक अपराधों के लिए 120 days।"},"54":{"q":"विस्कॉन्सिन में 10 years के भीतर दूसरे out-of-service आदेश उल्लंघन (गैर-hazmat, गैर-यात्री) के लिए CDL अयोग्यता क्या है?","options":["2 years","90 days","1 year","5 years"],"explanation":"WisDOT CDL Disqualifications तालिका के अनुसार, 10 years के भीतर दूसरा out-of-service आदेश उल्लंघन CDL को 2 years के लिए अयोग्य कर देता है (hazmat-प्लेकार्ड या यात्री वाहन होने पर 3 years)।"},"55":{"q":"विस्कॉन्सिन में, रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन (जैसे पटरियाँ साफ न होने पर रुकने में विफलता) की पहली दोषसिद्धि के लिए CDL अयोग्यता क्या है?","options":["60 days","30 days","120 days","90 days"],"explanation":"WisDOT CDL Disqualifications तालिका पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन को 60-day अयोग्यता पर निर्धारित करती है; 3 years के भीतर दूसरा 120 days और 3 years के भीतर तीसरा 1 year है।"},"56":{"q":"विस्कॉन्सिन में 3-year की अवधि के भीतर तीसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन पर कौन सी CDL अयोग्यता लागू होती है?","options":["1 year","120 days","60 days","आजीवन (Lifetime)"],"explanation":"WisDOT CDL Disqualifications तालिका के अनुसार, रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन में 60 days (पहला), 120 days (3 years के भीतर दूसरा), और 1 year (3 years के भीतर तीसरा) होता है।"},"57":{"q":"विस्कॉन्सिन में, किसी नियंत्रित पदार्थ (controlled substance) के निर्माण, वितरण, या वितरण से जुड़े किसी अपराध (felony) को करने में वाणिज्यिक मोटर वाहन का उपयोग करने पर कौन सी CDL अयोग्यता होती है?","options":["आजीवन (Lifetime), बिना किसी पुनर्बहाली के","1 year","3 years","10 years"],"explanation":"WisDOT CDL Disqualifications तालिका और Wis. Stat. § 343.315 के अनुसार, CMV का उपयोग करके किया गया नियंत्रित पदार्थ से जुड़ा कोई अपराध (felony) पहली बार के अपराध के लिए भी एक अपरिवर्तनीय आजीवन अयोग्यता (बिना पुनर्बहाली) में परिणत होता है।"},"58":{"q":"Wisconsin के Move Over कानून के तहत, जब आप किसी टो ट्रक, पुलिस वाहन, या हाईवे रखरखाव वाहन के पास पहुँचते हैं जो चमकती चेतावनी रोशनी के साथ सड़क के किनारे रुका हुआ है और आपकी दिशा में एक से अधिक लेन हैं, तो आपको क्या करना चाहिए?","options":["यदि ऐसा करना सुरक्षित हो तो रुके हुए वाहन से सटी हुई लेन के अलावा किसी अन्य लेन में चले जाएँ","जब तक दूसरे वाहन की रोशनी बंद न हो जाए, तब तक पूरी तरह रुके रहें","निर्धारित गति पर चलते रहें क्योंकि Move Over केवल पुलिस कारों पर लागू होता है","अपना हॉर्न बजाएँ और रुके हुए वाहन के पास से अपनी गति बनाए रखें"],"explanation":"Wisconsin का Move Over कानून (Wis. Stat. s. 346.072) चालकों से यह अपेक्षा करता है कि चमकती रोशनी वाले आपातकालीन, टो, यूटिलिटी, या हाईवे रखरखाव वाहनों के पास पहुँचते समय, यदि लेन बदलना सुरक्षित रूप से किया जा सकता है तो वे वाहन से सटी हुई लेन खाली कर दें। Wisconsin CDL Manual (Section 2.8) और WisDOT कहते हैं कि यह केवल पुलिस पर ही नहीं, बल्कि कानून प्रवर्तन, EMS, अग्निशमन, टो, और सड़क किनारे काम करने वालों पर लागू होता है।"},"59":{"q":"Wisconsin के Move Over कानून के तहत, यदि आप चमकती रोशनी प्रदर्शित कर रहे किसी रुके हुए आपातकालीन या सड़क-किनारे-सेवा वाहन से सुरक्षित रूप से दूर लेन नहीं बदल सकते, तो आपको क्या करना चाहिए?","options":["गति धीमी करें और जब तक आप वाहन के पास से सुरक्षित रूप से न गुजर जाएँ, तब तक सावधानी से आगे बढ़ें","शोल्डर पर पूरी तरह रुक जाएँ और वाहन के जाने का इंतज़ार करें","निर्धारित गति सीमा बनाए रखें क्योंकि लेन बदलना असंभव है","अधिकतम जगह देने के लिए सड़क के विपरीत किनारे पर चले जाएँ"],"explanation":"Wis. Stat. s. 346.072 और Wisconsin CDL Manual (Section 2.8) कहते हैं कि यदि लेन बदलना असुरक्षित है (या आपकी दिशा में केवल एक ही लेन है), तो आपको गति धीमी करनी चाहिए और जब तक आप रुके हुए वाहन के पास से सुरक्षित रूप से न गुजर जाएँ, तब तक सावधानी से आगे बढ़ना चाहिए। रुकने या विपरीत लेन का उपयोग करने की कोई आवश्यकता नहीं है।"},"60":{"q":"Wisconsin में, चमकती लाल चेतावनी रोशनी प्रदर्शित कर रही किसी रुकी हुई स्कूल बस के पास पहुँच रहे वाहन को बस से कम से कम कितनी दूरी पर रुकना चाहिए?","options":["बस से 20 फीट से कम नहीं","बस से 10 फीट से कम नहीं","बस से 50 फीट से कम नहीं","बस से 100 फीट से कम नहीं"],"explanation":"Wisconsin Statute 346.48(1) के अनुसार चमकती लाल चेतावनी रोशनी प्रदर्शित कर रही स्कूल बस के आगे या पीछे से पास आ रहे वाहन के चालक को बस से 20 फीट से कम दूरी पर नहीं रुकना चाहिए और तब तक रुके रहना चाहिए जब तक बस आगे न बढ़ जाए या लाल रोशनी बंद न हो जाए।"},"61":{"q":"Wisconsin कानून के तहत, चमकती लाल चेतावनी रोशनी प्रदर्शित कर रही स्कूल बस के लिए रुकने की आवश्यकता से किसे छूट प्राप्त है?","options":["विभाजित हाईवे पर विपरीत दिशा में चल रहे चालक","बस से 100 फीट के भीतर समान दिशा में चल रहे चालक","किसी भी हाईवे पर अपनी दिशा में दो या अधिक लेन वाले चालक","किसी को छूट नहीं है; हर प्रकार की सड़क पर सभी चालकों को रुकना चाहिए"],"explanation":"Wisconsin Statute 346.48(1) एक अपवाद देता है: रुकने की आवश्यकता उन वाहनों के चालकों पर लागू नहीं होती जो किसी विभाजित (DIVIDED) हाईवे पर विपरीत (OPPOSITE) दिशा में चल रहे हों। अविभाजित सड़कों पर, विपरीत दिशा के यातायात को भी रुकना चाहिए। समान दिशा के यातायात को हमेशा रुकना चाहिए।"},"62":{"q":"Wisconsin में एक स्कूल बस चालक एक रेलमार्ग-हाईवे ग्रेड क्रॉसिंग के पास पहुँचता है जहाँ रुकना आवश्यक है। बस के सामने वाले हिस्से को निकटतम रेल से किस सीमा के भीतर पूरी तरह रुकना चाहिए?","options":["15 फीट से कम नहीं और 50 फीट से अधिक नहीं","5 फीट से कम नहीं और 15 फीट से अधिक नहीं","25 फीट से कम नहीं और 75 फीट से अधिक नहीं","50 फीट से कम नहीं और 100 फीट से अधिक नहीं"],"explanation":"Wisconsin CDL Manual (Sections 2.15 और 4.3.5) के अनुसार बस को रेलमार्ग क्रॉसिंग से पहले 15 और 50 फीट के बीच रुकना चाहिए - निकटतम रेल से 15 फीट से अधिक पास नहीं और 50 फीट से अधिक दूर नहीं - फिर आगे बढ़ने से पहले दोनों दिशाओं में देखना और सुनना चाहिए।"},"63":{"q":"Wisconsin CDL Manual के अनुसार, प्लेकार्ड लगे खतरनाक सामग्री वाले वाहन को रेलमार्ग क्रॉसिंग से पहले 15 से 50 फीट पर रुकना चाहिए। प्लेकार्ड वाले लोड के अलावा, इनमें से किसको खाली होने पर भी रुकना ज़रूरी है?","options":["खतरनाक सामग्री के लिए उपयोग किया गया कार्गो टैंक, चाहे भरा हो या खाली","26,000 पाउंड से अधिक का कोई भी स्ट्रेट ट्रक जो सूखा माल ढो रहा हो","एक फ्लैटबेड जो ठीक से सुरक्षित स्टील कॉइल ढो रहा हो","एक रेफ्रिजरेटेड वैन जो जल्दी खराब होने वाले खाद्य उत्पाद ढो रही हो"],"explanation":"Wisconsin CDL Manual Section 9.6.12 कहता है कि वाहन को निकटतम रेल से पहले 15 से 50 फीट पर रुकना चाहिए यदि उस पर प्लेकार्ड लगा हो, वह किसी भी मात्रा में क्लोरीन ढो रहा हो, या उसमें खतरनाक सामग्री के लिए उपयोग किए गए कार्गो टैंक हों, चाहे भरे हों या खाली। सामान्य सूखे माल या रेफर लोड के लिए रुकना ज़रूरी नहीं है।"},"64":{"q":"यदि आपको अपना वाणिज्यिक वाहन किसी Wisconsin दो-लेन सड़क या अविभाजित हाईवे पर रोकना पड़े, तो आपके आपातकालीन चेतावनी उपकरणों को कितने मिनट के भीतर रखा जाना चाहिए?","options":["10 मिनट के भीतर","2 मिनट के भीतर","15 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"Wisconsin CDL Manual (Section 2.7) कहता है कि यदि आपको किसी सड़क या शोल्डर पर रुकना पड़े, तो आपको रुकने के 10 मिनट के भीतर अपने आपातकालीन चेतावनी उपकरण लगा देने चाहिए।"},"65":{"q":"दोनों दिशाओं में यातायात ले जाने वाली Wisconsin दो-लेन सड़क पर रुके होने पर, CDL Manual आपके तीन परावर्तक त्रिकोण कहाँ रखने को कहता है?","options":["वाहन के 10 फीट के भीतर, और 100 फीट पीछे तथा 100 फीट आगे","केवल वाहन के 10 फीट, 100 फीट, और 200 फीट पीछे","आने वाले यातायात की ओर 50 फीट, 100 फीट, और 500 फीट पर","तीनों वाहन के पिछले बंपर के 25 फीट के भीतर"],"explanation":"Wisconsin CDL Manual (Section 2.7) निर्देश देता है कि दो-लेन/अविभाजित सड़क पर आप एक त्रिकोण वाहन के आगे या पीछे के कोने से 10 फीट के भीतर, एक लगभग 100 फीट पीछे, और एक लगभग 100 फीट आगे, शोल्डर पर या उस लेन में रखें जहाँ आप रुके हैं।"},"66":{"q":"Wisconsin CDL Manual के अनुसार, जब आप किसी एक-तरफ़ा या विभाजित हाईवे पर रुके हों तो तीन चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["आने वाले यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर","वाहन के दोनों ओर 10 फीट, 100 फीट, और 100 फीट पर","आने वाले यातायात की ओर 25 फीट, 100 फीट, और 300 फीट पर","वाहन के पीछे 50 फीट, 150 फीट, और 250 फीट पर"],"explanation":"Wisconsin CDL Manual (Section 2.7) कहता है कि एक-तरफ़ा या विभाजित हाईवे पर आप चेतावनी उपकरणों को आने वाले यातायात की ओर (वाहन के पीछे) 10 फीट, 100 फीट, और 200 फीट पर रखें।"},"67":{"q":"Wisconsin CDL Manual कहता है कि यदि आप किसी पहाड़ी, मोड़, या ऐसी बाधा के पास रुकते हैं जो अन्य चालकों को एक निश्चित दूरी के भीतर आपका वाहन देखने से रोकती है, तो आपको सबसे पीछे वाला त्रिकोण और दूर रखना चाहिए। वह दृश्यता-दूरी का आँकड़ा क्या है?","options":["500 फीट","200 फीट","300 फीट","1,000 फीट"],"explanation":"Wisconsin CDL Manual (Section 2.7) कहता है कि यदि कोई पहाड़ी, मोड़, या अन्य बाधा चालकों को 500 फीट के भीतर आपका वाहन देखने से रोकती है, तो पर्याप्त अग्रिम चेतावनी देने के लिए सबसे पीछे वाला चेतावनी त्रिकोण सड़क पर और पीछे रखें।"},"68":{"q":"इंटरस्टेट प्रणाली का हिस्सा होने वाले किसी ग्रामीण Wisconsin फ्रीवे पर वाणिज्यिक ट्रक के लिए अधिकतम गति सीमा क्या है?","options":["70 मील प्रति घंटा, कारों के समान","26,000 पाउंड से अधिक के सभी ट्रकों के लिए 55 मील प्रति घंटा","65 मील प्रति घंटा, कारों के लिए 70 mph की सीमा से कम","ट्रेलर खींचने वाले किसी भी वाहन के लिए 60 मील प्रति घंटा"],"explanation":"Wis. Stat. s. 346.57(4) के तहत, इंटरस्टेट हाईवे सहित Wisconsin फ्रीवे पर सीमा 70 mph है। Wisconsin ट्रकों के लिए कोई अलग, कम गति सीमा निर्धारित नहीं करता - कुछ पड़ोसी राज्यों के विपरीत - इसलिए ट्रक वहाँ समान निर्धारित 70 mph पर चल सकते हैं जहाँ संकेत हो, बशर्ते मूल सुरक्षित-गति नियम का पालन हो।"},"69":{"q":"क्या Wisconsin कानून सामान्य रूप से इंटरस्टेट हाईवे पर वाणिज्यिक ट्रकों को विशिष्ट लेन तक सीमित रखता है (जैसे उन्हें बाईं लेन से प्रतिबंधित करना)?","options":["कोई राज्यव्यापी केवल-ट्रक लेन प्रतिबंध मौजूद नहीं है; सामान्य 'ओवरटेक करने के अलावा दाएँ रहें' नियम लागू होता है","हाँ, सभी Wisconsin इंटरस्टेट पर ट्रकों को सबसे बाईं लेन से प्रतिबंधित किया गया है","हाँ, जब भी तीन या अधिक लेन हों तो ट्रकों को दाईं लेन में रहना चाहिए","हाँ, 10,000 पाउंड से अधिक के ट्रक राज्यव्यापी रूप से केवल दाईं ओर की दो लेन का उपयोग कर सकते हैं"],"explanation":"Wisconsin में ट्रकों को विशेष लेन तक सीमित करने वाला कोई राज्यव्यापी कानून नहीं है। सामान्य नियम (Wis. Stat. s. 346.05) के अनुसार दाईं ओर चलना और बाईं लेन का उपयोग मुख्यतः ओवरटेक करने के लिए करना ज़रूरी है। विशिष्ट स्थानीय लेन प्रतिबंध संकेत द्वारा लगाए जा सकते हैं, लेकिन कुछ राज्यों की तरह कोई व्यापक इंटरस्टेट ट्रक-लेन प्रतिबंध नहीं है।"},"70":{"q":"Wisconsin CDL Manual में स्कूल बसों और रेलमार्ग पटरियों के बारे में एक राज्य-विशिष्ट टिप्पणी सूचीबद्ध है। कौन सा कथन उस Wisconsin टिप्पणी को दर्शाता है?","options":["Wisconsin में, स्कूल बसों को औद्योगिक स्विचिंग के लिए उपयोग की जाने वाली पटरियों पर रुकना चाहिए","Wisconsin में, स्कूल बसें किसी भी क्रॉसिंग से 10 mph से कम पर चलती हुई गुज़र सकती हैं","Wisconsin में, स्कूल बसें शहर की सीमा के अंदर क्रॉसिंग पर कभी नहीं रुकतीं","Wisconsin में, स्कूल बसें केवल सक्रिय गेट वाले क्रॉसिंग पर रुकती हैं"],"explanation":"Wisconsin CDL Manual (Section 4.3.5) में एक 'Wisconsin Note' है जो कहता है कि Wisconsin में, स्कूल बसों को औद्योगिक स्विचिंग के लिए उपयोग की जाने वाली पटरियों पर रुकना चाहिए - यह सामान्य क्रॉसिंग नियमों से परे एक राज्य-विशिष्ट आवश्यकता है।"},"71":{"q":"Wisconsin CDL Manual के अनुसार, किस प्रकार के क्रॉसिंग पर बस चालक को पूरी तरह रुकने की आवश्यकता नहीं है (लेकिन फिर भी धीमा होकर यातायात की जाँच करनी चाहिए)?","options":["'exempt' या 'abandoned' के रूप में चिह्नित क्रॉसिंग","क्रॉसबक संकेत वाला और बिना गेट का क्रॉसिंग","ग्रामीण क्षेत्र में बहु-पटरी क्रॉसिंग","ऐसा क्रॉसिंग जहाँ चेतावनी की घंटियाँ शांत हों"],"explanation":"Wisconsin CDL Manual (Section 4.3.5) उन स्थानों को सूचीबद्ध करता है जहाँ बस को रुकने की आवश्यकता नहीं है लेकिन धीमा होकर जाँच करनी चाहिए: स्ट्रीटकार क्रॉसिंग, जहाँ कोई अधिकारी या फ्लैगमैन यातायात को निर्देशित करता हो, जब ट्रैफ़िक सिग्नल हरा दिखाता हो, और 'exempt' या 'abandoned' के रूप में चिह्नित क्रॉसिंग पर। इन शर्तों के बिना एक सादा क्रॉसबक होने पर भी बस को रुकना पड़ता है।"},"72":{"q":"Wisconsin में हाईवे पर यात्रा के लिए ओवरसाइज़ परमिट की आवश्यकता होने से पहले अधिकतम वैध वाहन चौड़ाई क्या है?","options":["8 फीट 6 इंच (8.5 फीट)","8 फीट 0 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"Wisconsin की वैध अधिकतम चौड़ाई 8 फीट 6 इंच (8.5 फीट) है; इससे चौड़े लोड के लिए WisDOT की परमिट प्रणाली के माध्यम से ओवरसाइज़ परमिट की आवश्यकता होती है। मानक वैध सीमाएँ हैं: 8.5 फीट चौड़ाई, 13.5 फीट ऊँचाई, सेमीट्रेलर के लिए 53 फीट लंबाई, और 80,000 lbs सकल वज़न।"},"73":{"q":"Wisconsin मौसमी वज़न-प्रतिबंध कार्यक्रम चलाता है जो उसकी जलवायु के लिए विशिष्ट हैं। शीतकालीन 'frozen road declaration' किसकी अनुमति देता है?","options":["नामित सड़कों पर भारी लोड की, जब तक फुटपाथ जमा हुआ और अधिक मज़बूत रहता है","वसंत के पिघलाव के समाप्त होने तक सभी वाणिज्यिक ट्रकों पर पूर्ण प्रतिबंध","गर्मियों के कम यातायात के कारण ट्रकों के लिए उच्च गति सीमाएँ","केवल रात में यात्रा करने वाले लोड के लिए सभी परमिट शुल्क की छूट"],"explanation":"WisDOT के मौसमी वज़न-प्रतिबंध कार्यक्रम Wisconsin की जलवायु का लाभ उठाते हैं: शीतकालीन frozen road declaration (लगभग मध्य-दिसंबर से मार्च की शुरुआत तक) भारी लोड की अनुमति देता है जब जमा हुआ फुटपाथ संरचनात्मक रूप से अधिक मज़बूत होता है, WisDOT के Seasonal Weight Restrictions कार्यक्रम के अनुसार।"},"74":{"q":"Wisconsin के वसंत पिघलाव के दौरान, Class II हाईवे और मौसमी पोस्टेड-रोड कार्यक्रम ट्रक वज़न के साथ क्या करते हैं?","options":["पिघलाव से कमज़ोर हुए फुटपाथ की रक्षा के लिए अनुमेय एक्सल वज़न को कम करते हैं","अनुमेय वज़न को बढ़ाते हैं क्योंकि पिघलती बर्फ सड़कें साफ़ कर देती है","वज़न पर कोई प्रभाव नहीं डालते; वे केवल निर्धारित गति सीमाएँ बदलते हैं","केवल यात्री कारों और मनोरंजन वाहनों पर लागू होते हैं, ट्रकों पर नहीं"],"explanation":"WisDOT के वसंत-पिघलाव कार्यक्रम (Class II सड़कें और मौसमी पोस्टेड सड़कें, लगभग मार्च से मई तक) अनुमेय एक्सल और सकल वज़न को कम करते हैं और कई विभाज्य-लोड परमिट निलंबित कर देते हैं क्योंकि पिघलता फुटपाथ संरचनात्मक रूप से कमज़ोर होता है। लक्ष्य हाईवे का जीवनकाल बढ़ाना है, WisDOT के Seasonal Weight Restrictions कार्यक्रम के अनुसार।"},"75":{"q":"Wisconsin में, जब कोई ओवरसाइज़ लोड इतना चौड़ा हो कि एक सामने वाले एस्कॉर्ट की आवश्यकता हो, तो किस प्रकार का वाहन एस्कॉर्ट के रूप में काम कर सकता है?","options":["एक ऑटोमोबाइल या सिंगल-यूनिट ट्रक जो 16,000 पाउंड से अधिक न हो और जिसमें आवश्यक चेतावनी लैंप हों","झंडे और एम्बर लाइट से सुसज्जित कोई भी मोटरसाइकिल","लोड के ठीक आगे चल रहा एक दूसरा भरा हुआ सेमीट्रेलर","हर मामले में केवल एक चिह्नित कानून-प्रवर्तन पुलिस वाहन"],"explanation":"Wisconsin ओवरसाइज़-परमिट नियमों (WisDOT/Trans code) के तहत, एक एस्कॉर्ट (पायलट) वाहन को एक ऑटोमोबाइल या सिंगल-यूनिट ट्रक होना चाहिए जो 16,000 पाउंड से अधिक न हो, जिसका दृश्य बाधारहित हो, लो-बीम हेडलैंप चालू हों, और परमिट वाले लोड को एस्कॉर्ट करते समय चेतावनी लैंप जलते रहें।"},"76":{"q":"Wisconsin दो-लेन सड़क पर, ओवरटेकिंग को नियंत्रित करने के लिए आमतौर पर रेलमार्ग क्रॉसिंग के साथ कौन सा अतिरिक्त फुटपाथ चिह्न होता है?","options":["पटरियों के पास पहुँचते समय एक नो-पासिंग ज़ोन चिह्न (और एक नो-पासिंग संकेत)","एक धराशायी पीली केंद्र रेखा जो पटरियों से पहले ओवरटेक करने को प्रोत्साहित करती है","एक ठोस सफ़ेद लेन रेखा जो ट्रकों को क्रॉसिंग साझा करने की अनुमति देती है","एक बाइक-लेन पट्टी जो ट्रकों को क्रॉसिंग के सबसे दाईं ओर निर्देशित करती है"],"explanation":"Wisconsin CDL Manual (Section 2.15) बताता है कि दो-लेन सड़कों पर, रेलमार्ग फुटपाथ चिह्नों में 'RR' अक्षरों के साथ एक 'X' और एक नो-पासिंग चिह्न शामिल होता है, और क्रॉसिंग के पास पहुँचते समय एक नो-पासिंग-ज़ोन संकेत भी होता है। यदि कोई सफ़ेद स्टॉप लाइन मौजूद हो, तो रुके होने पर बस का अगला हिस्सा वहीं रहना चाहिए।"},"77":{"q":"एक Wisconsin CDL चालक खराबी के बाद व्यस्त विभाजित फ्रीवे के शोल्डर पर रुकता है। आने वाले यातायात की ओर 10, 100, और 200 फीट पर तीन त्रिकोण रखने के बाद, Wisconsin CDL Manual त्रिकोणों को पकड़ने के बारे में क्या सलाह देता है?","options":["प्रत्येक त्रिकोण को अपने और आने वाले यातायात के बीच पकड़ें ताकि अन्य चालक आपको देख सकें","त्रिकोणों को सिर के ऊपर पकड़ें और यात्रा लेन के बीच में चलें","वाहन से पूरी तरह बाहर निकलने से बचने के लिए त्रिकोणों को केबिन से फेंकें","तीनों को बाईं ओर यातायात प्रवाह से दूर मुँह करके रखें"],"explanation":"Wisconsin CDL Manual (Section 2.7) सलाह देता है कि त्रिकोण रखते समय आप उन्हें अपनी सुरक्षा के लिए अपने और आने वाले यातायात के बीच पकड़ें, ताकि उपकरण लगाते समय आने वाले चालक आपको देख सकें।"},"78":{"q":"Wisconsin में Commercial Driver License (CDL) कौन सी राज्य एजेंसी जारी करती है?","options":["Wisconsin Division of Motor Vehicles (DMV), जो WisDOT का हिस्सा है","Wisconsin State Patrol","Wisconsin Department of Public Safety","Federal Motor Carrier Safety Administration"],"explanation":"Wisconsin CDL को Wisconsin Division of Motor Vehicles (DMV) द्वारा जारी किया जाता है, जो Wisconsin Department of Transportation का एक प्रभाग है। State Patrol मोटर कैरियर कानूनों को लागू करती है लेकिन लाइसेंस जारी नहीं करती, और FMCSA एक संघीय एजेंसी है जो राज्य CDL जारी करने के बजाय मानक निर्धारित करती है। स्रोत: Wisconsin Commercial Driver's Manual; wisconsindot.gov CDL Requirements पृष्ठ।"},"79":{"q":"Wisconsin CDL General Knowledge परीक्षा, जिसमें 50 प्रश्न होते हैं, उत्तीर्ण करने के लिए न्यूनतम कितने सही उत्तरों की आवश्यकता है?","options":["40 सही (80%)","30 सही (60%)","35 सही (70%)","45 सही (90%)"],"explanation":"Wisconsin General Knowledge परीक्षा में 50 प्रश्न होते हैं और आपको कम से कम 40 का सही उत्तर देना होता है, जो 80% का उत्तीर्ण स्कोर है। 80% का मानक Wisconsin में CDL ज्ञान परीक्षाओं पर लागू होता है। स्रोत: Wisconsin Commercial Driver's Manual; wisconsindot.gov CDL Requirements।"},"80":{"q":"Wisconsin Commercial Learner Permit (CLP) कितने समय तक वैध रहता है?","options":["180 दिन","90 दिन","1 वर्ष","60 दिन"],"explanation":"Wisconsin CLP 180 दिनों के लिए वैध होता है और इसमें वे वाहन प्रकार और एंडोर्समेंट सूचीबद्ध होते हैं जिनके लिए धारक योग्य हो चुका है। स्रोत: Wisconsin Commercial Driver's Manual, Commercial Learner Permit (CLP) अनुभाग।"},"81":{"q":"परमिट जारी होने के बाद Wisconsin CLP धारक को CDL कौशल परीक्षा देने की अनुमति मिलने से पहले कितने समय तक प्रतीक्षा करनी चाहिए?","options":["14 दिन","10 दिन","30 दिन","7 दिन"],"explanation":"Wisconsin द्वारा अपनाए गए संघीय नियमों के तहत, कौशल परीक्षा देने की अनुमति मिलने से पहले आपको CLP को कम से कम 14 दिनों तक रखना होगा। स्रोत: Wisconsin Commercial Driver's Manual, Skills testing अनुभाग; 49 CFR 383.25।"},"82":{"q":"Wisconsin CDL कौशल परीक्षा के तीन भाग होते हैं जिन्हें एक निर्धारित क्रम में लिया जाना चाहिए। सही क्रम क्या है?","options":["वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, सड़क-पर ड्राइविंग","सड़क-पर ड्राइविंग, वाहन निरीक्षण, बुनियादी वाहन नियंत्रण","बुनियादी वाहन नियंत्रण, सड़क-पर ड्राइविंग, वाहन निरीक्षण","वाहन निरीक्षण, सड़क-पर ड्राइविंग, बुनियादी वाहन नियंत्रण"],"explanation":"Wisconsin की तीन-भाग वाली कौशल परीक्षा क्रम में ली जानी चाहिए: पहले वाहन निरीक्षण, फिर बुनियादी वाहन नियंत्रण, फिर सड़क-पर ड्राइविंग। स्रोत: Wisconsin Commercial Driver's Manual, Skills tests अनुभाग।"},"83":{"q":"Wisconsin में किसी नए आवेदक के CDL परीक्षा देने के योग्य होने से पहले, कौन सा प्रशिक्षण पूरा किया जाना चाहिए?","options":["किसी FMCSA-पंजीकृत प्रदाता से Entry Level Driver Training (ELDT)","काउंटी द्वारा अनुमोदित एक रक्षात्मक ड्राइविंग पाठ्यक्रम","किसी लाइसेंस प्राप्त कैरियर के अधीन दो-वर्षीय अप्रेंटिसशिप","एक OSHA कार्यस्थल सुरक्षा प्रमाणन"],"explanation":"नए CDL आवेदकों (और वर्ग अपग्रेड करने या कुछ एंडोर्समेंट जोड़ने वालों) को परीक्षा से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry Level Driver Training पूरा करना होगा। स्रोत: Wisconsin Commercial Driver's Manual; 49 CFR Part 380 Subpart F।"},"84":{"q":"Wisconsin CDL आवेदक अपने वाणिज्यिक संचालन के टियर (प्रकार) को स्व-प्रमाणित करने के लिए किस दस्तावेज़ का उपयोग करते हैं?","options":["Form MV3230, Commercial Driver Certification: Tier of Operation","Form MV3001, सामान्य ड्राइवर लाइसेंस आवेदन","Form MV3740, स्कूल बस स्व-प्रमाणन","FMCSA Medical Examination Report (MCSA-5875)"],"explanation":"Wisconsin चालक Form MV3230 पर अपने संचालन के टियर को स्व-प्रमाणित करते हैं। MV3001 सामान्य लाइसेंस आवेदन है, MV3740 स्कूल बस स्व-प्रमाणन है, और MCSA-5875 एक परीक्षक द्वारा पूरी की गई चिकित्सा परीक्षा रिपोर्ट है। स्रोत: wisconsindot.gov Fed Med card पृष्ठ; Form MV3230।"},"85":{"q":"Wisconsin CDL धारक को कितनी स्व-प्रमाणन श्रेणियों (संचालन के टियर) में से चुनना होता है?","options":["चार","दो","तीन","पाँच"],"explanation":"चार स्व-प्रमाणन टियर हैं: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। स्रोत: wisconsindot.gov Fed Med card पृष्ठ; 49 CFR 383.71।"},"86":{"q":"किस Wisconsin स्व-प्रमाणन टियर के लिए चालक को एक वैध Federal medical examiner's certificate (Fed Med card) बनाए रखना आवश्यक है?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","कोई भी चालक जो कभी राज्य की सीमा पार नहीं करता"],"explanation":"Non-Excepted Interstate (NI) चालकों के पास एक वैध Fed Med card होना चाहिए। Excepted Interstate और Excepted Intrastate टियर के लिए इसकी आवश्यकता नहीं है। स्रोत: wisconsindot.gov Fed Med card पृष्ठ; 49 CFR 383.71।"},"87":{"q":"2025 की प्रक्रिया परिवर्तन के अनुसार, DOT physical के बाद किसी Wisconsin चालक की Federal medical examiner's certificate जानकारी आमतौर पर WI DMV तक कैसे पहुँचती है?","options":["FMCSA इसे परीक्षा के लगभग 48 घंटों के भीतर इलेक्ट्रॉनिक रूप से WI DMV को भेजती है","चालक को हमेशा 10 दिनों के भीतर एक कागज़ी प्रति DMV को फैक्स करनी होगी","ट्रकिंग नियोक्ता चालक की ओर से इसे DMV को डाक से भेजता है","यह CDL पर मुद्रित होता है और कभी राज्य को रिपोर्ट नहीं किया जाता"],"explanation":"13 अप्रैल, 2025 से प्रभावी, FMCSA चालक की Fed Med card जानकारी स्वचालित रूप से WI DMV को प्रदान करती है, आमतौर पर DOT physical के 48 घंटों के भीतर। उस तिथि से पहले पूरी की गई परीक्षाओं को चालक द्वारा प्रस्तुत किया जाना था। स्रोत: wisconsindot.gov Fed Med card पृष्ठ।"},"88":{"q":"Wisconsin CDL को कितनी बार नवीनीकृत किया जाना चाहिए?","options":["हर 8 साल में","हर 4 साल में","हर 6 साल में","हर 2 साल में"],"explanation":"Wisconsin CDL को हर 8 साल में नवीनीकृत किया जाना चाहिए। स्रोत: Wisconsin Commercial Driver's Manual; wisconsindot.gov नवीनीकरण जानकारी।"},"89":{"q":"इंट्रास्टेट (Wisconsin के भीतर) वाणिज्यिक ड्राइविंग के लिए Wisconsin CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"इंट्रास्टेट संचालन के लिए Wisconsin CDL/CLP प्राप्त करने के लिए आपकी आयु कम से कम 18 वर्ष होनी चाहिए। इंटरस्टेट वाणिज्य के लिए आमतौर पर कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: Wisconsin Commercial Driver's Manual, Commercial Learner Permit (CLP) अनुभाग।"},"90":{"q":"किस शर्त के तहत Wisconsin में कोई CLP धारक इंटरस्टेट वाणिज्य में वाणिज्यिक वाहन चला सकता है?","options":["केवल तभी जब आयु कम से कम 21 वर्ष हो और एक वैध संघीय चिकित्सा प्रमाणपत्र हो","किसी भी आयु में, क्योंकि CLP पूर्ण इंटरस्टेट अधिकार देता है","केवल CLP को 180 दिनों तक रखने के बाद","केवल स्कूल बस एंडोर्समेंट के साथ"],"explanation":"कोई CLP धारक इंटरस्टेट वाणिज्य में तब तक संचालन नहीं कर सकता जब तक उसकी आयु कम से कम 21 वर्ष न हो और उसके पास वैध Fed Med card न हो। स्रोत: Wisconsin Commercial Driver's Manual, CLP अनुभाग।"},"91":{"q":"कौशल परीक्षा में, Wisconsin आवेदक को तीन में से कितने खंड एक ही CLP पर उत्तीर्ण करने होते हैं?","options":["तीनों खंड एक ही CLP पर उत्तीर्ण किए जाने चाहिए","केवल सड़क-पर खंड एक ही CLP पर होना चाहिए","तीन में से कोई भी दो एक नए CLP पर आगे ले जाए जा सकते हैं","खंड तीन अलग-अलग CLP तक फैलाए जा सकते हैं"],"explanation":"Wisconsin के लिए आवश्यक है कि कौशल परीक्षा के तीनों खंड एक ही CLP पर उत्तीर्ण किए जाएँ। स्रोत: Wisconsin Commercial Driver's Manual, Skills testing अनुभाग।"},"92":{"q":"वर्ग या मांगे गए एंडोर्समेंट की परवाह किए बिना, प्रत्येक Wisconsin CDL आवेदक को कौन सी परीक्षा उत्तीर्ण करनी होती है?","options":["General Knowledge परीक्षा","Air Brakes परीक्षा","Combination Vehicles परीक्षा","Hazardous Materials परीक्षा"],"explanation":"General Knowledge परीक्षा सभी CDL आवेदकों द्वारा ली जाती है; अन्य ज्ञान परीक्षाएँ (air brakes, combination, hazmat, आदि) केवल विशिष्ट वर्गों या एंडोर्समेंट के लिए आवश्यक होती हैं। स्रोत: Wisconsin Commercial Driver's Manual, Knowledge tests अनुभाग।"},"93":{"q":"General Knowledge परीक्षा के अतिरिक्त, Wisconsin CLP/CDL के लिए आवेदन करते समय कौन से दो दस्तावेज़/प्रमाण आवश्यक हैं?","options":["एक वैध Wisconsin ड्राइवर लाइसेंस और नागरिकता या वैध स्थिति का प्रमाण","एक पासपोर्ट और एक नोटरीकृत नियोक्ता पत्र","एक Social Security कार्ड और एक वाहन शीर्षक","एक हाई स्कूल डिप्लोमा और दो चरित्र संदर्भ"],"explanation":"Wisconsin आवेदकों के पास एक वैध Wisconsin ड्राइवर लाइसेंस होना चाहिए और U.S. नागरिकता या कानूनी उपस्थिति का प्रमाण देना होगा, आवेदन (MV3001) और टियर स्व-प्रमाणन (MV3230) के साथ। स्रोत: wisconsindot.gov CDL Requirements; Wisconsin Commercial Driver's Manual।"},"94":{"q":"ऐसा CDL धारक जो अपना Fed Med card समाप्त हो जाने देता है और जिसके पास Wisconsin में फ़ाइल पर कोई वैध चिकित्सा प्रमाणपत्र नहीं है, वह किस प्रकार के संचालन तक सीमित है?","options":["केवल इंट्रास्टेट संचालन (Wisconsin के भीतर)","केवल इंटरस्टेट संचालन","केवल खाली वाहनों का संचालन","किसी भी वाणिज्यिक वाहन का संचालन अनुमत नहीं है"],"explanation":"वैध संघीय चिकित्सा कार्ड के बिना चालक इंट्रास्टेट (राज्य के भीतर) संचालन, या इंट्रास्टेट excepted संचालन तक सीमित होता है, और इंटरस्टेट अधिकार खो देता है। स्रोत: Wisconsin Commercial Driver's Manual, CLP/medical अनुभाग।"},"95":{"q":"Wisconsin DMV परीक्षकों के अलावा, Wisconsin CDL कौशल परीक्षाएँ प्रशासित करने के लिए कौन अधिकृत है?","options":["DMV-अधिकृत तृतीय पक्ष परीक्षक","आवेदक द्वारा चुना गया कोई भी लाइसेंस प्राप्त CDL चालक","FMCSA फ़ील्ड निरीक्षक","काउंटी शेरिफ़ के डिप्टी"],"explanation":"Wisconsin DMV अनुमोदित तृतीय पक्ष परीक्षकों को CDL कौशल परीक्षाएँ प्रशासित करने के लिए अधिकृत करता है; आवेदक समय निर्धारित करने के लिए किसी अधिकृत तृतीय पक्ष परीक्षक से संपर्क करते हैं। स्रोत: Wisconsin Commercial Driver's Manual, skills testing अनुभाग।"},"96":{"q":"Wisconsin कौशल परीक्षा के वाहन निरीक्षण खंड में, आवेदक से क्या करने की आवश्यकता होती है?","options":["वाहन का निरीक्षण करें और परीक्षक को समझाएँ कि क्या जाँचा जा रहा है और क्यों","परीक्षक को वाहन का निरीक्षण करते देखें और एक चेकलिस्ट पर हस्ताक्षर करें","पिछले सप्ताह की किसी मैकेनिक की लिखित निरीक्षण रिपोर्ट जमा करें","सड़क पर वाहन चलाएँ और साथ ही डैशबोर्ड गेज का वर्णन करें"],"explanation":"वाहन निरीक्षण परीक्षा में, आवेदक निरीक्षण करता है और परीक्षक को समझाता है कि क्या निरीक्षण किया जाएगा और क्यों, यह प्रदर्शित करते हुए कि उसे पता है कि वाहन चलाने के लिए सुरक्षित है। स्रोत: Wisconsin Commercial Driver's Manual, Section 2.1 और Section 11M।"},"97":{"q":"Fed Med card जारी करने वाले चिकित्सा परीक्षक और FMCSA National Registry के बीच क्या संबंध है?","options":["परीक्षा FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध किसी चिकित्सा परीक्षक द्वारा की जानी चाहिए","कोई भी लाइसेंस प्राप्त चिकित्सक बिना पंजीकरण के कार्ड जारी कर सकता है","केवल Wisconsin DMV स्टाफ़ चिकित्सक ही परीक्षा कर सकते हैं","कार्ड डाक से भेजी गई प्रश्नावली के बाद सीधे FMCSA द्वारा जारी किया जाता है"],"explanation":"DOT physical FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध किसी चिकित्सा परीक्षक द्वारा किया जाना चाहिए, जो FMCSA Medical Examination Report पूरी करता है और Medical Examiner's Certificate जारी करता है। स्रोत: wisconsindot.gov Fed Med card पृष्ठ; 49 CFR 390.103।"}},"ar":{"0":{"q":"بدون تصريح خاص، ما هو الحد الأقصى للعرض الإجمالي للمركبة وحمولتها على طريق سريع في ولاية ويسكونسن؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"تحظر المادة Wis. Stat. 348.05(1) تشغيل مركبة يتجاوز عرضها الإجمالي 8 أقدام و6 بوصات (102 بوصة) بدون تصريح. وهذا يطابق المعيار الفيدرالي الذي اعتمدته ولاية ويسكونسن."},"1":{"q":"بدون تصريح، ما هو الحد الأقصى القانوني لارتفاع المركبة (بما في ذلك الحمولة) على طريق سريع في ولاية ويسكونسن؟","options":["13 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و0 بوصة","14 قدمًا و6 بوصات"],"explanation":"تحدد المادة Wis. Stat. 348.06(1) الحد الأقصى للارتفاع الإجمالي عند 13 قدمًا و6 بوصات (13 1/2 قدم) بدون تصريح. ويظل السائقون مسؤولين عن الخلوص العلوي الفعلي بغض النظر عن هذا الحد."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي المفروض على طريق سريع في ولاية ويسكونسن بواسطة أي محور واحد بدون تصريح؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","24,000 رطل"],"explanation":"بموجب المادة Wis. Stat. 348.15(3)(b)، لا يجوز أن يتجاوز الوزن الإجمالي على أي محور واحد 20,000 رطل. وهذا مماثل لحد المحور الواحد الفيدرالي."},"3":{"q":"بدون تصريح، ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة محاور مزدوجة على طريق سريع من الفئة \"A\" في ولاية ويسكونسن؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تسمح المادة Wis. Stat. 348.15(3)(d) لمجموعة محاور مزدوجة (مجموعتان متتاليتان) بحمل ما يصل إلى 34,000 رطل، بما يتوافق مع حد المحور المزدوج الفيدرالي."},"4":{"q":"على طريق سريع من الفئة \"A\" في ولاية ويسكونسن، ما هو الحد الأقصى القانوني للوزن الإجمالي للمركبة لتوليفة خماسية المحاور متباعدة بشكل صحيح وتعمل بدون تصريح؟","options":["73,280 رطل","76,000 رطل","80,000 رطل","84,000 رطل"],"explanation":"يحدد جدول وزن مجموعة المحاور في المادة Wis. Stat. 348.15(3)(g)، الذي يطبّق صيغة الجسر الفيدرالية، الحد الأقصى للوزن الإجمالي القانوني عند 80,000 رطل. وتنشر WisDOT 80,000 رطل بوصفه الحد القانوني."},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي الذي تسمح به ولاية ويسكونسن على أي عجلة واحدة، أو عجلات تسند أحد طرفي محور، بدون تصريح؟","options":["9,000 رطل","10,000 رطل","11,000 رطل","13,000 رطل"],"explanation":"تحدّ المادة Wis. Stat. 348.15(3)(a) الوزن الإجمالي على أي عجلة واحدة أو عجلات تسند أحد طرفي محور بمقدار 11,000 رطل."},"6":{"q":"بدون تصريح، ما هو الحد الأقصى للطول الإجمالي لمركبة واحدة على طريق سريع في ولاية ويسكونسن؟","options":["40 قدمًا","45 قدمًا","48 قدمًا","53 قدمًا"],"explanation":"تحدّ المادة Wis. Stat. 348.07(1) المركبة الواحدة بطول إجمالي قدره 45 قدمًا بدون تصريح (ولأدوات الزراعة بدل أعلى منفصل)."},"7":{"q":"بدون تصريح، ما هو الحد الأقصى للطول الإجمالي لتوليفة من مركبتين وحمولة على طريق سريع في ولاية ويسكونسن (حيث ينطبق حد للطول الإجمالي)؟","options":["65 قدمًا","70 قدمًا","75 قدمًا","80 قدمًا"],"explanation":"تحدد المادة Wis. Stat. 348.07(1) الحد العام للطول الإجمالي لتوليفة من مركبتين عند 70 قدمًا، رغم أن بعض توليفات الجرار-نصف المقطورة على الطرق السريعة المخصصة ليس لها حد للطول الإجمالي."},"8":{"q":"على طريق سريع في ولاية ويسكونسن مخصص بموجب القسم s. 348.07(4)، ما هو الحد الأقصى لطول نصف المقطورة الواحدة المشغّلة في توليفة من مركبتين (مع وقوع المسافة من مسمار الارتكاز إلى المحور ضمن الحدود)؟","options":["48 قدمًا","50 قدمًا","53 قدمًا","57 قدمًا"],"explanation":"تسمح المادة Wis. Stat. 348.07(2)(gv) بنصف مقطورة طولها 53 قدمًا (المسافة من مسمار الارتكاز إلى المحور لا تتجاوز 43 قدمًا) في توليفة من مركبتين على الطرق السريعة المخصصة، دون حد للطول الإجمالي للتوليفة."},"9":{"q":"على الطرق السريعة في ولاية ويسكونسن غير المخصصة بموجب القسم s. 348.07(4)، ما هو الحد الأقصى لطول نصف المقطورة أو المقطورة المشغّلة كجزء من توليفة من مركبتين؟","options":["45 قدمًا","48 قدمًا","53 قدمًا","57 قدمًا"],"explanation":"تحدّ المادة Wis. Stat. 348.07(2)(g) نصف المقطورة أو المقطورة بمقدار 48 قدمًا على الطرق السريعة غير المخصصة بموجب القسم s. 348.07(4)؛ ولا ينطبق بدل الـ53 قدمًا إلا على الطرق السريعة المخصصة."},"10":{"q":"ما هو الحد الأقصى للوزن المسموح به على محور التوجيه لجرار الشاحنة في ولاية ويسكونسن عندما لا يسمح تصنيف الشركة المصنّعة بأكثر من ذلك؟","options":["11,000 رطل","12,000 رطل","13,000 رطل","15,000 رطل"],"explanation":"تحدّ المادة Wis. Stat. 348.15(3)(b) محور التوجيه لجرار الشاحنة بمقدار 13,000 رطل، ما لم تكن السعة المصنّفة من الشركة المصنّعة (الإطارات، المحور، إلخ) أعلى، حتى 20,000 رطل."},"11":{"q":"تُحسب حدود الوزن في ولاية ويسكونسن لمجموعات من محورين متتاليين أو أكثر باستخدام أي طريقة؟","options":["حد ثابت قدره 80,000 رطل بغض النظر عن التباعد","صيغة الجسر الفيدرالية / جدول الوزن في القسم s. 348.15(3)(g)","تصنيف GVWR من الشركة المصنّعة فقط","قيمة ثابتة قدرها 34,000 رطل لكل مجموعة محاور"],"explanation":"تحدد المادة Wis. Stat. 348.15(3)(g) الحدود القصوى للأوزان الإجمالية لمجموعات المحاور المتتالية وفقًا لجدول يطبّق صيغة الجسر الفيدرالية، استنادًا إلى تباعد المحاور وعددها."},"12":{"q":"في ولاية ويسكونسن، متى يُطلب عمومًا تصريح من وزارة النقل للأحمال الزائدة الحجم/الوزن (OSOW)؟","options":["فقط للأحمال التي تتجاوز 100,000 رطل","عندما تتجاوز المركبة أو الحمولة حدود الحجم أو الوزن القانونية","فقط للمركبات التي يزيد عرضها عن 10 أقدام","فقط عند السفر على شبكة الطرق السريعة بين الولايات"],"explanation":"بموجب المادة Wis. Stat. ch. 348 وقواعد تصاريح WisDOT، يجب على المركبة أو الحمولة التي تتجاوز حدود الحجم أو الوزن القانونية (العرض أو الارتفاع أو الطول أو الوزن) الحصول على تصريح OSOW قبل التشغيل."},"13":{"q":"يُصرَّح عادةً للحمولة غير القابلة للتجزئة التي تتجاوز الأبعاد القانونية لولاية ويسكونسن لرحلة واحدة بأي نوع من التصاريح؟","options":["تصريح OSOW لرحلة واحدة","ملصق تسجيل المركبة","مصادقة CDL","لوحة مخصصة بموجب IRP"],"explanation":"تصدر WisDOT تصاريح OSOW لرحلة واحدة (النموذج MV2600) للأحمال غير القابلة للتجزئة الزائدة الحجم/الوزن على مسار محدد؛ وتغطي تصاريح الرحلات المتعددة والتصاريح السنوية الحركات المتكررة المؤهِّلة."},"14":{"q":"بموجب تصريح وزن OSOW متعدد الرحلات في ولاية ويسكونسن، يجب أن يكون لتوليفة المركبة كم عدد من المحاور كحد أدنى لتكون مؤهَّلة لبدل الوزن الإجمالي الأعلى؟","options":["أربعة محاور","خمسة محاور","ستة محاور","ثمانية محاور"],"explanation":"تتطلب تصاريح الوزن متعددة الرحلات من WisDOT توليفة من ستة محاور أو أكثر، مع حمل كل محور معدود عمومًا ما لا يقل عن 8 بالمئة من إجمالي الوزن الإجمالي."},"15":{"q":"بموجب تصاريح OSOW في ولاية ويسكونسن للمركبات التي تنقل منتجات الغابات الخام بأوزان أعلى، ما هو الحد الأقصى للوزن الإجمالي المسموح به؟","options":["80,000 رطل","90,000 رطل","98,000 رطل","120,000 رطل"],"explanation":"تسمح تصاريح منتجات الغابات الخام (RS) من WisDOT بحد أقصى للوزن الإجمالي قدره 98,000 رطل مع توليفة من ستة محاور أو أكثر، دون أن يتجاوز أي محور واحد 18,000 رطل."},"16":{"q":"بدون تصريح، ما هو الحد الأقصى للعرض المسموح به لمعظم المركبات التجارية الزراعية على الطرق السريعة في ولاية ويسكونسن بموجب بدل العرض الزراعي؟","options":["8 أقدام و6 بوصات","9 أقدام و6 بوصات","10 أقدام","12 قدمًا"],"explanation":"تسمح المادة Wis. Stat. 348.05(2)(am) لبعض المركبات التجارية الزراعية بعرض يصل إلى 10 أقدام بدون تصريح (مع بدلات أعلى لمعدات محددة مثل الرشاشات)."},"17":{"q":"ينطبق حد الوزن الإجمالي القانوني في ولاية ويسكونسن البالغ 80,000 رطل على الطرق السريعة من الفئة \"A\". كيف يُعامَل الحد على شبكة الطرق السريعة بين الولايات في الولاية؟","options":["لا يوجد للطرق السريعة بين الولايات حد للوزن على الإطلاق","تستخدم الطرق السريعة بين الولايات حدود المحاور وصيغة الجسر نفسها، بحد أقصى قانوني قدره 80,000 رطل","تسمح الطرق السريعة بين الولايات بـ120,000 رطل بدون تصريح","تسمح الطرق السريعة بين الولايات فقط بـ73,280 رطل"],"explanation":"تطبّق ولاية ويسكونسن حدود المحاور وصيغة الجسر الفيدرالية على شبكة الطرق السريعة بين الولايات، مما يعطي الحد الأقصى القانوني نفسه البالغ 80,000 رطل (Wis. Stat. 348.15؛ 23 U.S.C. 127)، لذا لا تزال الأحمال الزائدة الوزن بحاجة إلى تصريح."},"18":{"q":"بموجب تصريح OSOW في ولاية ويسكونسن لنقل منتجات الحليب السائل، يجوز أن يتجاوز الوزن الإجمالي الحد الأقصى المعتاد بما لا يزيد عن أي مقدار؟","options":["10,000 رطل","15,000 رطل","18,000 رطل","25,000 رطل"],"explanation":"تسمح تصاريح منتجات الحليب السائل (FMP) من WisDOT للتوليفات بتجاوز الحد الأقصى للوزن الإجمالي بما لا يزيد عن 18,000 رطل (حتى 98,000 رطل) على توليفة من ستة محاور أو أكثر."},"19":{"q":"يجوز تحميل مجموعة محاور مزدوجة في ولاية ويسكونسن حتى 34,000 رطل فقط إذا كان التباعد بين المحورين الأول والأخير لمجموعتين متتاليتين من المحاور المزدوجة يلبّي أي مسافة دنيا؟","options":["28 قدمًا أو أكثر","30 قدمًا أو أكثر","36 قدمًا أو أكثر","40 قدمًا أو أكثر"],"explanation":"تسمح المادة Wis. Stat. 348.15(3)(d) لكل من مجموعتين متتاليتين من المحاور المزدوجة بحمل 34,000 رطل عندما تكون المسافة بين المحورين الأول والأخير 36 قدمًا أو أكثر."},"20":{"q":"في ولاية ويسكونسن، أي فئة من CDL مطلوبة لتشغيل مركبة توليفية بتصنيف وزن توليفي إجمالي يتجاوز 26,000 رطل ويشمل وحدة مقطورة بتصنيف GVWR يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف ولاية ويسكونسن رخصة CDL من الفئة A بأنها مركبة توليفية بتصنيف GCWR (أو وزن فعلي/مسجل) يتجاوز 26,000 رطل، شاملةً وحدة مقطورة بتصنيف GVWR يتجاوز 10,000 رطل. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، 'ما هي رخصة CDL التي أحتاجها؟'"},"21":{"q":"بموجب قواعد ولاية ويسكونسن، تتطلب شاحنة مستقيمة ثقيلة واحدة بتصنيف GVWR يتجاوز 26,000 رطل وبدون مقطورة (أو بوحدة مقطورة وزنها 10,000 رطل أو أقل) أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","لا يلزم CDL"],"explanation":"تعرّف ولاية ويسكونسن رخصة CDL من الفئة B بأنها مركبة مستقيمة ثقيلة بتصنيف GVWR (أو وزن فعلي/مسجل) يتجاوز 26,000 رطل، بما في ذلك مركبة كهذه تقطر وحدة وزنها 10,000 رطل أو أقل. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)."},"22":{"q":"مركبة صغيرة بتصنيف GVWR قدره 26,000 رطل أو أقل مصممة لحمل 16 شخصًا أو أكثر بما في ذلك السائق. أي فئة من CDL لولاية ويسكونسن تتطلبها؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تعرّف ولاية ويسكونسن رخصة CDL من الفئة C بأنها مركبة بوزن 26,000 رطل أو أقل مصممة لحمل 16 شخصًا أو أكثر (بما في ذلك السائق)، أو من أي حجم تُستخدم لنقل مواد خطرة كما هو معرّف في 49 CFR 383.5. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)."},"23":{"q":"عند تحديد فئة مركبة آلية تجارية لأغراض CDL في ولاية ويسكونسن، أي قيمة يجب استخدامها؟","options":["دائمًا تصنيف GVWR من الشركة المصنّعة فقط","الأدنى من بين GVWR أو الوزن الإجمالي الفعلي أو الوزن المسجل","الأكبر من بين GVWR أو الوزن الإجمالي الفعلي أو الوزن المسجل","وزن المركبة فارغةً (وزن الرصيف)"],"explanation":"توجّه ولاية ويسكونسن السائقين إلى استخدام الأكبر من بين تصنيف الوزن الإجمالي للمركبة أو الوزن الإجمالي الفعلي أو الوزن المسجل لتحديد فئة المركبة الآلية التجارية. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، 'ما هي رخصة CDL التي أحتاجها؟'"},"24":{"q":"أي مصادقة مطلوبة على رخصة CDL في ولاية ويسكونسن لقيادة مركبة تجارية تنقل مواد خطرة بكميات تستلزم وضع لافتات التحذير؟","options":["مصادقة N","مصادقة H","مصادقة T","مصادقة X"],"explanation":"مصادقة 'H' (المواد الخطرة) مطلوبة لنقل المواد الخطرة كما هو معرّف بموجب 49 CFR 383.5. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم المصادقات."},"25":{"q":"أي مصادقة CDL في ولاية ويسكونسن تسمح للسائق بتشغيل مركبة تجارية مزودة بخزان شحن يُستخدم لنقل السوائل أو الغازات بالجملة؟","options":["مصادقة P","مصادقة T","مصادقة N","مصادقة S"],"explanation":"مصادقة 'N' (الخزان) مطلوبة للمركبات التجارية المزودة بخزان شحن لنقل المواد السائلة أو الغازية بالجملة. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قائمة المصادقات."},"26":{"q":"بموجب قاعدة مركبات الخزانات في ولاية ويسكونسن، يُطلب اختبار مصادقة الخزان لمركبة تنقل سائلًا أو غازًا في حاوية فردية بسعة مصنّفة تزيد عن 119 غالونًا وبسعة مصنّفة إجمالية لا تقل عن كم؟","options":["500 غالون أو أكثر","1,000 غالون أو أكثر","2,500 غالون أو أكثر","3,000 غالون أو أكثر"],"explanation":"تتطلب ولاية ويسكونسن اختبار مركبة الخزان للمركبات التي تنقل سوائل أو غازات في حاوية بسعة مصنّفة تزيد عن 119 غالونًا وبسعة مصنّفة إجمالية قدرها 1,000 غالون أو أكثر. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، القسم 8 / اختبار مركبة الخزان."},"27":{"q":"أي مصادقة يحتاجها حامل رخصة CDL في ولاية ويسكونسن لقطر أكثر من مقطورة واحدة (مزدوجة أو ثلاثية)؟","options":["مصادقة T","مصادقة N","مصادقة H","مصادقة P"],"explanation":"تخوّل مصادقة 'T' (المزدوجة/الثلاثية) السائق تشغيل مركبات توليفية تقطر أكثر من مقطورة واحدة وتتطلب اجتياز اختبار المعرفة الخاص بالمزدوجة والثلاثية. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)."},"28":{"q":"مركبة تجارية في ولاية ويسكونسن مصممة لنقل 16 راكبًا أو أكثر بما في ذلك السائق. أي مصادقة مطلوبة بالإضافة إلى فئة CDL المناسبة؟","options":["مصادقة S","مصادقة P","مصادقة N","مصادقة T"],"explanation":"مصادقة 'P' (الركاب) مطلوبة لتشغيل مركبة مصممة لنقل أو تنقل فعليًا 16 راكبًا أو أكثر، بما في ذلك السائق. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قائمة المصادقات."},"29":{"q":"أي عبارة صحيحة بشأن مصادقة الحافلة المدرسية 'S' في ولاية ويسكونسن؟","options":["تتطلب فقط اختبار معرفة لمرة واحدة لا تنتهي صلاحيته أبدًا","تتطلب اختبار معرفة واختبار مهارات قيادة عند الإصدار الأول وعند كل تجديد","تُمنح تلقائيًا لأي شخص يحمل مصادقة 'P'","متوفرة فقط على رخصة CDL من الفئة A"],"explanation":"تتطلب ولاية ويسكونسن من المتقدم لمصادقة الحافلة المدرسية 'S' اجتياز اختبار المعرفة واختبار مهارات القيادة عند الإصدار الأصلي، واجتياز الاختبار (المعرفة وإشارات الطرق والرؤية ومهارات مختصرة) مجددًا عند كل تجديد. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم مصادقة الحافلة المدرسية."},"30":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ولاية ويسكونسن صالحة للقيادة التجارية داخل الولاية (ضمن ويسكونسن)؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"يجب أن يكون عمر السائق 18 عامًا على الأقل للحصول على رخصة CDL في ولاية ويسكونسن للتجارة داخل الولاية. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT) / متطلبات CDL لدى WisDOT."},"31":{"q":"ما هو الحد الأدنى للعمر المطلوب لقيادة مركبة آلية تجارية في التجارة بين الولايات (عبر حدود الولايات) بموجب قواعد ولاية ويسكونسن والقواعد الفيدرالية؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"يجب أن يكون عمر السائق 21 عامًا على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات، ولنقل المواد الخطرة، ولنقل الركاب عبر حدود الولايات. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT) / متطلبات CDL لدى WisDOT."},"32":{"q":"بموجب قواعد تصريح المتعلّم التجاري (CLP) في ولاية ويسكونسن، كم من الوقت يجب أن تحمل CLP قبل أن يُسمح لك بإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["7 أيام","14 يومًا","30 يومًا","60 يومًا"],"explanation":"تتطلب ولاية ويسكونسن (اتباعًا للمعيار الفيدرالي) أن تحمل CLP لمدة 14 يومًا على الأقل قبل إجراء اختبار المهارات. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم تصريح المتعلّم التجاري."},"33":{"q":"لكم عدد من الأيام يكون تصريح المتعلّم التجاري (CLP) في ولاية ويسكونسن صالحًا قبل أن يلزم تجديده؟","options":["90 يومًا","180 يومًا","سنة واحدة","سنتان"],"explanation":"يكون CLP في ولاية ويسكونسن صالحًا لمدة 180 يومًا ويمكن تجديده. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم تصريح المتعلّم التجاري / صفحة متطلبات CDL لدى WisDOT."},"34":{"q":"أثناء القيادة بتصريح المتعلّم التجاري (CLP) في ولاية ويسكونسن، ما المطلوب من السائق المشرف؟","options":["لا يلزم سائق مشرف إذا كان حامل CLP في سن 21","يجب أن يجلس بجانب حامل CLP شخص يحمل CDL صالحة عند مستوى فئة التصريح ومصادقته أو أعلى منه","يجوز لأي سائق مرخّص عمره 16 عامًا أو أكثر الركوب في المقعد الخلفي","يجب أن يكون فاحص WisDOT حاضرًا في جميع الأوقات"],"explanation":"يجب أن يكون حامل CLP مصحوبًا بشخص يحمل CDL صالحة عند مستوى فئة/مصادقة التصريح أو أعلى منه، يجلس بجانب حامل CLP في المقدمة. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم CLP."},"35":{"q":"عند التقدّم للحصول على مصادقة المواد الخطرة 'H' في ولاية ويسكونسن أو تجديدها، أي متطلب فيدرالي إضافي يجب على المتقدم استيفاؤه بخلاف اجتياز اختبار معرفة المواد الخطرة؟","options":["اختبار مهارات طريق ثانٍ في مركبة تحمل لافتات تحذير","أخذ بصمات الأصابع لإجراء فحص الخلفية الجنائية/تقييم التهديد لدى مكتب التحقيقات الفيدرالي (FBI)","خطاب رعاية موثّق من صاحب العمل","رسم اشتراك في مركز تبادل بيانات المخدرات والكحول"],"explanation":"تتطلب ولاية ويسكونسن من المتقدمين لمصادقة 'H' تقديم بصمات الأصابع لإجراء فحص سجلات الخلفية الجنائية لدى FBI (تقييم التهديد الأمني لدى TSA) وتقديم إثبات الجنسية الأمريكية أو الوضع القانوني، عند الإصدار الأصلي وكل تجديد. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم مصادقة المواد الخطرة 'H'."},"36":{"q":"بالنسبة لمصادقة المواد الخطرة 'H' في ولاية ويسكونسن، ستمنع الإدانة ببعض الجرائم المُسقِطة للأهلية الإصدارَ إذا وقعت الإدانة خلال كم عدد من السنوات قبل تاريخ التقديم؟","options":["3 سنوات","5 سنوات","7 سنوات","10 سنوات"],"explanation":"لن يُسمح للمتقدم بالحصول على مصادقة 'H' أو تجديدها أو نقلها إذا أُدين (أو وُجد غير مذنب بسبب الجنون) ببعض الجرائم المُسقِطة للأهلية خلال السنوات الـ7 السابقة لتاريخ التقديم. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، حالات إسقاط أهلية المواد الخطرة."},"37":{"q":"أي مستند أو إثبات تتطلبه ولاية ويسكونسن تحديدًا من المتقدم لمصادقة المواد الخطرة 'H' وهو غير مطلوب لمعظم مصادقات CDL الأخرى؟","options":["إثبات الجنسية الأمريكية أو الوضع القانوني في الولايات المتحدة","شهادة الثانوية العامة","اتفاقية تأجير مركبة تجارية","رقم USDOT لناقل آلي"],"explanation":"تتطلب ولاية ويسكونسن من المتقدمين لمصادقة المواد الخطرة 'H' تقديم إثبات الجنسية الأمريكية أو الوضع القانوني في الولايات المتحدة عند اختبار المعرفة والإصدار الأصلي وجميع التجديدات، بالإضافة إلى فحص الخلفية لدى FBI. المصدر: دليل السائق التجاري لولاية ويسكونسن (WisDOT)، قسم مصادقة المواد الخطرة 'H'."},"38":{"q":"يجب إكمال تدريب السائق المبتدئ (ELDT) في ولاية ويسكونسن من خلال مزوّد مدرج أين، وهو مطلوب للمتقدمين لرخصة CDL لأول مرة ولبعض المصادقات؟","options":["سجل نظام كليات ويسكونسن التقنية","سجل مزوّدي التدريب لدى FMCSA (TPR)","قاعدة بيانات مجلس السلامة الوطني","أي قائمة فاحصين خارجيين معتمدين من DMV"],"explanation":"يجب الحصول على ELDT من مزوّد تدريب مدرج في سجل مزوّدي التدريب لدى FMCSA (tpr.fmcsa.dot.gov). وهو مطلوب لأول رخصة CDL، ولترقية الفئة (من B إلى A)، ولمصادقات H وP وS؛ ويُعفى السائقون الذين صدرت رخصة CDL الخاصة بهم قبل 7 فبراير 2022. المصدر: صفحة متطلبات CDL لدى WisDOT / دليل السائق التجاري لولاية ويسكونسن."},"39":{"q":"في الإقرار الطبي الذاتي لرخصة CDL في ولاية ويسكونسن، أي مما يلي يُعد إحدى فئات الإقرار الأربع الصالحة لنوع التشغيل؟","options":["التشغيل بين الولايات غير المستثنى (NI)","معتمد فيدراليًا للمواد الخطرة (FH)","معلّق بين الولايات (IS)","مزرعة تجارية معفاة (CF)"],"explanation":"فئات الإقرار الذاتي الأربع لرخصة CDL في ولاية ويسكونسن هي: التشغيل بين الولايات غير المستثنى (NI)، والتشغيل بين الولايات المستثنى (EI)، والتشغيل داخل الولاية غير المستثنى (NA)، والتشغيل داخل الولاية المستثنى (EA)؛ ويجب على سائقي NI استيفاء المتطلبات الطبية في 49 CFR Part 391 وحمل بطاقة Fed Med صالحة. المصدر: نموذج WisDOT MV3230 إقرار السائق التجاري: مستوى التشغيل / صفحة بطاقة Fed Med."},"40":{"q":"في ولاية ويسكونسن، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونيًا تشغيل مركبة آلية تجارية (CMV)؟","options":["0.04","0.08","0.02","0.00"],"explanation":"تحظر ولاية ويسكونسن تشغيل مركبة آلية تجارية بتركيز كحول في الدم BAC قدره 0.04 أو أكثر (Wis. Stat. § 346.63(5)؛ دليل CDL لولاية ويسكونسن). وبلوغ 0.04 في مركبة آلية تجارية هو مخالفة رئيسية مُسقِطة للأهلية، خلافًا لحد الـ0.08 الذي ينطبق على المركبات العادية (غير التجارية)."},"41":{"q":"كم مدة إسقاط أهلية CDL في ولاية ويسكونسن عن مخالفة رئيسية أولى، مثل تشغيل مركبة آلية تجارية بتركيز كحول في الدم BAC قدره 0.04 أو أكثر؟","options":["سنة واحدة","60 يومًا","6 أشهر","3 سنوات"],"explanation":"بحسب جدول إسقاطات أهلية CDL العامة في ولاية ويسكونسن (WisDOT) والمادة Wis. Stat. § 343.315، تؤدي الإدانة الأولى بمخالفة رئيسية إلى إسقاط أهلية CDL لمدة سنة واحدة. ولا تنطبق مدة الـ3 سنوات إلا عندما يكون السائق ينقل مواد خطرة تحمل لافتات تحذير."},"42":{"q":"بموجب قواعد ولاية ويسكونسن، تحمل مخالفة رئيسية أولى (مثل القيادة تحت تأثير الكحول OWI في مركبة آلية تجارية) إسقاط أهلية CDL لمدة 3 سنوات بدلًا من سنة واحدة بموجب أي شرط؟","options":["كان السائق ينقل مواد خطرة تحمل لافتات تحذير","كان عمر السائق فوق 65 عامًا","تسبب الحادث في أضرار بالممتلكات","كان لدى السائق راكبان على متن المركبة"],"explanation":"يرفع جدول إسقاطات أهلية CDL لدى WisDOT والمادة Wis. Stat. § 343.315 إسقاطَ الأهلية عن مخالفة رئيسية أولى من سنة واحدة إلى 3 سنوات عندما تقع المخالفة بينما كانت المركبة الآلية التجارية تنقل مواد خطرة تحمل لافتات تحذير."},"43":{"q":"ما هي مدة إسقاط أهلية CDL في ولاية ويسكونسن عن مخالفة رئيسية ثانية (على سبيل المثال، قيادة ثانية تحت تأثير الكحول OWI في مركبة آلية تجارية)؟","options":["مدى الحياة","3 سنوات","10 سنوات","5 سنوات"],"explanation":"تؤدي الإدانة الثانية بأي مخالفة رئيسية مُسقِطة للأهلية إلى إسقاط أهلية CDL مدى الحياة بموجب جدول إسقاطات أهلية CDL لدى WisDOT والمادة Wis. Stat. § 343.315 (بما يعكس 49 CFR 383.51)."},"44":{"q":"بموجب قانون الموافقة الضمنية في ولاية ويسكونسن، ماذا يحدث إذا رفض سائق مركبة آلية تجارية طلب ضابط إنفاذ القانون بالخضوع لفحص كيميائي للكحول أو المخدرات؟","options":["تُسقَط أهلية CDL لمدة سنة واحدة (مدى الحياة عند تكرارها مرة ثانية)","يصدر تحذير دون إسقاط للأهلية","تُسقَط أهلية CDL لمدة 60 يومًا","تُسقَط أهلية CDL لمدة 6 أشهر"],"explanation":"يُعامَل الرفض كمخالفة رئيسية: إسقاط أهلية CDL لمدة سنة واحدة عن الحدوث الأول، وإسقاط مدى الحياة عن الحدوث الثاني (جدول إسقاطات أهلية CDL لدى WisDOT؛ Wis. Stat. §§ 343.305, 343.315)."},"45":{"q":"بموجب قانون الموافقة الضمنية في ولاية ويسكونسن، يؤدي رفض فحص كيميائي مطلوب إلى إلغاء امتياز القيادة لدى السائق لمدة لا تقل عن كم؟","options":["سنة واحدة","90 يومًا","30 يومًا","6 أشهر"],"explanation":"ينص دليل CDL لولاية ويسكونسن على أنك إذا رفضت فحصًا يطلبه ضابط بموجب قانون الموافقة الضمنية (Wis. Stat. § 343.305)، فسيُلغى امتياز قيادتك لمدة لا تقل عن سنة واحدة، إضافةً إلى عقوبات أخرى."},"46":{"q":"كم عدد المخالفات المرورية الجسيمة خلال فترة 3 سنوات التي تؤدي إلى إسقاط أهلية CDL لمدة 60 يومًا في ولاية ويسكونسن؟","options":["2","3","4","5"],"explanation":"تؤدي مخالفتان مروريتان جسيمتان في حادثتين منفصلتين خلال 3 سنوات إلى إسقاط أهلية CDL لمدة 60 يومًا (جدول إسقاطات أهلية CDL لدى WisDOT؛ Wis. Stat. § 343.315؛ 49 CFR 383.51)."},"47":{"q":"في ولاية ويسكونسن، تؤدي ثلاث مخالفات مرورية جسيمة خلال فترة 3 سنوات إلى إسقاط أهلية CDL لمدة كم؟","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية جسيمة خلال 3 سنوات إلى إسقاط أهلية CDL لمدة 120 يومًا (جدول إسقاطات أهلية CDL لدى WisDOT؛ Wis. Stat. § 343.315). ومخالفتان خلال 3 سنوات تساوي 60 يومًا."},"48":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية جسيمة بموجب قواعد CDL في ولاية ويسكونسن؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد","مخالفة وقوف","التشغيل بتركيز كحول في الدم BAC قدره 0.04 أو أكثر","رفض فحص كيميائي"],"explanation":"تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد هو مخالفة مرورية جسيمة (جدول إسقاطات أهلية CDL لدى WisDOT). وتركيز كحول قدره 0.04 ورفض الفحص هما مخالفتان رئيسيتان، وليستا مخالفتين جسيمتين، ولا تُحتسب مخالفات الوقوف."},"49":{"q":"أي مما يلي ليس مدرجًا في قائمة ولاية ويسكونسن للمخالفات المرورية الجسيمة لأغراض إسقاط أهلية CDL؟","options":["تشغيل مركبة آلية تجارية بتركيز كحول في الدم BAC قدره 0.04 أو أكثر","السير على مسافة قريبة جدًا (عدم ترك مسافة كافية)","القيادة المتهورة","تغيير المسار بشكل غير سليم أو متقطع"],"explanation":"السير على مسافة قريبة جدًا، والقيادة المتهورة، وتغيير المسار غير السليم/المتقطع هي مخالفات مرورية جسيمة (جدول WisDOT). والتشغيل بتركيز كحول في الدم BAC قدره 0.04 أو أكثر هو مخالفة رئيسية (سنة واحدة / مدى الحياة)، وليست مخالفة جسيمة."},"50":{"q":"منذ 1 يوليو 2016، في ولاية ويسكونسن، كم عدد الإدانات باستخدام هاتف محمول يدوي أثناء تشغيل مركبة آلية تجارية المطلوبة قبل إسقاط أهلية CDL؟","options":["2 أو أكثر","1","4 أو أكثر","3 أو أكثر"],"explanation":"ينص دليل CDL لولاية ويسكونسن على إسقاط أهلية CDL بعد إدانتين أو أكثر باستخدام الهاتف المحمول اليدوي أثناء تشغيل مركبة آلية تجارية: 60 يومًا عن المخالفة الثانية خلال 3 سنوات و120 يومًا عن ثلاث أو أكثر خلال 3 سنوات."},"51":{"q":"بموجب دليل CDL لولاية ويسكونسن، ما هو الحد الأقصى للغرامة المدنية التي يجوز فرضها على سائق مركبة آلية تجارية بسبب إرسال الرسائل النصية أثناء القيادة؟","options":["$2,750","$2,500","$11,000","$5,000"],"explanation":"ينص دليل CDL لولاية ويسكونسن على أن السائق الذي يرسل رسائل نصية أثناء تشغيل مركبة آلية تجارية يخضع لغرامات مدنية تصل إلى $2,750 عن كل مخالفة؛ والناقلون الآليون الذين يسمحون بذلك أو يفرضونه يواجهون غرامات تصل إلى $11,000."},"52":{"q":"بموجب دليل CDL لولاية ويسكونسن، ما هو الحد الأقصى للغرامة المدنية التي قد يواجهها ناقل آلي بسبب السماح لسائقيه باستخدام هاتف يدوي أو إرسال رسائل نصية أثناء قيادة مركبة آلية تجارية أو فرض ذلك عليهم؟","options":["$11,000","$2,750","$10,000","$5,500"],"explanation":"ينص دليل CDL لولاية ويسكونسن على أن أصحاب العمل (الناقلين الآليين) قد يخضعون لغرامات مدنية تصل إلى $11,000 بسبب السماح باستخدام الهاتف اليدوي أو إرسال الرسائل النصية من قبل سائقي المركبات الآلية التجارية أو فرض ذلك؛ وغرامة السائق نفسه تصل إلى $2,750."},"53":{"q":"تؤدي إدانتان بإرسال الرسائل النصية أثناء تشغيل مركبة آلية تجارية خلال فترة 3 سنوات إلى أي إسقاط لأهلية CDL في ولاية ويسكونسن؟","options":["60 يومًا","120 يومًا","30 يومًا","سنة واحدة"],"explanation":"ينص دليل CDL لولاية ويسكونسن على إسقاط أهلية CDL لمدة 60 يومًا عن مخالفة الرسائل النصية الثانية خلال 3 سنوات، و120 يومًا عن ثلاث مخالفات أو أكثر خلال 3 سنوات."},"54":{"q":"ما هو إسقاط أهلية CDL في ولاية ويسكونسن عن مخالفة أمر إخراج من الخدمة ثانية خلال 10 سنوات (لا مواد خطرة، لا ركاب)؟","options":["سنتان","90 يومًا","سنة واحدة","5 سنوات"],"explanation":"بحسب جدول إسقاطات أهلية CDL لدى WisDOT، تؤدي مخالفة أمر إخراج من الخدمة الثانية خلال 10 سنوات إلى إسقاط أهلية CDL لمدة سنتين (3 سنوات في حال المواد الخطرة التي تحمل لافتات تحذير أو مركبة ركاب)."},"55":{"q":"في ولاية ويسكونسن، ما هو إسقاط أهلية CDL عن إدانة أولى بمخالفة عند تقاطع سكة حديد مع طريق سريع (مثل عدم التوقف عندما لا تكون القضبان خالية)؟","options":["60 يومًا","30 يومًا","120 يومًا","90 يومًا"],"explanation":"يحدد جدول إسقاطات أهلية CDL لدى WisDOT مخالفة تقاطع سكة حديد مع طريق سريع الأولى عند إسقاط أهلية لمدة 60 يومًا؛ والثانية خلال 3 سنوات 120 يومًا والثالثة خلال 3 سنوات سنة واحدة."},"56":{"q":"ما إسقاط أهلية CDL الذي ينطبق في ولاية ويسكونسن على مخالفة ثالثة عند تقاطع سكة حديد مع طريق سريع خلال فترة 3 سنوات؟","options":["سنة واحدة","120 يومًا","60 يومًا","مدى الحياة"],"explanation":"بحسب جدول إسقاطات أهلية CDL لدى WisDOT، تحمل مخالفات تقاطع سكة حديد مع طريق سريع 60 يومًا (الأولى)، و120 يومًا (الثانية خلال 3 سنوات)، وسنة واحدة (الثالثة خلال 3 سنوات)."},"57":{"q":"في ولاية ويسكونسن، يؤدي استخدام مركبة آلية تجارية في ارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها إلى أي إسقاط لأهلية CDL؟","options":["مدى الحياة، دون إعادة إصدار","سنة واحدة","3 سنوات","10 سنوات"],"explanation":"بحسب جدول إسقاطات أهلية CDL لدى WisDOT والمادة Wis. Stat. § 343.315، تؤدي جناية تتعلق بمادة خاضعة للرقابة مرتكبة باستخدام مركبة آلية تجارية إلى إسقاط أهلية مدى الحياة غير قابل للتغيير (دون إعادة إصدار)، حتى عن مخالفة أولى."},"58":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية ويسكونسن، عندما تقترب من شاحنة قطر أو سيارة شرطة أو مركبة صيانة طرق متوقفة على جانب الطريق وأضواء التحذير الوامضة مضاءة، وكان هناك أكثر من حارة في اتجاهك، فماذا يجب عليك أن تفعل؟","options":["الانتقال إلى حارة ليست بجوار المركبة المتوقفة إذا كان من الآمن فعل ذلك","التوقف توقفًا تامًا حتى تُطفأ أضواء المركبة الأخرى","المتابعة بالسرعة المحددة لأن قانون \"أفسح الطريق\" يشمل سيارات الشرطة فقط","إطلاق بوق سيارتك والحفاظ على سرعتك أثناء تجاوز المركبة المتوقفة"],"explanation":"يقتضي قانون \"أفسح الطريق\" في ولاية ويسكونسن (Wis. Stat. s. 346.072) من السائقين الذين يقتربون من مركبات الطوارئ أو القطر أو المرافق أو صيانة الطرق ذات الأضواء الوامضة إخلاء الحارة الأقرب إلى المركبة بالانتقال إلى حارة أخرى، إذا كان تغيير الحارة ممكنًا بأمان. ويذكر دليل CDL لولاية ويسكونسن (القسم 2.8) و WisDOT أن هذا ينطبق على إنفاذ القانون والإسعاف والإطفاء والقطر وعمال جانب الطريق، وليس على الشرطة فقط."},"59":{"q":"بموجب قانون \"أفسح الطريق\" في ولاية ويسكونسن، ماذا يجب عليك أن تفعل إذا لم تتمكن من تغيير الحارة بأمان للابتعاد عن مركبة طوارئ أو خدمة على جانب الطريق متوقفة وأضواؤها الوامضة مضاءة؟","options":["أبطئ السرعة وتابع بحذر حتى تتجاوز المركبة بأمان","توقف توقفًا تامًا على الكتف وانتظر حتى تغادر المركبة","حافظ على السرعة القصوى المحددة بما أن الانتقال إلى حارة أخرى مستحيل","انتقل إلى الجانب المقابل من الطريق لإعطاء أقصى مسافة فاصلة"],"explanation":"ينص (Wis. Stat. s. 346.072) ودليل CDL لولاية ويسكونسن (القسم 2.8) على أنه إذا كان تغيير الحارة غير آمن (أو إذا كانت هناك حارة واحدة فقط في اتجاهك)، فيجب عليك إبطاء السرعة والمتابعة بحذر حتى تتجاوز المركبة المتوقفة بأمان. ولا يوجد ما يقتضي التوقف أو استخدام الحارة المقابلة."},"60":{"q":"في ولاية ويسكونسن، يجب على مركبة تقترب من حافلة مدرسية متوقفة وأضواء التحذير الحمراء الوامضة مضاءة أن تتوقف على أي مسافة دنيا من الحافلة؟","options":["على مسافة لا تقل عن 20 قدمًا من الحافلة","على مسافة لا تقل عن 10 أقدام من الحافلة","على مسافة لا تقل عن 50 قدمًا من الحافلة","على مسافة لا تقل عن 100 قدم من الحافلة"],"explanation":"يقتضي قانون ولاية ويسكونسن 346.48(1) من سائق المركبة المقتربة من أمام أو خلف حافلة مدرسية وأضواء التحذير الحمراء الوامضة مضاءة أن يتوقف على مسافة لا تقل عن 20 قدمًا من الحافلة وأن يبقى متوقفًا حتى تتحرك الحافلة أو تُطفأ الأضواء الحمراء."},"61":{"q":"بموجب قانون ولاية ويسكونسن، مَن المُعفى من اشتراط التوقف لحافلة مدرسية تكون أضواء التحذير الحمراء الوامضة فيها مضاءة؟","options":["السائقون المتجهون في الاتجاه المعاكس على طريق سريع مقسوم","السائقون المتجهون في الاتجاه نفسه على مسافة 100 قدم من الحافلة","السائقون على أي طريق سريع به حارتان أو أكثر في اتجاههم","لا أحد مُعفى؛ يجب على جميع السائقين التوقف على كل أنواع الطرق"],"explanation":"ينص قانون ولاية ويسكونسن 346.48(1) على استثناء واحد: لا ينطبق اشتراط التوقف على سائقي المركبات المتجهين في الاتجاه المعاكس على طريق سريع مقسوم. أما على الطرق غير المقسومة فيجب على حركة المرور المقابلة التوقف. ويجب على حركة المرور في الاتجاه نفسه التوقف دائمًا."},"62":{"q":"يقترب سائق حافلة مدرسية في ولاية ويسكونسن من تقاطع سكة حديد مع الطريق يُشترط التوقف عنده. يجب أن تتوقف مقدمة الحافلة توقفًا تامًا ضمن أي مدى من أقرب قضيب؟","options":["على مسافة لا تقل عن 15 قدمًا ولا تزيد على 50 قدمًا","على مسافة لا تقل عن 5 أقدام ولا تزيد على 15 قدمًا","على مسافة لا تقل عن 25 قدمًا ولا تزيد على 75 قدمًا","على مسافة لا تقل عن 50 قدمًا ولا تزيد على 100 قدم"],"explanation":"يقتضي دليل CDL لولاية ويسكونسن (القسمان 2.15 و 4.3.5) من الحافلة أن تتوقف بين 15 و 50 قدمًا قبل تقاطع السكة الحديدية - على مسافة لا تقل عن 15 قدمًا ولا تزيد على 50 قدمًا من أقرب قضيب - ثم النظر والإصغاء في الاتجاهين قبل المتابعة."},"63":{"q":"وفقًا لدليل CDL لولاية ويسكونسن، يجب على مركبة مواد خطرة تحمل لوحات تحذير (placards) أن تتوقف على مسافة 15 إلى 50 قدمًا قبل تقاطع السكة الحديدية. وإلى جانب الحمولات التي تحمل لوحات تحذير، أيٌّ مما يلي يقتضي التوقف أيضًا حتى عندما تكون فارغة؟","options":["خزان شحن يُستخدم للمواد الخطرة، سواء كان محمَّلًا أو فارغًا","أي شاحنة مفردة يزيد وزنها على 26,000 رطل تنقل بضائع جافة","شاحنة مسطحة تنقل لفائف فولاذية مؤمَّنة بشكل صحيح","شاحنة مبرَّدة تنقل منتجات غذائية قابلة للتلف"],"explanation":"ينص القسم 9.6.12 من دليل CDL لولاية ويسكونسن على أن المركبة يجب أن تتوقف على مسافة 15 إلى 50 قدمًا قبل أقرب قضيب إذا كانت تحمل لوحات تحذير، أو تنقل أي كمية من الكلور، أو إذا كانت لديها خزانات شحن تُستخدم للمواد الخطرة سواء كانت محمَّلة أو فارغة. أما حمولات البضائع الجافة أو المبرَّدة العادية فلا تقتضي التوقف."},"64":{"q":"إذا اضطررت إلى إيقاف مركبتك التجارية على طريق ذي حارتين أو طريق سريع غير مقسوم في ولاية ويسكونسن، ففي غضون كم دقيقة يجب وضع أجهزة التحذير من الطوارئ؟","options":["في غضون 10 دقائق","في غضون دقيقتين","في غضون 15 دقيقة","في غضون 30 دقيقة"],"explanation":"ينص دليل CDL لولاية ويسكونسن (القسم 2.7) على أنه إذا اضطررت إلى التوقف على طريق أو على كتفه، فيجب عليك وضع أجهزة التحذير من الطوارئ في غضون 10 دقائق من التوقف."},"65":{"q":"عند التوقف على طريق ذي حارتين في ولاية ويسكونسن يحمل حركة المرور في الاتجاهين، أين يقول الدليل بوضع المثلثات العاكسة الثلاثة؟","options":["ضمن مسافة 10 أقدام من المركبة، و 100 قدم خلفها و 100 قدم أمامها","على مسافة 10 أقدام و 100 قدم و 200 قدم خلف المركبة فقط","على مسافة 50 قدمًا و 100 قدم و 500 قدم باتجاه حركة المرور المقتربة","جميعها الثلاثة ضمن مسافة 25 قدمًا من المصد الخلفي للمركبة"],"explanation":"يوجِّه دليل CDL لولاية ويسكونسن (القسم 2.7) إلى أنه على طريق ذي حارتين/غير مقسوم تضع مثلثًا واحدًا ضمن مسافة 10 أقدام من الزاوية الأمامية أو الخلفية للمركبة، ومثلثًا على بُعد نحو 100 قدم خلفها، ومثلثًا على بُعد نحو 100 قدم أمامها، على الكتف أو في الحارة التي توقفت فيها."},"66":{"q":"وفقًا لدليل CDL لولاية ويسكونسن، أين ينبغي وضع مثلثات التحذير الثلاثة عند التوقف على طريق سريع باتجاه واحد أو مقسوم؟","options":["على مسافة 10 أقدام و 100 قدم و 200 قدم باتجاه حركة المرور المقتربة","على مسافة 10 أقدام و 100 قدم و 100 قدم على جانبي المركبة","على مسافة 25 قدمًا و 100 قدم و 300 قدم باتجاه حركة المرور المقتربة","على مسافة 50 قدمًا و 150 قدمًا و 250 قدمًا خلف المركبة"],"explanation":"ينص دليل CDL لولاية ويسكونسن (القسم 2.7) على أنه على طريق سريع باتجاه واحد أو مقسوم تضع أجهزة التحذير على مسافة 10 أقدام و 100 قدم و 200 قدم باتجاه حركة المرور المقتربة (خلف المركبة)."},"67":{"q":"يقول دليل CDL لولاية ويسكونسن إنه إذا توقفت قرب تلة أو منعطف أو عائق يمنع السائقين الآخرين من رؤية مركبتك ضمن مسافة معينة، فينبغي عليك تحريك المثلث الخلفي إلى مسافة أبعد. ما هي مسافة مدى الرؤية تلك؟","options":["500 قدم","200 قدم","300 قدم","1,000 قدم"],"explanation":"يقول دليل CDL لولاية ويسكونسن (القسم 2.7) إنه إذا منعت تلة أو منعطف أو عائق آخر السائقين من رؤية مركبتك ضمن مسافة 500 قدم، فحرِّك مثلث التحذير الخلفي إلى الوراء على الطريق لإعطاء تحذير مسبق كافٍ."},"68":{"q":"ما هي السرعة القصوى المحددة لشاحنة تجارية على طريق سريع ريفي في ولاية ويسكونسن يكون جزءًا من نظام الطرق السريعة بين الولايات؟","options":["70 ميلًا في الساعة، وهي نفس السرعة للسيارات","55 ميلًا في الساعة لجميع الشاحنات التي يزيد وزنها على 26,000 رطل","65 ميلًا في الساعة، أي أقل من حد الـ 70 mph المحدد للسيارات","60 ميلًا في الساعة لأي مركبة تقطر مقطورة"],"explanation":"بموجب (Wis. Stat. s. 346.57(4))، يبلغ الحد على الطرق السريعة في ولاية ويسكونسن بما فيها الطرق السريعة بين الولايات 70 mph. ولا تضع ولاية ويسكونسن حدًّا منفصلًا أقل للسرعة للشاحنات - بخلاف بعض الولايات المجاورة - لذا يمكن للشاحنات السير بنفس السرعة المحددة البالغة 70 mph حيث توجد لافتات بذلك، مع الخضوع لقاعدة السرعة الآمنة الأساسية."},"69":{"q":"هل يقيِّد قانون ولاية ويسكونسن الشاحنات التجارية بحارات محددة (مثل منعها من الحارة اليسرى) على الطرق السريعة بين الولايات بشكل عام؟","options":["لا يوجد حظر على مستوى الولاية لحارات مخصصة للشاحنات؛ وتنطبق القاعدة العامة \"الزم اليمين إلا للتجاوز\"","نعم، تُمنع الشاحنات من الحارة اليسرى القصوى على جميع الطرق السريعة بين الولايات في ويسكونسن","نعم، يجب أن تبقى الشاحنات في الحارة اليمنى متى كان هناك ثلاث حارات أو أكثر","نعم، يجوز للشاحنات التي يزيد وزنها على 10,000 رطل استخدام الحارتين اليمنيين فقط على مستوى الولاية"],"explanation":"ليس لدى ولاية ويسكونسن أي قانون على مستوى الولاية يقيِّد الشاحنات بحارات معينة. تقتضي القاعدة العامة (Wis. Stat. s. 346.05) القيادة على اليمين واستخدام الحارة اليسرى بشكل رئيسي للتجاوز. ويمكن وضع لافتات لقيود حارات محلية محددة، لكن لا يوجد حظر شامل على حارات الشاحنات على الطرق السريعة بين الولايات كما هو موجود في بعض الولايات."},"70":{"q":"يورد دليل CDL لولاية ويسكونسن ملاحظة خاصة بالولاية حول الحافلات المدرسية وسكك الحديد. أي عبارة تعكس ملاحظة ويسكونسن هذه؟","options":["في ولاية ويسكونسن، يجب أن تتوقف الحافلات المدرسية عند السكك المستخدمة للمناورة الصناعية","في ولاية ويسكونسن، يجوز للحافلات المدرسية المرور عبر أي تقاطع بسرعة أقل من 10 mph","في ولاية ويسكونسن، لا تتوقف الحافلات المدرسية أبدًا عند التقاطعات داخل حدود المدينة","في ولاية ويسكونسن، تتوقف الحافلات المدرسية فقط عند التقاطعات ذات البوابات النشطة"],"explanation":"يتضمن دليل CDL لولاية ويسكونسن (القسم 4.3.5) \"ملاحظة ويسكونسن\" تنص على أنه في ولاية ويسكونسن يجب أن تتوقف الحافلات المدرسية عند السكك المستخدمة للمناورة الصناعية - وهو اشتراط خاص بالولاية يتجاوز قواعد التقاطعات العامة."},"71":{"q":"وفقًا لدليل CDL لولاية ويسكونسن، عند أي نوع من التقاطعات لا يحتاج سائق الحافلة إلى التوقف توقفًا تامًا (لكن يجب عليه مع ذلك الإبطاء والتحقق من حركة المرور)؟","options":["تقاطع موسوم بأنه \"مُعفى\" (exempt) أو \"مهجور\" (abandoned)","تقاطع به لافتة صليبية (crossbuck) ولا توجد به بوابات","تقاطع متعدد السكك في منطقة ريفية","تقاطع تكون أجراس التحذير فيه صامتة"],"explanation":"يورد دليل CDL لولاية ويسكونسن (القسم 4.3.5) الحالات التي لا تحتاج فيها الحافلة إلى التوقف بل يجب عليها الإبطاء والتحقق: تقاطعات الترام، وحيث يوجِّه ضابط أو شخص حركة المرور، وعندما تُظهر إشارة المرور اللون الأخضر، وعند التقاطعات الموسومة بأنها \"مُعفاة\" أو \"مهجورة\". أما اللافتة الصليبية العادية دون تلك الشروط فتظل تقتضي توقف الحافلة."},"72":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة في ولاية ويسكونسن قبل أن يُشترط تصريح للحمولة الزائدة الحجم للسير على الطرق السريعة؟","options":["8 أقدام و 6 بوصات (8.5 أقدام)","8 أقدام و 0 بوصة","9 أقدام و 0 بوصة","10 أقدام و 0 بوصة"],"explanation":"يبلغ الحد الأقصى القانوني للعرض في ولاية ويسكونسن 8 أقدام و 6 بوصات (8.5 أقدام)؛ والحمولات الأعرض من ذلك تقتضي تصريحًا للحمولة الزائدة الحجم عبر نظام التصاريح في WisDOT. والحدود القانونية القياسية هي 8.5 أقدام عرضًا، و 13.5 قدمًا ارتفاعًا، و 53 قدمًا طولًا لنصف المقطورة، و 80,000 رطل وزنًا إجماليًا."},"73":{"q":"تدير ولاية ويسكونسن برامج موسمية لتقييد الأوزان تتميز بها بسبب مناخها. ماذا يتيح \"إعلان الطرق المتجمدة\" (frozen road declaration) الشتوي؟","options":["حمولات أثقل على طرق محددة طالما كان الرصيف متجمدًا وأقوى","حظرًا كاملًا على جميع الشاحنات التجارية حتى انتهاء ذوبان الربيع","حدود سرعة أعلى للشاحنات بسبب انخفاض حركة المرور الصيفية","إعفاءً من جميع رسوم التصاريح للحمولات المسافرة ليلًا فقط"],"explanation":"تستفيد برامج WisDOT الموسمية لتقييد الأوزان من مناخ ولاية ويسكونسن: فإعلان الطرق المتجمدة الشتوي (من منتصف ديسمبر تقريبًا إلى أوائل مارس) يتيح حمولات أثقل طالما كان الرصيف المتجمد أقوى من الناحية الإنشائية، وذلك بموجب برنامج WisDOT لقيود الأوزان الموسمية."},"74":{"q":"خلال ذوبان الربيع في ولاية ويسكونسن، ماذا تفعل برامج الطرق السريعة من الدرجة الثانية (Class II) والطرق الموسومة الموسمية بأوزان الشاحنات؟","options":["تخفِّض أوزان المحاور المسموح بها لحماية الرصيف الذي أضعفه الذوبان","تزيد الأوزان المسموح بها لأن ذوبان الثلوج يُخلي الطرق","ليس لها أي تأثير على الوزن؛ فهي تغيِّر فقط حدود السرعة المحددة","تنطبق فقط على سيارات الركاب والمركبات الترفيهية، وليس على الشاحنات"],"explanation":"تخفِّض برامج WisDOT لذوبان الربيع (طرق الدرجة الثانية والطرق الموسومة الموسمية، من مارس تقريبًا حتى مايو) أوزان المحاور والأوزان الإجمالية المسموح بها وتعلِّق العديد من تصاريح الحمولات القابلة للتقسيم لأن الرصيف الذائب يكون ضعيفًا من الناحية الإنشائية. والهدف هو إطالة عمر الطريق السريع، وذلك بموجب برنامج WisDOT لقيود الأوزان الموسمية."},"75":{"q":"في ولاية ويسكونسن، عندما تكون حمولة زائدة الحجم عريضة بما يكفي لتقتضي مرافقة أمامية واحدة، فأي نوع من المركبات يجوز أن يقوم بدور المرافق؟","options":["سيارة أو شاحنة أحادية الوحدة لا يزيد وزنها على 16,000 رطل ومزوَّدة بمصابيح التحذير المطلوبة","أي دراجة نارية مجهزة براية وضوء كهرماني","نصف مقطورة محمَّلة ثانية تسير مباشرة أمام الحمولة","سيارة شرطة موسومة لإنفاذ القانون فقط في كل الحالات"],"explanation":"بموجب قواعد تصاريح الحمولات الزائدة الحجم في ولاية ويسكونسن (WisDOT/Trans code)، يجب أن تكون مركبة المرافقة (الطليعة) سيارة أو شاحنة أحادية الوحدة لا يزيد وزنها على 16,000 رطل، مع رؤية غير معاقة ومصابيح أمامية منخفضة الشعاع مضاءة ومصابيح تحذير مضاءة أثناء مرافقة الحمولة المصرَّح بها."},"76":{"q":"على طريق ذي حارتين في ولاية ويسكونسن، ما هي علامة الرصف الإضافية التي ترافق عادةً تقاطع السكة الحديدية للتحكم في التجاوز؟","options":["علامة منطقة ممنوع التجاوز فيها (مع لافتة ممنوع التجاوز) عند الاقتراب من السكك","خط أصفر متقطع في الوسط يشجع على التجاوز قبل السكك","خط حارة أبيض متصل يتيح للشاحنات مشاركة التقاطع","شريط حارة دراجات يوجِّه الشاحنات إلى أقصى يمين التقاطع"],"explanation":"يلاحظ دليل CDL لولاية ويسكونسن (القسم 2.15) أنه على الطرق ذات الحارتين تتضمن علامات رصف السكة الحديدية حرف \"X\" مع الحرفين \"RR\" وعلامة ممنوع التجاوز، كما توجد لافتة منطقة ممنوع التجاوز عند الاقتراب من التقاطع. وخط التوقف الأبيض، إن وُجد، هو حيث يجب أن تبقى مقدمة الحافلة أثناء التوقف."},"77":{"q":"يتوقف سائق CDL في ولاية ويسكونسن على كتف طريق سريع مقسوم مزدحم بعد عطل. بعد وضع المثلثات الثلاثة باتجاه حركة المرور المقتربة على مسافة 10 و 100 و 200 قدم، بماذا ينصح دليل CDL لولاية ويسكونسن بخصوص حمل المثلثات؟","options":["احمل كل مثلث بينك وبين حركة المرور المقابلة كي يتمكن السائقون الآخرون من رؤيتك","احمل المثلثات فوق رأسك وامشِ في وسط حارة السير","ارمِ المثلثات من المقصورة لتجنب مغادرة المركبة كليًا","ضع المثلثات الثلاثة جميعها على الجانب الأيسر مواجهةً بعيدًا عن تدفق حركة المرور"],"explanation":"ينصح دليل CDL لولاية ويسكونسن (القسم 2.7) بأنه عند وضع المثلثات تحملها بينك وبين حركة المرور المقابلة من أجل سلامتك أنت، كي يتمكن السائقون المقتربون من رؤيتك أثناء وضعك للأجهزة."},"78":{"q":"أي وكالة حكومية تُصدر رخص القيادة التجارية (CDLs) في ولاية ويسكونسن؟","options":["شعبة المركبات الآلية في ولاية ويسكونسن (DMV)، وهي جزء من WisDOT","دورية ولاية ويسكونسن (State Patrol)","وزارة السلامة العامة في ولاية ويسكونسن","الإدارة الفيدرالية لسلامة ناقلي البضائع (FMCSA)"],"explanation":"تُصدر رخص CDL في ولاية ويسكونسن من قِبل شعبة المركبات الآلية في ولاية ويسكونسن (DMV)، وهي شعبة تابعة لوزارة النقل في ولاية ويسكونسن. وتقوم دورية الولاية بإنفاذ قوانين ناقلي البضائع لكنها لا تُصدر الرخص، و FMCSA وكالة فيدرالية تضع المعايير بدلًا من إصدار رخص CDL الخاصة بالولايات. المصدر: دليل القيادة التجارية لولاية ويسكونسن؛ صفحة متطلبات CDL على wisconsindot.gov."},"79":{"q":"ما هو الحد الأدنى لعدد الإجابات الصحيحة اللازمة لاجتياز اختبار المعرفة العامة لرخصة CDL في ولاية ويسكونسن، والذي يتضمن 50 سؤالًا؟","options":["40 إجابة صحيحة (80%)","30 إجابة صحيحة (60%)","35 إجابة صحيحة (70%)","45 إجابة صحيحة (90%)"],"explanation":"يتضمن اختبار المعرفة العامة في ولاية ويسكونسن 50 سؤالًا ويجب عليك الإجابة بشكل صحيح عن 40 سؤالًا على الأقل، أي درجة نجاح قدرها 80%. ويسري معيار الـ 80% على اختبارات معرفة CDL في ولاية ويسكونسن. المصدر: دليل القيادة التجارية لولاية ويسكونسن؛ متطلبات CDL على wisconsindot.gov."},"80":{"q":"ما مدة صلاحية تصريح المتعلِّم التجاري (CLP) في ولاية ويسكونسن؟","options":["180 يومًا","90 يومًا","سنة واحدة","60 يومًا"],"explanation":"يكون تصريح CLP في ولاية ويسكونسن صالحًا لمدة 180 يومًا ويُدرج أنواع المركبات والمصادقات التي تأهَّل لها حامله. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم تصريح المتعلِّم التجاري (CLP)."},"81":{"q":"كم يجب أن ينتظر حامل تصريح CLP في ولاية ويسكونسن بعد إصدار التصريح قبل أن يُسمح له بإجراء اختبار مهارات CDL؟","options":["14 يومًا","10 أيام","30 يومًا","7 أيام"],"explanation":"بموجب القواعد الفيدرالية التي اعتمدتها ولاية ويسكونسن، يجب أن تحمل تصريح CLP لمدة 14 يومًا على الأقل قبل أن يُسمح لك بإجراء اختبار المهارات. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم اختبار المهارات؛ 49 CFR 383.25."},"82":{"q":"يتألف اختبار مهارات CDL في ولاية ويسكونسن من ثلاثة أجزاء يجب إجراؤها بترتيب محدد. ما هو الترتيب الصحيح؟","options":["فحص المركبة، ثم التحكم الأساسي بالمركبة، ثم القيادة على الطريق","القيادة على الطريق، ثم فحص المركبة، ثم التحكم الأساسي بالمركبة","التحكم الأساسي بالمركبة، ثم القيادة على الطريق، ثم فحص المركبة","فحص المركبة، ثم القيادة على الطريق، ثم التحكم الأساسي بالمركبة"],"explanation":"يجب إجراء اختبار المهارات المكوَّن من ثلاثة أجزاء في ولاية ويسكونسن بالترتيب: فحص المركبة، ثم التحكم الأساسي بالمركبة، ثم القيادة على الطريق. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم اختبارات المهارات."},"83":{"q":"قبل أن يصبح المتقدم الجديد في ولاية ويسكونسن مؤهلًا لإجراء اختبار CDL، ما التدريب الذي يجب إكماله؟","options":["تدريب السائق المبتدئ (ELDT) من مزوِّد مسجَّل لدى FMCSA","دورة قيادة دفاعية معتمدة من المقاطعة","تدرُّب مهني لمدة سنتين تحت إشراف ناقل مرخَّص","شهادة سلامة في مكان العمل من OSHA"],"explanation":"يجب على المتقدمين الجدد لرخصة CDL (وكذلك من يرتقون بفئتهم أو يضيفون مصادقات معينة) إكمال تدريب السائق المبتدئ من مزوِّد مُدرج في سجل مزوِّدي التدريب لدى FMCSA قبل الاختبار. المصدر: دليل القيادة التجارية لولاية ويسكونسن؛ 49 CFR Part 380 Subpart F."},"84":{"q":"أي مستند يستخدمه المتقدمون لرخصة CDL في ولاية ويسكونسن للتصديق الذاتي على فئتهم (نوع) من التشغيل التجاري؟","options":["النموذج MV3230، تصديق السائق التجاري: فئة التشغيل","النموذج MV3001، طلب رخصة القيادة العامة","النموذج MV3740، التصديق الذاتي للحافلة المدرسية","تقرير الفحص الطبي لـ FMCSA (MCSA-5875)"],"explanation":"يصدِّق سائقو ولاية ويسكونسن ذاتيًا على فئة تشغيلهم في النموذج MV3230. والنموذج MV3001 هو طلب الرخصة العامة، والنموذج MV3740 هو تصديق ذاتي للحافلة المدرسية، و MCSA-5875 هو تقرير الفحص الطبي الذي يكمله الفاحص. المصدر: صفحة بطاقة Fed Med على wisconsindot.gov؛ النموذج MV3230."},"85":{"q":"من بين كم فئة تصديق ذاتي (فئات التشغيل) يجب أن يختار حامل رخصة CDL في ولاية ويسكونسن؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"توجد أربع فئات للتصديق الذاتي: غير مُعفى بين الولايات، ومُعفى بين الولايات، وغير مُعفى داخل الولاية، ومُعفى داخل الولاية. المصدر: صفحة بطاقة Fed Med على wisconsindot.gov؛ 49 CFR 383.71."},"86":{"q":"أي فئة تصديق ذاتي في ولاية ويسكونسن تقتضي من السائق الاحتفاظ بشهادة فاحص طبي فيدرالية صالحة (بطاقة Fed Med)؟","options":["غير مُعفى بين الولايات (NI)","مُعفى بين الولايات (EI)","مُعفى داخل الولاية (EA)","أي سائق لا يعبر حدود الولايات أبدًا"],"explanation":"يجب على السائقين غير المُعفين بين الولايات (NI) أن يحملوا بطاقة Fed Med صالحة. أما فئتا المُعفى بين الولايات والمُعفى داخل الولاية فلا تقتضيان بطاقة. المصدر: صفحة بطاقة Fed Med على wisconsindot.gov؛ 49 CFR 383.71."},"87":{"q":"اعتبارًا من تغيير الإجراءات لعام 2025، كيف تصل عادةً معلومات شهادة الفاحص الطبي الفيدرالية لسائق في ولاية ويسكونسن إلى DMV ولاية ويسكونسن بعد فحص DOT الطبي؟","options":["تنقلها FMCSA إلكترونيًا إلى DMV ولاية ويسكونسن في غضون نحو 48 ساعة من الفحص","يجب على السائق دائمًا إرسال نسخة ورقية بالفاكس إلى DMV في غضون 10 أيام","يرسلها صاحب عمل النقل بالبريد إلى DMV نيابةً عن السائق","تُطبع على رخصة CDL ولا يتم إبلاغ الولاية بها أبدًا"],"explanation":"اعتبارًا من 13 أبريل 2025، تقدِّم FMCSA تلقائيًا معلومات بطاقة Fed Med للسائق إلى DMV ولاية ويسكونسن، عمومًا في غضون 48 ساعة من فحص DOT الطبي. أما الفحوصات المكتملة قبل ذلك التاريخ فكان يجب على السائق تقديمها. المصدر: صفحة بطاقة Fed Med على wisconsindot.gov."},"88":{"q":"كم مرة يجب تجديد رخصة CDL في ولاية ويسكونسن؟","options":["كل 8 سنوات","كل 4 سنوات","كل 6 سنوات","كل سنتين"],"explanation":"يجب تجديد رخصة CDL في ولاية ويسكونسن كل 8 سنوات. المصدر: دليل القيادة التجارية لولاية ويسكونسن؛ معلومات التجديد على wisconsindot.gov."},"89":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ولاية ويسكونسن للقيادة التجارية داخل الولاية (ضمن ويسكونسن)؟","options":["18 عامًا","21 عامًا","19 عامًا","16 عامًا"],"explanation":"يجب أن يكون عمرك 18 عامًا على الأقل للحصول على رخصة CDL/CLP في ولاية ويسكونسن للتشغيل داخل الولاية. أما التجارة بين الولايات فتقتضي عمومًا أن يكون عمرك 21 عامًا على الأقل. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم تصريح المتعلِّم التجاري (CLP)."},"90":{"q":"بموجب أي شرط يجوز لحامل تصريح CLP في ولاية ويسكونسن تشغيل مركبة تجارية في التجارة بين الولايات؟","options":["فقط إذا كان عمره 21 عامًا على الأقل ويحمل شهادة طبية فيدرالية صالحة","في أي عمر، بما أن تصريح CLP يمنح صلاحية كاملة بين الولايات","فقط بعد حمل تصريح CLP لمدة 180 يومًا","فقط بوجود مصادقة حافلة مدرسية"],"explanation":"لا يجوز لحامل تصريح CLP التشغيل في التجارة بين الولايات إلا إذا كان عمره 21 عامًا على الأقل ويحمل بطاقة Fed Med صالحة. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم CLP."},"91":{"q":"في اختبار المهارات، كم عددًا من الأجزاء الثلاثة يجب أن يجتازها المتقدم في ولاية ويسكونسن على تصريح CLP نفسه؟","options":["يجب اجتياز الأجزاء الثلاثة جميعها على تصريح CLP نفسه","يجب أن يكون جزء القيادة على الطريق فقط على تصريح CLP نفسه","يجوز ترحيل أي اثنين من الثلاثة إلى تصريح CLP جديد","يجوز توزيع الأجزاء على ما يصل إلى ثلاثة تصاريح CLP مختلفة"],"explanation":"تقتضي ولاية ويسكونسن اجتياز الأجزاء الثلاثة جميعها من اختبار المهارات على تصريح CLP نفسه. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم اختبار المهارات."},"92":{"q":"أي اختبار يجب أن يجتازه كل متقدم لرخصة CDL في ولاية ويسكونسن بغض النظر عن الفئة أو المصادقات المطلوبة؟","options":["اختبار المعرفة العامة","اختبار الفرامل الهوائية","اختبار المركبات المركَّبة","اختبار المواد الخطرة"],"explanation":"يخوض اختبار المعرفة العامة جميع المتقدمين لرخصة CDL؛ أما اختبارات المعرفة الأخرى (الفرامل الهوائية، والمركبات المركَّبة، والمواد الخطرة، وغيرها) فتُشترط فقط لفئات أو مصادقات معينة. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم اختبارات المعرفة."},"93":{"q":"إلى جانب اختبار المعرفة العامة، أي مستندين/إثباتين مطلوبان عند التقدم بطلب الحصول على CLP/CDL في ولاية ويسكونسن؟","options":["رخصة قيادة سارية من ولاية ويسكونسن وإثبات المواطنة أو الوضع القانوني","جواز سفر ورسالة موثَّقة من صاحب العمل","بطاقة ضمان اجتماعي وسند ملكية مركبة","شهادة ثانوية عامة ومرجعان لحُسن السيرة"],"explanation":"يجب على المتقدمين في ولاية ويسكونسن أن يحملوا رخصة قيادة سارية من ولاية ويسكونسن وأن يقدموا إثبات المواطنة الأمريكية أو الوجود القانوني، إلى جانب الطلب (MV3001) والتصديق الذاتي على الفئة (MV3230). المصدر: متطلبات CDL على wisconsindot.gov؛ دليل القيادة التجارية لولاية ويسكونسن."},"94":{"q":"حامل رخصة CDL يترك بطاقة Fed Med الخاصة به تنتهي صلاحيتها وليس لديه شهادة طبية صالحة مسجَّلة في ولاية ويسكونسن، يُقيَّد بأي نوع من التشغيل؟","options":["التشغيل داخل الولاية فقط (ضمن ويسكونسن)","التشغيل بين الولايات فقط","تشغيل المركبات الفارغة فقط","لا يُسمح بتشغيل أي مركبة تجارية"],"explanation":"يُقيَّد السائق الذي لا يحمل بطاقة طبية فيدرالية صالحة بالتشغيل داخل الولاية فقط (ضمن الولاية)، أو التشغيل المُعفى داخل الولاية، ويفقد صلاحية التشغيل بين الولايات. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم CLP/الطبي."},"95":{"q":"من المخوَّل، إلى جانب فاحصي DMV في ولاية ويسكونسن، بإجراء اختبارات مهارات CDL في ولاية ويسكونسن؟","options":["فاحصو الطرف الثالث المخوَّلون من DMV","أي سائق CDL مرخَّص يختاره المتقدم","مفتشو FMCSA الميدانيون","نواب مأمور المقاطعة (sheriff's deputies)"],"explanation":"يخوِّل DMV ولاية ويسكونسن فاحصي طرف ثالث معتمدين بإجراء اختبارات مهارات CDL؛ ويتواصل المتقدمون مع فاحص طرف ثالث مخوَّل لتحديد الموعد. المصدر: دليل القيادة التجارية لولاية ويسكونسن، قسم اختبار المهارات."},"96":{"q":"في جزء فحص المركبة من اختبار المهارات في ولاية ويسكونسن، ما المطلوب من المتقدم أن يفعله؟","options":["فحص المركبة وشرح ما يتم فحصه ولماذا للفاحص","مشاهدة الفاحص وهو يفحص المركبة وتوقيع قائمة تحقق","تقديم تقرير فحص مكتوب من ميكانيكي عن الأسبوع السابق","قيادة المركبة على الطريق مع وصف عدادات لوحة القيادة"],"explanation":"في اختبار فحص المركبة، يؤدي المتقدم الفحص ويشرح للفاحص ما الذي سيتم فحصه ولماذا، مبيِّنًا معرفته بأن المركبة آمنة للقيادة. المصدر: دليل القيادة التجارية لولاية ويسكونسن، القسم 2.1 والقسم 11M."},"97":{"q":"ما العلاقة بين الفاحص الطبي الذي يُصدر بطاقة Fed Med والسجل الوطني لـ FMCSA؟","options":["يجب أن يجري الفحص فاحص طبي مُدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA","يجوز لأي طبيب مرخَّص إصدار البطاقة دون تسجيل","يجوز فقط لأطباء موظفي DMV ولاية ويسكونسن إجراء الفحص","تُصدر البطاقة من FMCSA مباشرةً بعد استبيان مُرسل بالبريد"],"explanation":"يجب أن يجري فحص DOT الطبي فاحص طبي مُدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA، والذي يكمل تقرير الفحص الطبي لـ FMCSA ويُصدر شهادة الفاحص الطبي. المصدر: صفحة بطاقة Fed Med على wisconsindot.gov؛ 49 CFR 390.103."}}};
